provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your domain name

  tags = {
    Environment = "Production"
    Terraform   = "true"
  }
}

# Associate the hosted zone with a VPC (if needed)
# Uncomment and configure if you need VPC association
# resource "aws_route53_zone_association" "vpc_association" {
#   zone_id = aws_route53_zone.main.zone_id
#   vpc_id  = "vpc-12345678" # Replace with your VPC ID
# }

# Output the hosted zone ID for reference
output "hosted_zone_id" {
  value = aws_route53_zone.main.zone_id
}

# Output the hosted zone name servers for DNS configuration
output "name_servers" {
  value = aws_route53_zone.main.name_servers
}

