  region = "us-east-1" # Change to your preferred region
}

resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your domain name
}

resource "aws_elb" "main" { # Note: For newer ALB/NLB, use aws_lb instead
  name            = "main-elb"
  security_groups = [aws_security_group.elb.id] # Ensure this is defined or adjust accordingly
  subnets         = [aws_subnet.subnet1.id, aws_subnet.subnet2.id] # Replace with your subnet IDs

