extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  alias = "main"
  region = "us-west-1"
}

provider "aws" {
  alias = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias = "ap-southeast"
  region = "ap-southeast-1"
}

# Create the hosted zone in us-west-1
resource "aws_route53_zone" "main" {
  provider = aws.main
  name      = "main.example.com"
}

# Create primary db_instance in us-west-1
resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier             = "primary"
  engine                 = "postgres"
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false
  storage_encrypted      = true
  backup_retention_period = 7
  tags = {
    Name = "primary-db-instance"
  }
}

# Create replica db_instance in us-east-1
resource "aws_db_instance" "replica_us_east" {
  provider = aws.us-east
  identifier             = "replica_us_east"
  engine                 = "postgres"
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false
  storage_encrypted      = true
  backup_retention_period = 7
  replication_source_arn = aws_db_instance.primary.arn
  tags = {
    Name = "replica-us-east-db-instance"
  }
}

# Create replica db_instance in eu-central-1
resource "aws_db_instance" "replica_eu_central" {
  provider = aws.eu-central
  identifier             = "replica_eu_central"
  engine                 = "postgres"
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false
  storage_encrypted      = true
  backup_retention_period = 7
  replication_source_arn = aws_db_instance.primary.arn
  tags = {
    Name = "replica-eu-central-db-instance"
  }
}

# Create replica db_instance in ap-southeast-1
resource "aws_db_instance" "replica_ap_southeast" {
  provider = aws.ap-southeast
  identifier             = "replica_ap_southeast"
  engine                 = "postgres"
  engine_version         = "14.5"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_name                = "maindb"
  username               = "admin"
  password               = "securepassword123"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false
  storage_encrypted      = true
  backup_retention_period = 7
  replication_source_arn = aws_db_instance.primary.arn
  tags = {
    Name = "replica-ap-southeast-db-instance"
  }
}

# Create a weighted failover routing policy
resource "aws_route53_record" "weighted_routing" {
  provider = aws.main
  zone_id   = aws_route53_zone.main.zone_id
  name      = "db.example.com"
  type      = "A"

  alias {
    name                   = aws_db_instance.primary.endpoint
    zone_id                = aws_db_instance.primary.db_subnet_group.arn
    evaluate_target_health = true
  }

  set_identifier = "weighted-routing"

  failover_routing_policy {
    type = "WEIGHTED"
  }

  health_check_id = aws_route53_health_check.db_health_check.id
}

# Create health check for failover routing
resource "aws_route53_health_check" "db_health_check" {
  provider = aws.main
  caller_reference = timestamp()
  health_check_config {
    type                     = "HTTPS"
    resource_path            = "/health"
    fully_qualified_domain_name = aws_db_instance.primary.endpoint
    request_interval         = 30
    failure_threshold        = 3
    port                     = 80
  }
}

# Create weighted records for each replica
resource "aws_route53_record" "replica_weighted" {
  for_each = {
    "replica_us_east" = {
      weight = 33
      region = aws.us-east
      endpoint = aws_db_instance.replica_us_east.endpoint
    },
    "replica_eu_central" = {
      weight = 33
      region = aws.eu-central
      endpoint = aws_db_instance.replica_eu_central.endpoint
    },
    "replica_ap_southeast" = {
      weight = 33
      region = aws.ap-southeast
      endpoint = aws_db_instance.replica_ap_southeast.endpoint
    }
  }

  provider = aws.main
  zone_id   = aws_route53_zone.main.zone_id
  name      = "db.example.com"
  type      = "A"

  alias {
    name                   = each.value.endpoint
    zone_id                = each.value.region.db_subnet_group.arn
    evaluate_target_health = true
  }

  set_identifier = "weighted-routing-${each.key}"
  health_check_id = aws_route53_health_check.db_health_check.id

  weighted_routing_policy {
    weight = each.value.weight
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
      configuration_aliases = [ aws.main, aws.us_east, aws.eu_central, aws.ap_southeast ]
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  alias = "main"
  region = "us-west-2" 

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "us_east"
  region = "us-east-1" # Example region for US East

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1" # Example region for EU Central

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "ap_southeast"
  region = "ap-southeast-1" # Example region for AP Southeast

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier = "master"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_us_east" {
  provider             = aws.us_east
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-us-east"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_eu_central" {
  provider             = aws.eu_central
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-eu-central"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider             = aws.ap_southeast
  replicate_source_db  = aws_db_instance.primary.arn

  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-ap-southeast"
  skip_final_snapshot  = true
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_us_east_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "us.east.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_us_east.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "eu.central.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_eu_central.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "ap.southeast.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_ap_southeast.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-ap-southeast"
}

