```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Adjust region as needed
}

# Create the hosted zone
resource "aws_route53_zone" "main" {
  name = "example.com" # Replace with your domain name
}

# Create the primary record set for the primary DB instance
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary.example.com" # Replace with your primary instance subdomain
  type    = "A"

  alias {
    name                   = aws_rds_cluster.primary.endpoint
    zone_id                = aws_rds_cluster.primary.cluster_resource_id
    evaluate_target_health = true
  }

  set_identifier = "primary"
  weight          = 1
}

# Create the record set for the first replica DB instance
resource "aws_route53_record" "replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-1.example.com" # Replace with your replica-1 instance subdomain
  type    = "A"

  alias {
    name                   = aws_rds_cluster.replica_1.endpoint
    zone_id                = aws_rds_cluster.replica_1.cluster_resource_id
    evaluate_target_health = true
  }

  set_identifier = "replica-1"
  weight          = 2
}

# Create the record set for the second replica DB instance
resource "aws_route53_record" "replica_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replica-2.example.com" # Replace with your replica-2 instance subdomain
  type    = "A"

  alias {
    name                   = aws_rds_cluster.replica_2.endpoint
    zone_id                = aws_rds_cluster.replica_2.cluster_resource_id
    evaluate_target_health = true
  }

  set_identifier = "replica-2"
  weight          = 2
}

# Create a weighted failover record set for the main domain
resource "aws_route53_record" "main_weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_zone.main.name
  type    = "A"

  alias {
    name                   = aws_route53_recordset_group.main.name
    zone_id                = aws_route53_recordset_group.main.zone_id
    evaluate_target_health = true
  }

  set_identifier = "weighted"
  weight          = 5 # Distribute traffic 50% to primary, 50% to replicas combined
}

# Create a weighted record set group for the main domain
resource "aws_route53_recordset_group" "main" {
  zone_id = aws_route53_zone.main.zone_id

  recordset {
    name    = aws_route53_record.primary.name
    type    = aws_route53_record.primary.type
    alias {
      name                   = aws_route53_record.primary.alias.name
      zone_id                = aws_route53_record.primary.alias.zone_id
      evaluate_target_health = aws_route53_record.primary.alias.evaluate_target_health
    }
    set_identifier = aws_route53_record.primary.set_identifier
    weight          = aws_route53_record.primary.weight
  }

  recordset {
    name    = aws_route53_record.replica_1.name
    type    = aws_route53_record.replica_1.type
    alias {
      name                   = aws_route53_record.replica_1.alias.name
      zone_id                = aws_route53_record.replica_1.alias.zone_id
      evaluate_target_health = aws_route53_record.replica_1.alias.evaluate_target_health
    }
    set_identifier = aws_route53_record.replica_1.set_identifier
    weight          = aws_route53_record.replica_1.weight
  }

  recordset {
    name    = aws_route53_record.replica_2.name
    type    = aws_route53_record.replica_2.type
    alias {
      name                   = aws_route53_record.replica_2.alias.name
      zone_id                = aws_route53_record.replica_2.alias.zone_id
      evaluate_target_health = aws_route53_record.replica_2.alias.evaluate_target_health
    }
    set_identifier = aws_route53_record.replica_2.set_identifier
    weight          = aws_route53_record.replica_2.weight
  }
}

# Create a weighted record set for the main domain pointing to the recordset group
resource "aws_route53_record" "main_weighted_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_zone.main.name
  type    = "A"

  alias {
    name                   = aws_route53_recordset_group.main.name
    zone_id                = aws_route53_recordset_group.main.zone_id
    evaluate_target_health = true
  }

  set_identifier = "weighted"
  weight          = 5 # Primary gets 50% (5/10), replicas get 50% (5/10 combined)
}

# Create a failover record set for the primary instance
resource "aws_route53_record" "primary_failover" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_record.primary.name
  type    = "A"

  alias {
    name                   = aws_route53_record.primary.alias.name
    zone_id                = aws_route53_record.primary.alias.zone_id
    evaluate_target_health = aws_route53_record.primary.alias.evaluate_target_health
  }

  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Create failover record sets for the replicas
resource "aws_route53_record" "replica_failover_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_record.replica_1.name
  type    = "A"

  alias {
    name                   = aws_route53_record.replica_1.alias.name
    zone_id                = aws_route53_record.replica_1.alias.zone_id
    evaluate_target_health = aws_route53_record.replica_1.alias.evaluate_target_health
  }

  failover_routing_policy {
    type = "SECONDARY"
  }
}

resource "aws_route53_record" "replica_failover_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_record.replica_2.name
  type    = "A"

  alias {
    name                   = aws_route53_record.replica_2.alias.name
    zone_id                = aws_route53_record.replica_2.alias.zone_id
    evaluate_target_health = aws_route53_record.replica_2.alias.evaluate_target_health
  }

  failover_routing_policy {
    type = "SECONDARY"
  }
}

# Create a weighted record set for the main domain with failover
resource "aws_route53_record" "main_weighted_failover" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_zone.main.name
  type    = "A"

  set_identifier = "weighted_failover"

  health_check_id = aws_route53_health_check.main.id

  alias {
    name                   = aws_route53_recordset_group.main.name
    zone_id                = aws_route53_recordset_group.main.zone_id
    evaluate_target_health = true
  }

  failover_routing_policy {
    type = "ANY"
  }

  records = [
    aws_route53_record.primary_failover.fqdn,
    aws_route53_record.replica_failover_1.fqdn,
    aws_route53_record.replica_failover_2.fqdn
  ]

  weight = 5 # Primary gets 50%, replicas get 50% combined
}

# Health check for the failover routing
resource "aws_route53_health_check" "main" {
  name = "main-dns-health-check"

  type = "DNS"

  resource_path = "example.com" # Replace with your domain name

  failure_condition {
    num_consecutive_failures = 3
    num_consecutive_successes = 1
  }
}
```

**Note:**
This example assumes you have an existing RDS cluster setup with primary and replica instances. You'll need to replace placeholder values like `example.com` with your actual domain, and ensure the `aws_rds_cluster` resources are defined or referenced correctly. The weights are set to distribute traffic equally between the primary and replicas (50% each). Adjust weights as needed.

