provider "aws" {
  region = "us-east-1"
}

# IAM Role for Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Instance Profile for Elastic Beanstalk
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "my_application" {
  name        = "my_application"
  description = "Simple Elastic Beanstalk Application"
}

# Elastic Beanstalk Application Version (empty for now, can be updated later)
resource "aws_elasticbeanstalk_application_version" "app_version" {
  name        = "app_version_1"
  application = aws_elasticbeanstalk_application.my_application.name
  source_zip = "${path.module}/application.zip" # Update this path to your application zip file
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "eb_env" {
  name                = "my_eb_env"
  application         = aws_elasticbeanstalk_application.my_application.name
  application_version = aws_elasticbeanstalk_application_version.app_version.name
  environment_name    = "my_eb_env"
  platform            = "Platform_Unknown" # Update this to your application platform (e.g., "Platform_Java" or "Platform_Tomcat")

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }
}

# Security Group for Elastic Beanstalk
resource "aws_security_group" "eb_sg" {
  name        = "eb_sg"
  description = "Security group for Elastic Beanstalk"
  vpc_id      = aws_vpc.default.id # Ensure you have a VPC defined or replace with your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Basic VPC setup (ensure this matches your environment or replace with existing VPC)
resource "aws_vpc" "default" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "default_vpc"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.default.id
}

resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.default.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.default.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_association" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

