  name        = "eb_ec2_policy"
  description = "Policy for Elastic Beanstalk EC2 instances"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "elasticbeanstalk:*",
          "ec2:*",
          "s3:*",
          "cloudwatch:*",
