# IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# IAM Policy for S3 and SQS access
resource "aws_iam_policy" "eb_s3_sqs_policy" {
  name        = "eb_s3_sqs_policy"
  description = "Policy for S3 and SQS access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "sqs:ReceiveMessage",
          "sqs:DeleteMessage",
          "sqs:ChangeMessageVisibility"
        ],
        Resource = aws_sqs_queue.batch_job_queue.arn
      }
    ]
  })
}

# Attach the policy to the IAM role
resource "aws_iam_role_policy_attachment" "eb_s3_sqs_attachment" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = aws_iam_policy.eb_s3_sqs_policy.arn
}

# SQS Queue for batch jobs
resource "aws_sqs_queue" "batch_job_queue" {
  name = "batch_job_queue"
}

# Elastic Beanstalk Application
resource "aws_elasticbeanstalk_application" "batch_job_app" {
  name        = "batch_job_app"
  description = "Elastic Beanstalk application for batch processing"
}

# Elastic Beanstalk Environment
resource "aws_elasticbeanstalk_environment" "batch_job_env" {
  name                = "batch-job-worker-env"
  application         = aws_elasticbeanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 14" # Adjust based on your needs

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro" # Adjust based on your needs
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/health"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = "aws-elasticbeanstalk-service-role"
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:nodejs"
    name      = "NodeCommand"
    value     = "node worker.js" # Adjust based on your worker script
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentVariables"
    value     = jsonencode({
      S3_BUCKET_NAME = var.s3_bucket_name
      S3_OBJECT_KEY  = var.s3_object_key
      SQS_QUEUE_URL  = aws_sqs_queue.batch_job_queue.url
    })
  }
}

# Elastic Beanstalk Application Version
