  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  application_version = aws_elastic_beanstalk_application_version.version.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js" # Change to your preferred stack

