  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_zone.main.name # Replace with your domain name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eb-env.cname
    zone_id                = aws_elastic_beanstalk_environment.eb-env.cname_zone_id
    evaluate_target_health = true
  }
}

