    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role"
  }
  depends_on = [aws_elastic_beanstalk_application.app]
}

# Create Elastic Beanstalk Environment "green"
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 18" # Adjust as needed
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role"
  }
  depends_on = [aws_elastic_beanstalk_application.app]
}

# Create Route 53 Hosted Zone (if it doesn't exist)
resource "aws_route53_zone" "app_domain" {
  name = "example.com" # Replace with your domain
}

# Create Route 53 Record Set for Blue Environment
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.app_domain.zone_id
  name    = "app.example.com" # Replace with your subdomain
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.cname_dns_name_zone_id
    evaluate_target_health = true
  }
  set_identifier = "blue"
  weight          = 0 # Initially 0% traffic
}

# Create Route 53 Record Set for Green Environment
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.app_domain.zone_id
  name    = "app.example.com" # Replace with your subdomain
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.green.cname
    zone_id                = aws_elastic_beanstalk_environment.green.cname_dns_name_zone_id
    evaluate_target_health = true
  }
  set_identifier = "green"
  weight          = 100 # Initially 100% traffic
}

# Outputs for reference
output "blue_environment_cname" {
  value = aws_elastic_beanstalk_environment.blue.cname
}

output "green_environment_cname" {
  value = aws_elastic_beanstalk_environment.green.cname
}

output "blue_record_set_id" {
  value = aws_route53_record.blue.id
}

output "green_record_set_id" {
