terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2" # Default region for us_west
  alias  = "us_west"
}

provider "aws" {
  region = "eu-central-1" # Default region for eu_central
  alias  = "eu_central"
}

# --- US West Environment (us-west-2) ---
resource "aws_elastic_beanstalk_application" "us_west_app" {
  provider      = aws.us_west
  name          = "us_west_app"
  description   = "Elastic Beanstalk application for US West region"
}

resource "aws_elastic_beanstalk_environment" "us_west_env" {
  provider      = aws.us_west
  name          = "us_west_env"
  application   = aws_elastic_beanstalk_application.us_west_app.name
  description   = "Elastic Beanstalk environment for US West region"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  provider = aws.us_west
  name     = "eb_instance_profile_us_west"
  role     = aws_iam_role.eb_role.name
}

resource "aws_iam_role" "eb_role" {
  provider = aws.us_west
  name     = "eb_role_us_west"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ssm_policy" {
  provider = aws.us_west
  role     = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

# --- EU Central Environment (eu-central-1) ---
resource "aws_elastic_beanstalk_application" "eu_central_app" {
  provider      = aws.eu_central
  name          = "eu_central_app"
  description   = "Elastic Beanstalk application for EU Central region"
}

resource "aws_elastic_beanstalk_environment" "eu_central_env" {
  provider      = aws.eu_central
  name          = "eu_central_env"
  application   = aws_elastic_beanstalk_application.eu_central_app.name
  description   = "Elastic Beanstalk environment for EU Central region"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eu_central_eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }
}

resource "aws_iam_instance_profile" "eu_central_eb_instance_profile" {
  provider = aws.eu_central
  name     = "eb_instance_profile_eu_central"
  role     = aws_iam_role.eu_central_eb_role.name
}

resource "aws_iam_role" "eu_central_eb_role" {
  provider = aws.eu_central
  name     = "eb_role_eu_central"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
