    value     = aws_iam_instance_profile.eu_central_eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }
}

resource "aws_iam_instance_profile" "eu_central_eb_instance_profile" {
  provider = aws.eu_central
  name     = "eb_instance_profile_eu_central"
  role     = aws_iam_role.eu_central_eb_role.name
}

resource "aws_iam_role" "eu_central_eb_role" {
  provider = aws.eu_central
  name     = "eb_role_eu_central"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eu_central_eb_ssm_policy" {
  provider = aws.eu_central
  role     = aws_iam_role.eu_central_eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

# --- Route 53 Latency-Based Routing ---
resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_record" "latency_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "latency"
  ttl     = "60"

  records = [
    {
      region  = "us-west-2"
      value   = aws_elastic_beanstalk_environment.us_west_env.cname_dns_name
    },
    {
      region  = "eu-central-1"
      value   = aws_elastic_beanstalk_environment.eu_central_env.cname_dns_name
    }
  ]
}

resource "aws_route53_record" "www_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "A"
  alias {
    name                   = aws_route53_record.latency_record.name
    zone_id                = aws_route53_record.latency_record.zone_id
    evaluate_target_health = true
    failover_routing_policy = "PRIMARY"
  }
}
