# Main Terraform configuration for Blue-Green Deployment with Elastic Beanstalk and RDS

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "eb-role-for-blue-green"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Instance Profile for Elastic Beanstalk
resource "aws_iam_instance_profile" "eb_profile" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

# RDS Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "eb-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet1.id, aws_subnet.private_subnet2.id] # Replace with your private subnet IDs

  tags = {
    Name = "EB-RDS-Subnet-Group"
  }
}

# RDS Database
resource "aws_db_instance" "my_db" {
  allocated_storage      = 20
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.t3.micro"
  db_name                = "my_db"
  username               = "admin"
  password               = "your_secure_password" # Change this to a secure password or use AWS Secrets Manager
  skip_final_snapshot    = false
  final_snapshot_identifier = "final-snapshot-${random_id.snapshot_suffix.hex}"
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  multi_az               = false
  storage_encrypted      = true
  backup_retention_period = 7
  copy_tags_to_snapshot  = true

  tags = {
    Name = "my_db"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow inbound traffic to RDS from Elastic Beanstalk"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["${aws_elastic_beanstalk_environment.blue_environment.option_settings[0].value}"] # Dynamic CIDR from EB environment
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS-Security-Group"
  }
}

# VPC and Subnets (Example setup, adjust as needed)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "private_subnet1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  tags = {
    Name = "private-subnet-2"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-blue-green-app"
  description = "Blue-Green Deployment Application"
}

# Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "blue_version" {
  name        = "blue-version"
  application = aws_elastic_beanstalk_application.my_app.name
  source_bundle {
    application_arn = aws_elastic_beanstalk_application.my_app.arn
    crc            = filebase64sha256("path/to/your/blue-app.zip") # Replace with your blue app bundle path
  }
}

# Elastic Beanstalk Configuration Template
resource "aws_elastic_beanstalk_configuration_template" "blue_template" {
  application_name = aws_elastic_beanstalk_application.my_app.name
  name             = "blue-template"
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value       = aws_iam_instance_profile.eb_profile.name
  }
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "InstanceType"
    value       = "t3.micro"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value       = "LoadBalanced"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value       = "application"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "ServiceRole"
    value       = aws_iam_role.eb_role.name
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    option_name = "HealthCheckPath"
    value       = "/"
  }
  option_settings {
    namespace = "aws:rds:dbinstance"
    option_name = "DBName"
    value       = "my_db"
  }
  option_settings {
    namespace = "aws:rds:dbinstance"
    option_name = "DBHostname"
    value       = aws_db_instance.my_db.endpoint
  }
  option_settings {
    namespace = "aws:rds:dbinstance"
    option_name = "DBPort"
    value       = aws_db_instance.my_db.port
  }
}

# Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_environment" {
  name                = "blue-environment"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 16" # Adjust as needed
  version_label       = aws_elastic_beanstalk_application_version.blue_version.name
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value       = aws_iam_instance_profile.eb_profile.name
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value       = "LoadBalanced"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value       = "application"
  }
  depends_on = [aws_elastic_beanstalk_configuration_template.blue_template]
}

# Elastic Beanstalk Environment (Green)
resource "aws_elastic_beanstalk_application_version" "green_version" {
  name        = "green-version"
  application = aws_elastic_beanstalk_application.my_app.name
  source_bundle {
    application_arn = aws_elastic_beanstalk_application.my_app.arn
    crc            = filebase64sha256("path/to/your/green-app.zip") # Replace with your green app bundle path
  }
}

resource "aws_elastic_beanstalk_environment" "green_environment" {
  name                = "green-environment"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 16" # Adjust as needed
  version_label       = aws_elastic_beanstalk_application_version.green_version.name
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value       = aws_iam_instance_profile.eb_profile.name
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value       = "LoadBalanced"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value       = "application"
  }
  depends_on = [aws_elastic_beanstalk_configuration_template.blue_template]
}

# Lambda Function for Database Snapshot Before Deployment
resource "aws_lambda_function" "pre_deploy_snapshot" {
  function_name = "pre-deploy-db-snapshot"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs16.x"
  filename      = "path/to/your/lambda_function.zip" # Replace with your Lambda function zip file path

  environment {
    variables = {
      DB_ID = aws_db_instance.my_db.id
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda-db-snapshot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_rds_access" {
  name = "lambda-rds-access-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:CreateDBSnapshot",
          "rds:DescribeDBInstances"
        ],
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Event Rule to Trigger Lambda Before Deployment
resource "aws_cloudwatch_event_rule" "pre_deploy_trigger" {
  name        = "pre-deploy-db-snapshot-trigger"
  description = "Trigger Lambda before Elastic Beanstalk deployment"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.pre_deploy_trigger.name
  target_id = "TriggerLambdaFunction"
  arn       = aws_lambda_function.pre_deploy_snapshot.arn
}

# Random ID for Snapshot Suffix
resource "random_id" "snapshot_suffix" {
  byte_length = 4
}

# Outputs
output "blue_environment_url" {
  value = aws_elastic_beanstalk_environment.blue_environment.cname
}

output "green_environment_url" {
  value = aws_elastic_beanstalk_environment.green_environment.cname
}

output "rds_endpoint" {
  value = aws_db_instance.my_db.endpoint
}

