    option_name = "DBHostname"
    value       = aws_db_instance.my_db.endpoint
  }
  option_settings {
    namespace = "aws:rds:dbinstance"
    option_name = "DBPort"
    value       = aws_db_instance.my_db.port
  }
}

# Elastic Beanstalk Environment (Blue)
resource "aws_elastic_beanstalk_environment" "blue_environment" {
  name                = "blue-environment"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 16" # Adjust as needed
  version_label       = aws_elastic_beanstalk_application_version.blue_version.name
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value       = aws_iam_instance_profile.eb_profile.name
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value       = "LoadBalanced"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value       = "application"
  }
  depends_on = [aws_elastic_beanstalk_configuration_template.blue_template]
}

# Elastic Beanstalk Environment (Green)
resource "aws_elastic_beanstalk_application_version" "green_version" {
  name        = "green-version"
  application = aws_elastic_beanstalk_application.my_app.name
  source_bundle {
    application_arn = aws_elastic_beanstalk_application.my_app.arn
    crc            = filebase64sha256("path/to/your/green-app.zip") # Replace with your green app bundle path
  }
}

resource "aws_elastic_beanstalk_environment" "green_environment" {
  name                = "green-environment"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 16" # Adjust as needed
  version_label       = aws_elastic_beanstalk_application_version.green_version.name
  option_settings {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value       = aws_iam_instance_profile.eb_profile.name
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value       = "LoadBalanced"
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value       = "application"
  }
  depends_on = [aws_elastic_beanstalk_configuration_template.blue_template]
}

# Lambda Function for Database Snapshot Before Deployment
resource "aws_lambda_function" "pre_deploy_snapshot" {
  function_name = "pre-deploy-db-snapshot"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs16.x"
  filename      = "path/to/your/lambda_function.zip" # Replace with your Lambda function zip file path

  environment {
    variables = {
      DB_ID = aws_db_instance.my_db.id
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda-db-snapshot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_rds_access" {
  name = "lambda-rds-access-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:CreateDBSnapshot",
          "rds:DescribeDBInstances"
        ],
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Event Rule to Trigger Lambda Before Deployment
resource "aws_cloudwatch_event_rule" "pre_deploy_trigger" {
  name        = "pre-deploy-db-snapshot-trigger"
  description = "Trigger Lambda before Elastic Beanstalk deployment"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.pre_deploy_trigger.name
  target_id = "TriggerLambdaFunction"
  arn       = aws_lambda_function.pre_deploy_snapshot.arn
}

# Random ID for Snapshot Suffix
resource "random_id" "snapshot_suffix" {
  byte_length = 4
}

# Outputs
output "blue_environment_url" {
  value = aws_elastic_beanstalk_environment.blue_environment.cname
}

output "green_environment_url" {
  value = aws_elastic_beanstalk_environment.green_environment.cname
}

output "rds_endpoint" {
  value = aws_db_instance.my_db.endpoint
}
