  }
}

# Internet Gateway
resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id
  tags = {
    Name = "eb_igw"
  }
}

# Public Subnets
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "eb_subnet_public_1"
  }
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "eb_subnet_public_2"
  }
}

# Route Table
resource "aws_route_table" "eb_route_table" {
  vpc_id = aws_vpc.eb_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }
  tags = {
    Name = "eb_route_table"
  }
}

# Route Table Association
resource "aws_route_table_association" "eb_route_association_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_route_table_association" "eb_route_association_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_route_table.id
}

# Security Group
resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Security group for Elastic Beanstalk environments"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_env_sg"
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "shared_rds_subnet_group" {
  name       = "shared_rds_subnet_group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "shared_rds_subnet_group"
  }
}

# RDS Instance
resource "aws_db_instance" "shared_rds" {
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  db_name              = "shared_db"
  username             = "admin"
  password             = "your_secure_password_here" # Change this to a secure password
  parameter_group_name = "default.postgres15"
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.shared_rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.eb_env_sg.id]
  publicly_accessible    = false
  tags = {
    Name = "shared_rds"
  }
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "eb_app"
  description = "Elastic Beanstalk Application"
}

# Elastic Beanstalk Environment 1
resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  name                = "eb_env_1"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 18"
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role"
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "InstanceType"
    value = "t3.micro"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value = "LoadBalanced"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    option_name = "HealthCheckPath"
    value = "/"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value = "application"
  }
  setting {
    name  = "DBName"
    value = aws_db_instance.shared_rds.db_name
  }
  setting {
    name  = "DBHost"
    value = aws_db_instance.shared_rds.endpoint
  }
  setting {
    name  = "DBPort"
    value = aws_db_instance.shared_rds.port
  }
  setting {
    name  = "DBUser"
    value = aws_db_instance.shared_rds.username
  }
  setting {
    name  = "DBPassword"
    value = aws_db_instance.shared_rds.password
  }
  setting {
    name  = "VPCId"
    value = aws_vpc.eb_vpc.id
  }
  setting {
    name  = "Subnets"
    value = "${aws_subnet.eb_subnet_public_1.id},${aws_subnet.eb_subnet_public_2.id}"
  }
  setting {
    name  = "SecurityGroups"
    value = aws_security_group.eb_env_sg.id
  }
}

# Elastic Beanstalk Environment 2
resource "aws_elastic_beanstalk_environment" "eb_env_2" {
  name                = "eb_env_2"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.8.0 running Node.js 18"
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role"
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "InstanceType"
    value = "t3.micro"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value = "LoadBalanced"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    option_name = "HealthCheckPath"
    value = "/"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "LoadBalancerType"
    value = "application"
  }
  setting {
    name  = "DBName"
    value = aws_db_instance.shared_rds.db_name
  }
  setting {
    name  = "DBHost"
    value = aws_db_instance.shared_rds.endpoint
  }
  setting {
    name  = "DBPort"
    value = aws_db_instance.shared_rds.port
  }
  setting {
    name  = "DBUser"
    value = aws_db_instance.shared_rds.username
  }
  setting {
    name  = "DBPassword"
    value = aws_db_instance.shared_rds.password
  }
  setting {
    name  = "VPCId"
    value = aws_vpc.eb_vpc.id
  }
  setting {
    name  = "Subnets"
    value = "${aws_subnet.eb_subnet_public_1.id},${aws_subnet.eb_subnet_public_2.id}"
  }
  setting {
    name  = "SecurityGroups"
    value = aws_security_group.eb_env_sg.id
  }
}
