terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create IAM role for Elastic Beanstalk EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_profile1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policies to the IAM role
resource "aws_iam_role_policy_attachment" "eb_ec2_role_attachment" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Create instance profile for Elastic Beanstalk
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

# Create RDS Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "myapp_db_subnet_group"
  subnet_ids = data.aws_subnets.default.ids # Replace with your subnet IDs or use aws_subnet resource

  tags = {
    Name = "myapp_db_subnet_group"
  }
}

# Create RDS instance
resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  name                 = "myapp_db"
  username             = "admin"
  password             = "your_secure_password_here" # Change this to a secure password
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  skip_final_snapshot  = true
  publicly_accessible  = false
  vpc_security_group_ids = [aws_security_group.rds_sg.id] # Create this resource if needed
}

# Create Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds_security_group"
  description = "Allow inbound traffic to RDS"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your Elastic Beanstalk security group in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "My Application"
}

# Create Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "myapp_version" {
  name        = "myapp_version_1"
  application = aws_elastic_beanstalk_application.myapp.name
  source_ip   = "0.0.0.0/0" # Use a specific IP or CIDR block in production

  # Replace with your application source bundle
  auto_create_application = true
  source_bundle {
    s3_bucket = aws_s3_bucket.eb_source_bucket.bucket
    s3_key    = aws_s3_bucket_object.eb_source_object.key
  }
}

# Create S3 bucket for Elastic Beanstalk source bundle
resource "aws_s3_bucket" "eb_source_bucket" {
  bucket = "myapp-eb-source-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Create S3 object for Elastic Beanstalk source bundle
resource "aws_s3_bucket_object" "eb_source_object" {
  bucket = aws_s3_bucket.eb_source_bucket.bucket
  key    = "application.zip"
  source = "path/to/your/application.zip" # Replace with your application zip file path
}

# Create Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.myapp.name
  application_version = aws_elastic_beanstalk_application_version.myapp_version.version
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }
  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "HealthCheckPath"
    value     = "/"
  }
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }
  setting {
    namespace = "aws:rds:iam:dbauth"
    name      = "DBUserName"
    value     = aws_db_instance.myapp_db.username
  }
  setting {
    namespace = "aws:rds:iam:dbauth"
    name      = "DBClusterIdentifier"
    value     = aws_db_instance.myapp_db.id
  }
  setting {
    namespace = "aws:rds:iam:dbauth"
    name      = "DBName"
    value     = aws_db_instance.myapp_db.name
  }
  setting {
    namespace = "aws:rds:iam:dbauth"
    name      = "DBPort"
    value     = aws_db_instance.myapp_db.port
  }
}

# Create Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your domain name
}

# Create Route 53 Record for Elastic Beanstalk Environment
resource "aws_route53_record" "eb_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = aws_route53_zone.primary.name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv.cname_zone_id
    evaluate_target_health = true
  }
}

# Get default VPC and subnets (if not using custom VPC)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role2" {
  name = "elastic_beanstalk_ec2_role2"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role2.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile1" {
  name = "elastic_beanstalk_ec2_profile2"
  role = aws_iam_role.eb_ec2_role2.name
}

resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "my-application"
  description = "my application"
}

resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "my-environment"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile1.name
  }
}

resource "aws_route53_zone" "main" {
  name = "example56.com"
}

