  name    = "app.example.com" # Replace with your desired subdomain
  type    = "Latency"

  latency_routing_policy {
    region = "us-east-1"
  }

  latency_routing_policy {
    region = "eu-west-1"
  }

  alias {
    name                   = aws_route53_record.us_east_1.name
    zone_id                = aws_route53_record.us_east_1.zone_id
    evaluate_target_health = true
  }
}
