    name      = "Database URL"
    value     = "postgres://admin:${aws_db_instance.myapp_db.password}@${aws_db_instance.myapp_db.endpoint}:5432/myapp_db"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "RDS Database Name"
