# Route 53 Hosted Zone
resource "aws_route53_zone" "myapp_zone" {
  name = "example.com" # Change to your domain name
}

# Route 53 Health Check for Blue Environment
resource "aws_route53_health_check" "blue_health_check" {
  health_check_config {
    type               = "HTTPS"
    resource_path      = "/health"
    fully_qualified_domain_name = aws_elasticbeanstalk_environment.blue.cname
    request_interval   = 30
    failure_threshold  = 3
    port               = 443
  }
}

# Route 53 Health Check for Green Environment
resource "aws_route53_health_check" "green_health_check" {
  health_check_config {
    type               = "HTTPS"
    resource_path      = "/health"
    fully_qualified_domain_name = aws_elasticbeanstalk_environment.green.cname
    request_interval   = 30
    failure_threshold  = 3
    port               = 443
  }
}

# Route 53 Record Set for Blue Environment
resource "aws_route53_record" "blue_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "blue.example.com" # Change to your blue environment subdomain
  type    = "A"

  alias {
    name                   = aws_elasticbeanstalk_environment.blue.cname
    zone_id                = aws_elasticbeanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
    health_check_id        = aws_route53_health_check.blue_health_check.id
  }

  set_identifier = "blue"
  failover_routing_policy {
    failover_criteria {
      type               = "HEALTH"
    }
  }
}

# Route 53 Record Set for Green Environment
resource "aws_route53_record" "green_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "green.example.com" # Change to your green environment subdomain
  type    = "A"

  alias {
    name                   = aws_elasticbeanstalk_environment.green.cname
    zone_id                = aws_elasticbeanstalk_environment.green.cname_zone_id
    evaluate_target_health = true
    health_check_id        = aws_route53_health_check.green_health_check.id
  }

  set_identifier = "green"
  failover_routing_policy {
    failover_criteria {
      type               = "HEALTH"
    }
  }
}

# Route 53 Record Set for Primary (Blue) Environment
resource "aws_route53_record" "primary_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "app.example.com" # Change to your primary domain
  type    = "A"

  alias {
    name                   = aws_elasticbeanstalk_environment.blue.cname
    zone_id                = aws_elasticbeanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
    health_check_id        = aws_route53_health_check.blue_health_check.id
  }

  set_identifier = "primary"
  failover_routing_policy {
    failover_criteria {
      type               = "HEALTH"
    }
  }

  failover_routing_policy {
    failover_criteria {
      type               = "HEALTH"
    }
  }

  health_check_id = aws_route53_health_check.blue_health_check.id
}

# Route 53 Record Set for Secondary (Green) Environment
resource "aws_route53_record" "secondary_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "app.example.com" # Same domain as primary
  type    = "A"

  alias {
    name                   = aws_elasticbeanstalk_environment.green.cname
    zone_id                = aws_elasticbeanstalk_environment.green.cname_zone_id
    evaluate_target_health = true
    health_check_id        = aws_route53_health_check.green_health_check.id
  }

  set_identifier = "secondary"
  failover_routing_policy {
    failover_criteria {
      type               = "HEALTH"
    }
  }

  routing_policy = "WEIGHTED"
  weight         = 0 # Initially, all traffic goes to the primary (blue)
}

# Route 53 Latency-Based Routing (Optional)
resource "aws_route53_record" "latency_record" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "app.example.com" # Same domain as primary
  type    = "A"

  alias {
    name                   = aws_elasticbeanstalk_environment.blue.cname
    zone_id                = aws_elasticbeanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
    health_check_id        = aws_route53_health_check.blue_health_check.id
  }

  set_identifier = "latency"
  routing_policy = "LATENCY"
}
