    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkEnhancedHealth"
}

resource "aws_iam_role_policy_attachment" "eb_ec2" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_elastic_beanstalk_configuration_template" "config_template" {
  name_prefix = "my-eb-config-"
  application = aws_elastic_beanstalk_application.app.name
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
  option_setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "LoadBalancerType"
    value     = "application"
  }
}

resource "aws_s3_bucket" "eb_deployment_bucket" {
  bucket = "my-eb-deployment-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "my-eb-app-version"
  application = aws_elastic_beanstalk_application.app.name
  description = "Initial application version"
  source_ip   = "0.0.0.0/0" # Adjust based on your security requirements
  origin_path = "https://github.com/your-repo/your-app" # Replace with your app's source
}

resource "aws_elastic_beanstalk_application_version" "zip_deployment" {
  name        = "my-eb-app-zip-version"
  application = aws_elastic_beanstalk_application.app.name
  description = "Zip deployment version"
  source_ip   = "0.0.0.0/0" # Adjust based on your security requirements
  bucket      = aws_s3_bucket.eb_deployment_bucket.bucket
  key         = aws_s3_object.app_zip.key
}

resource "aws_s3_object" "app_zip" {
  bucket = aws_s3_bucket.eb_deployment_bucket.bucket
  key    = "application.zip"
  source = "path/to/your/application.zip" # Replace with your application zip file path
  etag   = filemd5("path/to/your/application.zip") # Replace with your application zip file path
}

resource "aws_elastic_beanstalk_deployment" "deployment" {
  application_name = aws_elastic_beanstalk_application.app.name
  version_label   = aws_elastic_beanstalk_application_version.zip_deployment.name
  environment_name = aws_elastic_beanstalk_environment.env.name
}

