# Google Cloud Configuration (Cloud Run + Cloud Load Balancing)
provider "google" {
  project = "your-gcp-project-id"
  region  = "us-central1"
}

resource "google_cloud_run_service" "web_app" {
  name     = "web-app-autoscaler"
  location = "us-central1"

  template {
    spec {
      containers {
        image = "gcr.io/your-gcp-project-id/your-web-app-image"
        ports {
          container_port = 8080
        }
      }
      scaling {
        min_instance_count = 1
        max_instance_count = 10
      }
    }
  }

  traffic {
    percent         = 100
    latest_revision = true
  }

  depends_on = [google_project_iam_member.run_invoker]
}

resource "google_project_iam_member" "run_invoker" {
  project = "your-gcp-project-id"
  role    = "roles/run.invoker"
  member  = "allUsers"
}

# Azure Configuration (App Service + Auto Scaling)
provider "azurerm" {
  features {}
  subscription_id = "your-azure-subscription-id"
  client_id       = "your-azure-client-id"
  client_secret   = "your-azure-client-secret"
  tenant_id       = "your-azure-tenant-id"
}

resource "azurerm_resource_group" "web_app" {
  name     = "web-app-rg"
  location = "East US"
}

resource "azurerm_service_plan" "web_app" {
  name                = "web-app-service-plan"
  resource_group_name = azurerm_resource_group.web_app.name
  location            = azurerm_resource_group.web_app.location
  os_type             = "Linux"
  sku_name            = "B1" # Basic tier with auto-scaling
}

resource "azurerm_linux_web_app" "web_app" {
  name                = "web-app-autoscaler"
  resource_group_name = azurerm_resource_group.web_app.name
  location            = azurerm_resource_group.web_app.location
  service_plan_id     = azurerm_service_plan.web_app.id

  site_config {
    application_stack {
      node_version = "18.0" # Example for Node.js; adjust for your language
    }
    always_on = true
    min_tls_version = "1.2"
    ftps_state    = "Disabled"
    http2_enabled = true
  }

  app_settings = {
    "WEBSITES_CONTAINER_START_TIME_LIMIT" = "3600"
  }
}

resource "azurerm_monitor_autoscale_setting" "web_app" {
  name                = "web-app-autoscale"
  resource_group_name = azurerm_resource_group.web_app.name
  location            = azurerm_resource_group.web_app.location
  target_resource_id  = azurerm_service_plan.web_app.id

  profile {
    name = "defaultProfile"

    capacity {
      default = 1
      minimum = 1
      maximum = 10
    }

    rule {
      metric_trigger {
        metric_name        = "Percentage CPU"
        metric_resource_id = azurerm_service_plan.web_app.id
        time_grain         = "PT1M"
        statistic          = "Average"
        time_window        = "PT5M"
        time_aggregation   = "Average"
        operator           = "GreaterThan"
        threshold          = 70
      }

      scale_action {
        direction = "Increase"
        type       = "ChangeCount"
        value       = "1"
        cooldown   = "PT1M"
      }
    }

    rule {
      metric_trigger {
        metric_name        = "Percentage CPU"
        metric_resource_id = azurerm_service_plan.web_app.id
        time_grain         = "PT1M"
        statistic          = "Average"
        time_window        = "PT5M"
        time_aggregation   = "Average"
        operator           = "LessThan"
        threshold          = 30
      }

      scale_action {
        direction = "Decrease"
        type       = "ChangeCount"
        value       = "1"
        cooldown   = "PT1M"
      }
    }
  }
}

