provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket for Elastic Beanstalk deployment
resource "aws_s3_bucket" "eb_deployment" {
  bucket = "my-eb-app-deployment-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create an IAM role for Elastic Beanstalk
resource "aws_iam_role" "eb_service_role" {
  name = "my-eb-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic EB service policy to the role
resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

# Create Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-eb-app"
  description = "My Elastic Beanstalk Application"
}

# Create Elastic Beanstalk application version lifecycle configuration
resource "aws_elastic_beanstalk_application_version_lifecycle_config" "app_version_lifecycle" {
  application_name = aws_elastic_beanstalk_application.my_app.name
  max_age_in_days  = 30 # Versions older than 30 days will be deleted
  version_count_limit = 5 # Keep only the last 5 versions
  stop_version_deletion_on_cordon = false
}

# Create Elastic Beanstalk application version (example using a zip file)
resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "my-app-version-${random_id.version_suffix.hex}"
  application = aws_elastic_beanstalk_application.my_app.name
  description = "Initial application version"

  auto_create_application_version = false
  source_artifact {
    name = "my-app.zip"
    path = "s3://${aws_s3_bucket.eb_deployment.bucket}/my-app.zip"
  }
}

resource "random_id" "version_suffix" {
  byte_length = 4
}

