provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_elastic_beanstalk_application" "example_app" {
  name        = "example-application"
  description = "Example Elastic Beanstalk Application"
}

resource "aws_elastic_beanstalk_application_version" "example_version" {
  name        = "example-version-${timestamp()}"
  application = aws_elastic_beanstalk_application.example_app.name
  source_bundle {
    s3_bucket = "your-s3-bucket-name" # Replace with your S3 bucket name
    s3_key    = "path/to/your/application.zip" # Replace with your application zip file path
  }
}

resource "aws_elastic_beanstalk_configuration_template" "example_template" {
  name        = "example-config-template"
  application = aws_elastic_beanstalk_application.example_app.name
  option_setting {
    namespace = "aws:autoscaling:launchconfiguration"
    option_name = "IamInstanceProfile"
    value = "aws-elasticbeanstalk-ec2-role" # Ensure this role exists in your AWS account
  }
}

resource "aws_elastic_beanstalk_environment" "example_env" {
  name                = "example-env"
  application         = aws_elastic_beanstalk_application.example_app.name
  template_name       = aws_elastic_beanstalk_configuration_template.example_template.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.1 running Node.js 14" # Adjust as needed

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "2"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }
}

resource "aws_elastic_beanstalk_version_lifecycle_config" "example_lifecycle" {
  application_name = aws_elastic_beanstalk_application.example_app.name
  version_lifecycle_policy {
    delete_rule {
      max_count = 5
      days      = 5
      version_statuses_to_retain = ["D"]
    }
    rollback_rule {
      trigger_on {
        status_code_codes = ["ALL"]
      }
      action_on_disabled {
        delete_option {
          max_count = 1
          days      = 1
        }
      }
    }
  }
}

