        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy_attachment" "cloudwatch_logs" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_codebuild_source_version" "github_source" {
  identifier    = "github-source"
  cache         = false
  git_clone_depth = 0
  git_submodules_config {
    fetch_submodules = false
  }
  git_trigger_config {
    filter {
      file_pattern = "**"
      excluded_file_patterns = ["*.md"]
    }
    webhook = true
  }
}

resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with GitHub source and logging"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "LOG_LEVEL"
      value = "DEBUG"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/sample-project"
      stream_name = "build-log"
    }
    s3_logs {
      status = "DISABLED"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/your-repo.git"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install --upgrade pip
            - pip install -r requirements.txt
        pre_build:
          commands:
            - echo "Pre-build phase..."
        build:
          commands:
            - echo "Building the application..."
            - python -m pytest
        post_build:
          commands:
            - echo "Build completed on `date`"
      artifacts:
        files: '**/*'
      cache:
        paths:
          - '/root/.cache/pip/**/*'
    EOT
    git_submodules_config {
      fetch_submodules = false
    }
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
    paths    = ["/root/.cache"]
  }
}

