provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild_sample_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project for CI/CD pipeline"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_VARIABLE_NAME"
      value = "env_variable_value"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-repo/your-repo.git"
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  build_batch {
    build_spec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install --upgrade pip
            - pip install -r requirements.txt
        pre_build:
          commands:
            - echo "Pre-build phase..."
        build:
          commands:
            - echo "Building the application..."
            - python -m pytest tests/
        post_build:
          commands:
            - echo "Build completed on `date`"
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.cache/pip/**/*'
      batch:
        build-matrix:
          compute-type: BUILD_GENERAL1_SMALL
          env:
            variables:
              VAR1: "value1"
              VAR2: "value2"
    EOT
    compute_type = "BUILD_GENERAL1_SMALL"
    service_role = aws_iam_role.codebuild_role.arn
    env {
      type  = "BUILD_ENVIRONMENT_PULL_THROUGH"
      name  = "env_name"
      value = "env_value"
    }
  }
}

