provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild_sample_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy_attachment" "cloudwatch_logs" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_codebuild_source_version" "main_repo" {
  identifier    = "main_repo_source"
  build_spec    = <<-EOT
    version: 0.2
    phases:
      install:
        runtime-versions:
          python: 3.8
      pre_build:
        commands:
          - echo "Installing dependencies..."
          - pip install -r requirements.txt
      build:
        commands:
          - echo "Building the application..."
          - python -m pytest
    artifacts:
      files: '**/*'
    EOT
  git_clone_depth = 1
}

resource "aws_codebuild_source_version" "secondary_repo_1" {
  identifier    = "secondary_repo_1_source"
  build_spec    = <<-EOT
    version: 0.2
    phases:
      install:
        runtime-versions:
          nodejs: 14
      build:
        commands:
          - echo "Building secondary repo 1..."
          - npm install
          - npm run build
    artifacts:
      files: '**/*'
    EOT
  git_clone_depth = 1
}

resource "aws_codebuild_source_version" "secondary_repo_2" {
  identifier    = "secondary_repo_2_source"
  build_spec    = <<-EOT
    version: 0.2
    phases:
      install:
        runtime-versions:
          docker: 19
      build:
        commands:
          - echo "Building Docker image..."
          - docker build -t my-app .
    artifacts:
      files: '**/*'
    EOT
  git_clone_depth = 1
}

resource "aws_codebuild_project" "sample_project" {
  name          = "sample-codebuild-project"
  description   = "Sample CodeBuild project with multiple sources and artifacts"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "CODEPIPELINE"
  }

  secondary_artifacts {
    type = "S3"
    location = "my-secondary-artifacts-bucket"
    namespace_type = "BUILD_ID"
    packaging = "ZIP"
  }

  secondary_artifacts {
    type = "CODEPIPELINE"
    location = "secondary-pipeline-output"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "ENV_VAR_1"
      value = "value1"
    }

    environment_variable {
      name  = "ENV_VAR_2"
      value = "value2"
    }
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  source {
    type      = "CODECOMMIT"
    location  = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/main-repo"
    git_clone_depth = 1
    buildspec = aws_codebuild_source_version.main_repo.build_spec
  }

  secondary_sources {
    type      = "CODECOMMIT"
    location  = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/secondary-repo-1"
    git_clone_depth = 1
    buildspec = aws_codebuild_source_version.secondary_repo_1.build_spec
  }

  secondary_sources {
    type      = "CODECOMMIT"
    location  = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/secondary-repo-2"
    git_clone_depth = 1
    buildspec = aws_codebuild_source_version.secondary_repo_2.build_spec
  }
}
