# Create an IAM role for Lex to assume
resource "aws_iam_role" "lex_role" {
  name = "lex-chatbot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic permissions to the IAM role
resource "aws_iam_role_policy_attachment" "lex_basic_execution" {
  role       = aws_iam_role.lex_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexFullAccess"
}

# Create a CloudWatch Logs group for Lex
resource "aws_cloudwatch_log_group" "lex_log_group" {
  name              = "/aws/lex/${var.bot_name}"
  retention_in_days = 7 # Adjust retention as needed
}

# Create the Lex bot
resource "aws_lex_bot" "chatbot" {
  name               = var.bot_name
  description        = var.bot_description
  dataPrivacy        = var.data_privacy
  idempotency_key    = var.idempotency_key
  role_arn           = aws_iam_role.lex_role.arn
  log_settings {
    cloudwatch_logs_log_group = aws_cloudwatch_log_group.lex_log_group.arn
    log_level               = "DEBUG" # Adjust log level as needed
  }
  # Define bot aliases (optional)
  lifecycle {
    ignore_changes = [alias]
  }
}

# Create a Lex bot alias (optional)
resource "aws_lex_bot_alias" "chatbot_alias" {
  name               = "prod"
  bot_name           = aws_lex_bot.chatbot.name
  description        = "Production alias for ${var.bot_name}"
  bot_version        = aws_lex_bot.chatbot.version
  enabled            = true
  idempotency_key    = var.idempotency_key
  log_settings {
    cloudwatch_logs_log_group = aws_cloudwatch_log_group.lex_log_group.arn
    log_level               = "DEBUG"
  }
}

# Create a Lex intent (example)
resource "aws_lex_intent" "example_intent" {
  name        = "ExampleIntent"
  bot_name    = aws_lex_bot.chatbot.name
  description = "Example intent for the chatbot"
  sample_utterances = [
    "Hello",
    "Hi there",
    "Greetings"
  ]
  sample_user_utterances = [
    "Hello",
    "Hi there",
    "Greetings"
  ]
  input_contexts {
    intent_name = aws_lex_intent.example_intent.name
    intent_version = aws_lex_intent.example_intent.version
  }
}

# Create a Lex slot type (example)
resource "aws_lex_slot_type" "example_slot" {
  name        = "ExampleSlot"
  description = "Example slot type for the chatbot"
  value_elimination_rules {
    elimination_type = "REGEX"
    regex_specification {
      regex = "^[A-Za-z0-9]+$"
      match_behavior = "MATCH_ALL"
    }
  }
}

# Create a Lex slot (example)
resource "aws_lex_slot" "example_slot_value" {
  name        = "ExampleSlotValue"
  slot_type_name = aws_lex_slot_type.example_slot.name
  description = "Example slot value for the chatbot"
  value {
    value = "example_value"
  }
}

# Create a Lex slot value mapping (example)
resource "aws_lex_slot_value_mapping" "example_slot_mapping" {
  slot_type_name = aws_lex_slot_type.example_slot.name
  value {
    value = "example_value"
    slot_value {
      slot_value = aws_lex_slot.example_slot_value.name
    }
  }
}

# Create a Lex slot value (example)
