  description = "Description of the Lex bot"
  type        = string
  default     = "A sample Lex chatbot"
}

variable "data_privacy" {
  description = "Data privacy setting for the Lex bot"
  type        = string
  default     = "PRIVATE"
}

variable "idempotency_key" {
  description = "Idempotency key for the Lex bot"
  type        = string
  default     = "default_key"
}

