resource "aws_lex_bot" "customer_support_bot" {
  name        = "CustomerSupportBot"
  description = "A Lex bot for handling customer support queries"
  role_arn    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  auto_generate_fallback_intent = true
  idle_session_ttl_in_seconds   = 300
}

resource "aws_lex_intent" "greeting_intent" {
  name        = "GreetingIntent"
  bot_name    = aws_lex_bot.customer_support_bot.name
  sample_utterances = [
