```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_cloudwatch_log_group" "lex_bot_logs" {
  name              = "/aws/lex/bots/PizzaOrderBot"
  retention_in_days = 7
}

resource "aws_lex_bot" "pizza_order_bot" {
  name               = "PizzaOrderBot"
  description        = "A Lex bot for ordering pizza with follow-up prompts"
  dataPrivacy        = "PRIVACY_LEVEL_UNSPECIFIED"
  idempotency_strategy = "CREATE_IF_NOT_EXISTS"
  role_arn           = aws_iam_role.lex_bot_role.arn
  bot_file_s3_location {
    bucket_name = aws_s3_bucket.lex_bot_bucket.bucket
    bucket_path = aws_s3_bucket_object.lex_bot_file.key
  }
  bot_tags {
    Environment = "Production"
  }
  bot_tags {
    Purpose     = "PizzaOrdering"
  }
  depends_on = [aws_cloudwatch_log_group.lex_bot_logs]
}

resource "aws_lex_intent" "greeting_intent" {
  name               = "GreetingIntent"
  sample_utterances  = ["hello", "hi", "hey", "greetings"]
  parent_intent_sigil = "GreetingIntent"
  description        = "User greets the bot"
  sample_utterances  = ["hello", "hi", "hey", "greetings"]
}

resource "aws_lex_intent" "order_pizza_intent" {
  name               = "OrderPizzaIntent"
  sample_utterances  = [
    "I want to order a pizza",
    "Order me a pizza",
    "Can I get a pizza?",
    "Pizza please"
  ]
  description        = "User wants to order a pizza"
  parent_intent_sigil = "OrderPizzaIntent"
}

resource "aws_lex_intent" "follow_up_size_intent" {
  name               = "FollowUpSizeIntent"
  sample_utterances  = [
    "What size?",
    "Large or small?",
    "I want a {size}",
    "Size please"
  ]
  description        = "Follow-up prompt for pizza size"
  parent_intent_sigil = "FollowUpSizeIntent"
  slots {
    name     = "size"
    type     = "AMAZON.Number"
    value {
      default_value = "medium"
    }
  }
}

resource "aws_lex_intent" "follow_up_topping_intent" {
  name               = "FollowUpToppingIntent"
  sample_utterances  = [
    "What toppings?",
    "Add {toppings}",
    "I want {toppings}",
    "Toppings please"
  ]
  description        = "Follow-up prompt for pizza toppings"
  parent_intent_sigil = "FollowUpToppingIntent"
  slots {
    name     = "toppings"
    type     = "AMAZON.SearchQuery"
    value {
      default_value = "pepperoni"
    }
  }
}

resource "aws_lex_intent" "confirm_order_intent" {
  name               = "ConfirmOrderIntent"
  sample_utterances  = [
    "Yes, confirm",
    "Go ahead",
    "Place the order",
    "Order it"
  ]
  description        = "User confirms the pizza order"
  parent_intent_sigil = "ConfirmOrderIntent"
}

resource "aws_lex_intent" "cancel_order_intent" {
  name               = "CancelOrderIntent"
  sample_utterances  = [
    "Cancel",
    "No, nevermind",
    "Never mind",
    "I changed my mind"
  ]
  description        = "User cancels the pizza order"
  parent_intent_sigil = "CancelOrderIntent"
}

resource "aws_lex_slot_type" "pizza_size_slot" {
  name     = "PizzaSize"
  value_elimination_strategy = "ELIMINATE_ALL"
  slot_constraint = "REQUIRED"
  enumeration_values {
    value = "small"
  }
  enumeration_values {
    value = "medium"
  }
  enumeration_values {
    value = "large"
  }
}

resource "aws_lex_slot_type" "pizza_topping_slot" {
  name     = "PizzaTopping"
  value_elimination_strategy = "ELIMINATE_ALL"
  slot_constraint = "OPTIONAL"
  enumeration_values {
    value = "pepperoni"
  }
  enumeration_values {
    value = "mushrooms"
  }
  enumeration_values {
    value = "onions"
  }
  enumeration_values {
    value = "sausage"
  }
  enumeration_values {
    value = "extra cheese"
  }
}

resource "aws_lex_slot_type" "pizza_type_slot" {
  name     = "PizzaType"
  value_elimination_strategy = "ELIMINATE_ALL"
  slot_constraint = "REQUIRED"
  enumeration_values {
    value = "cheese"
  }
  enumeration_values {
    value = "pepperoni"
  }
  enumeration_values {
    value = "vegetarian"
  }
