# Create S3 bucket for Lex bot file
resource "aws_s3_bucket" "lex_bot_bucket" {
  bucket = "pizza-order-lex-bot-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_versioning" "lex_bot_bucket_versioning" {
  bucket = aws_s3_bucket.lex_bot_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "lex_bot_bucket_encryption" {
  bucket = aws_s3_bucket.lex_bot_bucket.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_object" "lex_bot_file" {
  bucket = aws_s3_bucket.lex_bot_bucket.id
  key    = "PizzaOrderBot.json"
  source = "${path.module}/PizzaOrderBot.json"
  etag   = filemd5("${path.module}/PizzaOrderBot.json")
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-order-bot-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLexRunBotPolicy"
}

resource "aws_lex_bot_alias" "pizza_order_bot_alias" {
  name               = "PizzaOrderBotAlias"
  bot_name           = aws_lex_bot.pizza_order_bot.name
  description        = "Alias for PizzaOrderBot"
  enabled            = true
  bot_tags {
    Environment = "Production"
  }
  bot_tags {
    Purpose     = "PizzaOrdering"
  }
  depends_on = [aws_lex_bot.pizza_order_bot]
}

resource "aws_cloudwatch_metric_alarm" "lex_bot_error_alarm" {
  alarm_name          = "PizzaOrderBotErrorAlarm"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "FailedSlotElicitationCount"
  namespace           = "AWS/Lex"
  period              = "60"
  statistic           = "Sum"
  threshold           = "1"
  alarm_description   = "Alarm when PizzaOrderBot encounters errors"
  alarm_actions       = [aws_sns_topic.lex_bot_alerts.arn]
  dimensions = {
    BotName = aws_lex_bot.pizza_order_bot.name
    AliasName = aws_lex_bot_alias.pizza_order_bot_alias.name
  }
}

resource "aws_sns_topic" "lex_bot_alerts" {
  name = "PizzaOrderBotAlerts"
}

resource "aws_sns_topic_subscription" "lex_bot_alerts_email" {
  topic_arn = aws_sns_topic.lex_bot_alerts.arn
  protocol  = "email"
  endpoint  = "your-email@example.com" # Replace with your email
}

