terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "pizza_order_bot" {
  name                     = "PizzaOrderBot"
  description              = "A Lex bot for handling pizza orders"
  idempotency_parameters {
    enable = true
  }
  role_arn                 = aws_iam_role.lex_bot_role.arn
  lifecycle {
    ignore_changes = [description]
  }
}

resource "aws_lex_bot_version" "pizza_order_bot_version" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "PizzaOrderBotVersion1"
}

resource "aws_lex_intent" "greeting_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "GreetingIntent"
  sample_utterances = ["hello", "hi", "hey", "greetings"]
  description = "User greets the bot"
}

resource "aws_lex_intent" "order_pizza_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "OrderPizzaIntent"
  sample_utterances = [
    "I want to order a pizza",
    "Order me a pizza",
    "Can I get a pizza?",
    "Pizza please"
  ]
  description = "User wants to order a pizza"
  input_slot {
    name     = "pizza_type"
    slot_type = "AMAZON.SearchS3"
    value_eligibility = "Required"
  }
  input_slot {
    name     = "size"
    slot_type = "AMAZON.SearchS3"
    value_eligibility = "Required"
  }
  input_slot {
    name     = "quantity"
    slot_type = "AMAZON.NUMBER"
    value_eligibility = "Required"
  }
  output_slot {
    name = "pizza_type"
  }
  output_slot {
    name = "size"
  }
  output_slot {
    name = "quantity"
  }
}

resource "aws_lex_intent" "confirm_order_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "ConfirmOrderIntent"
  sample_utterances = ["yes", "confirm", "go ahead", "proceed"]
  description = "User confirms the order"
}

resource "aws_lex_intent" "cancel_order_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "CancelOrderIntent"
  sample_utterances = ["no", "cancel", "nevermind", "forget it"]
  description = "User cancels the order"
}

resource "aws_lex_intent" "close_session_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "CloseSessionIntent"
  sample_utterances = ["bye", "goodbye", "thanks", "exit", "quit"]
  description = "User wants to close the session"
}

resource "aws_lex_slot_type" "pizza_type_slot" {
  name     = "PizzaType"
  value_eligibility = "Accepted"
  enumeration_values {
    value = "Margherita"
  }
  enumeration_values {
    value = "Pepperoni"
  }
  enumeration_values {
    value = "Hawaiian"
  }
  enumeration_values {
    value = "Vegetarian"
