  name    = "GetDeliveryDetailsIntent"
  sample_utterances = ["delivery details", "where will it be delivered?", "delivery information"]
  description = "User requests details about delivery"
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Here are the delivery details:

{DeliveryDetails}"
      }
    }
  }
}

