resource "aws_lex_intent" "set_user_preference_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "SetUserPreferenceIntent"
  sample_utterances = [
    "set my {user_preference} to {user_preference_value}",
    "change my {user_preference} to {user_preference_value}",
    "update my {user_preference}"
  ]
  description = "User sets or updates their preferences"
  input_slot {
    name     = "user_preference"
    slot_type = aws_lex_slot_type.user_preference_slot.name
  }
  input_slot {
    name     = "user_preference_value"
    slot_type = aws_lex_slot_type.user_preference_value_slot.name
  }
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Your {user_preference} has been updated to {user_preference_value}."
      }
    }
  }
}

