resource "aws_lex_intent" "help_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "HelpIntent"
  sample_utterances = ["help", "how do I order?", "what can you do?"]
  description = "User requests help"
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Here's how you can order a pizza:

1. Say 'I want to order a pizza'
2. Specify the type, size, and quantity
3. Confirm your order

You can also ask for help with your preferences or order details."
      }
    }
  }
}

