# Simplified version focusing on essentials for a pizza ordering bot with summary
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_lex_bot" "pizza_order_bot" {
  name                     = "PizzaOrderBot"
  description              = "A Lex bot for handling pizza orders"
  idempotency_parameters {
    enable = true
  }
  role_arn                 = aws_iam_role.lex_bot_role.arn
}

resource "aws_lex_slot_type" "pizza_type" {
  name     = "PizzaType"
  value_eligibility = "Accepted"
  enumeration_values {
    value = "Margherita"
  }
  enumeration_values {
    value = "Pepperoni"
  }
  enumeration_values {
    value = "Hawaiian"
  }
  enumeration_values {
    value = "Vegetarian"
  }
}

resource "aws_lex_slot_type" "size" {
  name     = "Size"
  value_eligibility = "Accepted"
  enumeration_values {
    value = "Small"
  }
  enumeration_values {
    value = "Medium"
  }
  enumeration_values {
    value = "Large"
  }
}

resource "aws_lex_slot_type" "quantity" {
  name     = "Quantity"
  value_eligibility = "Accepted"
}

resource "aws_lex_slot_type" "address" {
  name     = "Address"
  value_eligibility = "Accepted"
}

resource "aws_lex_slot_type" "delivery_instructions" {
  name     = "DeliveryInstructions"
  value_eligibility = "Optional"
}

resource "aws_lex_intent" "order_pizza" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "OrderPizzaIntent"
  sample_utterances = [
    "I want to order a {pizza_type} pizza of {size} size, {quantity} pizzas",
    "Order me a {pizza_type} pizza, {size} size",
    "Can I get a {pizza_type} pizza, {size} size, {quantity} pizzas?"
  ]
  description = "User wants to order a pizza"
  input_slot {
    name     = "pizza_type"
    slot_type = aws_lex_slot_type.pizza_type.name
  }
  input_slot {
    name     = "size"
    slot_type = aws_lex_slot_type.size.name
  }
  input_slot {
    name     = "quantity"
    slot_type = aws_lex_slot_type.quantity.name
  }
}

resource "aws_lex_intent" "confirm_order" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "ConfirmOrderIntent"
  sample_utterances = ["yes", "confirm", "go ahead", "proceed"]
  description = "User confirms the order"
}

resource "aws_lex_intent" "cancel_order" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "CancelOrderIntent"
  sample_utterances = ["no", "cancel", "nevermind", "forget it"]
  description = "User cancels the order"
}

resource "aws_lex_intent" "close_session" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "CloseSessionIntent"
  sample_utterances = ["bye", "goodbye", "thanks", "exit", "quit"]
  description = "User wants to close the session"
}

resource "aws_lex_intent" "get_order_summary" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "GetOrderSummaryIntent"
  sample_utterances = ["summarize my order", "what did I order?", "give me a summary"]
  description = "User requests a summary of their order"
}

resource "aws_lex_intent" "get_order_confirmation" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "GetOrderConfirmationIntent"
  sample_utterances = ["confirm my order", "finalize my order", "place my order"]
  description = "User requests confirmation of their order"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-order-bot-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotServiceRolePolicy"
}

resource "aws_cloudwatch_log_group" "lex_bot_log_group" {
  name              = "/aws/lex/${aws_lex_bot.pizza_order_bot.name}"
  retention_in_days = 7
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_pizza_intent" {
  name                       = "OrderPizzaIntent"
  description                = "To order a pizza"

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name                     = "PizzaType"
    description              = "Type of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1
    value_elicitation_prompt {
      message {
        content             = "What type of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PizzaSize"
    description              = "Size of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.NUMBER"
    priority                 = 2
    value_elicitation_prompt {
      message {
        content             = "What size of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PizzaQuantity"
    description              = "Number of pizzas to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.NUMBER"
    priority                 = 3
    value_elicitation_prompt {
      message {
        content             = "How many pizzas do you want to order?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  conclusion_statement {
    message {
      content              = "Your pizza order has been received."
      content_type         = "PlainText"
    }
  } 
}

resource "aws_lex_bot" "pizza_ordering_bot" {
  name                     = "PizzaOrderingBot"
  description              = "Bot to order pizzas"
  voice_id                 = "Joanna"
  idle_session_ttl_in_seconds = 300
  child_directed           = false
  clarification_prompt {
    message {
      content      = "I didn't understand you, what type of pizza would you like to order?"
      content_type = "PlainText"
    }
    max_attempts = 5
  }
  abort_statement {
    message {
      content      = "Sorry, I am unable to assist at the moment."
      content_type = "PlainText"
    }
  }

  locale                  = "en-US"
  process_behavior        = "BUILD"

  intent {
    intent_name    = aws_lex_intent.order_pizza_intent.name
    intent_version = aws_lex_intent.order_pizza_intent.version
  }
}

