resource "aws_lex_intent" "confirm_order_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "ConfirmOrderIntent"
  sample_utterances = ["yes", "confirm", "go ahead", "proceed"]
  description = "User confirms the order"
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Your order has been confirmed! Here is the summary:

{OrderSummary}"
      }
    }
  }
}

resource "aws_lex_intent" "cancel_order_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "CancelOrderIntent"
  sample_utterances = ["no", "cancel", "nevermind", "forget it"]
  description = "User cancels the order"
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Your order has been canceled. Is there anything else I can help you with?"
      }
    }
  }
}

resource "aws_lex_intent" "greeting_intent" {
  bot_id = aws_lex_bot.pizza_order_bot.id
  name    = "GreetingIntent"
  sample_utterances = ["hello", "hi", "hey", "greetings"]
  description = "User greets the bot"
  fulfillment_activity {
    type = "ReturnIntent"
    response_card {
      content_type = "PlainText"
      small_image {
        content_type = "image/png"
        small_image_url = "https://example.com/small_image.png"
      }
      image {
        content_type = "image/png"
        image_url = "https://example.com/image.png"
      }
      text {
        content_type = "PlainText"
        content = "Hello! Welcome to PizzaOrderBot. How can I help you today?"
      }
    }
  }
}

