provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "trip_reservation_bot" {
  name                     = "TripReservationBot"
  description              = "A Lex bot for handling trip reservations"
  idempotency_parameters {
    enable = true
  }
  lifecycle {
    ignore_changes = [
      last_updated_date,
      last_updated_time,
      version
    ]
  }

  # Bot settings
  bot_locale_settings {
    locale_id = "en_US"
    nlu_intent_confidence_threshold = 0.7
    parent_locale_id = "en_US"
    child_locale_ids = []
  }

  # Bot file settings
  bot_file_settings {
    file_location = "s3://${aws_s3_bucket.lex_bot_bucket.bucket}/bot-files"
    s3_bucket_arn = aws_s3_bucket.lex_bot_bucket.arn
  }

  # Bot tags
  tags = {
    Environment = "Production"
    Purpose     = "Trip Reservation"
    Owner       = "lex-team"
  }

  # Bot user attributes
  user_attributes {
    active = true
  }

  # Bot logging configuration
  logging_configuration {
    cloudwatch_logging_options {
      log_group_name = "/aws/lex/${aws_lex_bot.trip_reservation_bot.name}"
      log_stream_name = "${aws_lex_bot.trip_reservation_bot.name}-logs"
    }
  }

  # Bot slot types
  slot_type {
    name     = "Destination"
    value_elimination_settings {
      elimination_strategy = "ALL"
    }
    sample_utterances = [
      "I want to go to {Destination}",
      "My destination is {Destination}",
      "I'm traveling to {Destination}"
    ]
  }

  slot_type {
    name     = "DepartureDate"
    value_elimination_settings {
      elimination_strategy = "ALL"
    }
    sample_utterances = [
      "I want to travel on {DepartureDate}",
      "My departure is {DepartureDate}",
      "I'm leaving on {DepartureDate}"
    ]
  }

  slot_type {
    name     = "ReturnDate"
    value_elimination_settings {
      elimination_strategy = "ALL"
    }
    sample_utterances = [
      "I'll be back on {ReturnDate}",
      "My return date is {ReturnDate}",
      "I'm returning on {ReturnDate}"
    ]
  }

  slot_type {
    name     = "TravelClass"
    value_elimination_settings {
      elimination_strategy = "ALL"
    }
    sample_utterances = [
      "I'd like {TravelClass} seating",
      "I prefer {TravelClass} class",
      "Can I get {TravelClass} please?"
    ]
    enumeration_values {
      value = "Economy"
    }
    enumeration_values {
      value = "Business"
    }
    enumeration_values {
      value = "First"
    }
  }

  # Bot intents
  intent {
    name     = "GreetingIntent"
    sample_utterances = [
      "Hello",
      "Hi",
      "Hey",
      "Greetings"
    ]
    sample_utterances_enhancement_settings {
      enable = true
    }
    slot_priority_settings {
      slot_name = "Destination"
      priority = 1
    }
    slot_priority_settings {
      slot_name = "DepartureDate"
      priority = 2
    }
    slot_priority_settings {
      slot_name = "ReturnDate"
      priority = 3
    }
    slot_priority_settings {
      slot_name = "TravelClass"
      priority = 4
    }
    fulfillment_activity {
      return_session_attributes_activity {
        return_values {
          slot_name = "Destination"
          value = "Destination"
        }
        return_values {
          slot_name = "DepartureDate"
          value = "DepartureDate"
        }
        return_values {
          slot_name = "ReturnDate"
          value = "ReturnDate"
        }
        return_values {
          slot_name = "TravelClass"
          value = "TravelClass"
        }
      }
    }
  }

  intent {
    name     = "ConfirmReservationIntent"
    sample_utterances = [
      "Yes, confirm my reservation",
      "I want to confirm my trip",
      "Go ahead and confirm"
    ]
    sample_utterances_enhancement_settings {
      enable = true
    }
    fulfillment_activity {
      return_session_attributes_activity {
        return_values {
          slot_name = "Confirmation"
          value = "Yes"
        }
      }
    }
  }

  intent {
    name     = "CancelReservationIntent"
    sample_utterances = [
      "Cancel my reservation",
      "I want to cancel my trip",
      "Nevermind, cancel it"
    ]
    sample_utterances_enhancement_settings {
      enable = true
    }
    fulfillment_activity {
      return_session_attributes_activity {
        return_values {
          slot_name = "Confirmation"
          value = "No"
        }
      }
    }
  }

  intent {
    name     = "HelpIntent"
    sample_utterances = [
      "Help",
      "I need help",
      "How do I proceed?"
    ]
    sample_utterances_enhancement_settings {
      enable = true
    }
    fulfillment_activity {
      return_session_attributes_activity {
        return_values {
          slot_name = "Help"
          value = "Yes"
        }
      }
    }
  }

  intent {
    name     = "FallbackIntent"
    sample_utterances = [
      "I don't know",
      "I'm not sure",
      "I can't figure it out"
    ]
    sample_utterances_enhancement_settings {
      enable = true
    }
    fulfillment_activity {
      return_session_attributes_activity {
        return_values {
          slot_name = "Fallback"
          value = "Yes"
        }
      }
    }
  }

  # Bot message groups
  message_groups {
    message_group_name = "Greeting"
    message {
      content_type = "PlainText"
      content = "Hello! I'm your Trip Reservation Assistant. How can I help you today?"
    }
  }

  message_groups {
