      content_type = "PlainText"
      content = "Your reservation has been canceled. Have a nice day!"
    }
  }

  message_groups {
    message_group_name = "Help"
    message {
      content_type = "PlainText"
      content = "Sure! You can ask me to book a trip by providing your destination, departure date, return date, and travel class."
    }
  }

  message_groups {
    message_group_name = "Fallback"
    message {
      content_type = "PlainText"
      content = "I'm sorry, I didn't understand that. Could you please rephrase?"
    }
  }

  # Bot message versions
  message_version {
    message_group_name = "Greeting"
