    type = "ReturnIntent"
  }
}

resource "aws_lex_intent" "Appreciation" {
  name = "Appreciation"
  description = "Intent for appreciating the service"

  sample_utterances = [
    "I appreciate your service",
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

