provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lex_bot" "pizza_ordering_bot" {
  name        = "pizza-ordering-bot"
  description = "A Lex bot for ordering pizzas"

  # Configure NLU intent confidence threshold
  nlu_intent_confidence_threshold = 0.5

  # Define the bot's locale (English in this case)
  locale {
    locale_id = "en_US"
    nlu_intent_confidence_threshold = 0.5
  }

  # Define the bot's voice settings (optional)
  voice_settings {
    voice_id = "Joanna" # Default AWS voice
  }

  # Define the bot's child directed settings (optional)
  child_directed = false
}

# Example: Create a slot type for pizza size (optional)
resource "aws_lex_slot_type" "pizza_size_slot" {
  name     = "PizzaSize"
  value_elimination_enabled = true
  enum_value {
    value = "small"
  }
  enum_value {
    value = "medium"
  }
  enum_value {
    value = "large"
  }
}

# Example: Create an intent for ordering pizza (optional)
resource "aws_lex_intent" "order_pizza_intent" {
  bot_name      = aws_lex_bot.pizza_ordering_bot.name
  intent_name   = "OrderPizza"
  sample_utterances = [
    "I want a pizza",
    "Order a pizza",
    "Pizza please"
  ]

  # Define slots for the intent (optional)
  slot {
    name = "pizza_size"
    type = aws_lex_slot_type.pizza_size_slot.name
  }

  # Define fulfillment code (optional)
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

