# Create IAM role for Lambda execution
resource "aws_iam_role" "lex_lambda_role" {
  name = "lex-pizza-order-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lex_lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create Lambda function for pizza order processing
resource "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "lambda_function.zip"
  source {
    content  = <<-EOT
      def lambda_handler(event, context):
          # Simple pizza order processing logic
          intent_name = event.get('currentIntent', {}).get('name')
          slots = event.get('currentIntent', {}).get('slots', {})

          if intent_name == 'PizzaOrderIntent':
              size = slots.get('Size', '').lower()
              toppings = slots.get('Toppings', '').lower().split(',')
              crust = slots.get('Crust', '').lower()

              response = {
                  "sessionAttributes": {
                      "size": size,
                      "toppings": toppings,
                      "crust": crust
                  },
                  "dialogAction": {
                      "type": "Close",
                      "fulfillmentState": "Fulfilled",
                      "message": {
                          "contentType": "PlainText",
                          "content": f"Thank you! Your {size} {crust} pizza with {', '.join(toppings)} will be ready in 30 minutes."
                      }
                  }
              }
              return response
          else:
              return {
                  "sessionAttributes": {},
                  "dialogAction": {
                      "type": "Close",
                      "fulfillmentState": "Failed",
                      "message": {
                          "contentType": "PlainText",
                          "content": "Sorry, I don't understand that intent."
                      }
                  }
              }
      EOT
    filename = "lambda_function.py"
  }
}

