# AWS Connect Instance (if not already created)
resource "aws_connect_instance" "children_connect_instance" {
  name        = "children-connect-instance"
  type        = "STANDARD"
  region      = "us-east-1"
  service_role_arn = aws_iam_role.connect_bot_role.arn
}

# AWS Connect Bot (tailored for children)
resource "aws_connect_bot" "children_bot" {
  name        = "children-support-bot"
  description = "Support bot for children's use case"
  instance_id = aws_connect_instance.children_connect_instance.id

  # Basic configuration for a children's bot
  configuration {
    bot_name        = "children-support-bot"
    description     = "Bot for children's support"
    language_code   = "en-US"
    default_language_code = "en-US"
    default_experience_name = "children-support-experience"
    default_flow_name = "children-support-flow"
  }

  # Security settings for children's bot
  security {
    allow_public_access = false
    allow_anonymous_invites = false
    allow_guest_access = false
  }
}

# AWS Connect Bot Association (tailored for children)
resource "aws_connect_bot_association" "children_bot_association" {
  bot_id = aws_connect_bot.children_bot.id
  instance_id = aws_connect_instance.children_connect_instance.id

  # Association with a specific user group for children's support
  user_group_ids = [
    aws_connect_user_group.children_support_group.id
  ]

  # Association with a specific contact flow for children
  contact_flow_id = aws_connect_contact_flow.children_support_flow.id
}

# AWS Connect User Group for children's support
resource "aws_connect_user_group" "children_support_group" {
  name        = "children-support-group"
  description = "User group for children's support agents"
  instance_id = aws_connect_instance.children_connect_instance.id
}

# AWS Connect Contact Flow for children's support
resource "aws_connect_contact_flow" "children_support_flow" {
  name        = "children-support-flow"
  description = "Contact flow for children's support"
  instance_id = aws_connect_instance.children_connect_instance.id

  # Example: Simple flow for children's support
  content = <<EOF
{
  "Type": "ContactFlow",
  "Name": "children-support-flow",
  "Description": "Contact flow for children's support",
  "Steps": [
    {
      "Type": "Start",
      "Name": "Start",
      "NextStep": "Greeting"
    },
    {
      "Type": "Greeting",
      "Name": "Greeting",
      "GreetingText": "Hello! I'm your friendly support bot. How can I help you today?",
      "NextStep": "AskQuestion"
    },
    {
      "Type": "AskQuestion",
      "Name": "AskQuestion",
      "QuestionText": "What would you like help with?",
      "NextStep": "HandleQuestion"
    },
    {
      "Type": "HandleQuestion",
      "Name": "HandleQuestion",
      "Question": "What is your question?",
      "NextStep": "End"
    },
    {
      "Type": "End",
      "Name": "End",
      "EndReason": "SUCCESS"
    }
  ]
}
EOF
}
