terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Kinesis data stream
resource "aws_kinesis_stream" "analytics_input_stream" {
  name             = "analytics-input-stream"
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours (default is 24)
}

# Create an IAM role for Kinesis Data Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policies to the IAM role
resource "aws_iam_role_policy_attachment" "analytics_stream_access" {
  role       = aws_iam_role.analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFullAccess"
}

resource "aws_iam_role_policy_attachment" "analytics_cloudwatch" {
  role       = aws_iam_role.analytics_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# Create a Kinesis Data Analytics application
resource "aws_kinesisanalyticsv2_application" "flink_application" {
  application_name = "flink-analytics-app"
  runtime_environment {
    type = "FLINK_RUNTIME_2_11"
    image_version {
      image_uri = "flink:1.15.0-scala_2.12-java11"
    }
  }
  service_execution_role_arn = aws_iam_role.analytics_role.arn
  application_code_location {
    s3_location {
      bucket_arn = aws_s3_bucket.application_bucket.arn
      file_key   = "application.jar" # Path to your Flink application JAR
    }
  }
  application_configuration {
    application_code_configuration {
      code_content_type = "application/java-archive"
      code_content      = filebase64("path/to/your/application.jar") # Replace with your JAR file path
    }
    application_environment_properties = {
      "app.input.stream" = aws_kinesis_stream.analytics_input_stream.name
      "app.output.stream" = aws_kinesis_stream.analytics_output_stream.name # Output stream (optional)
    }
  }
  depends_on = [aws_s3_bucket.application_bucket]
}

# Create an S3 bucket for storing the application JAR (optional)
resource "aws_s3_bucket" "application_bucket" {
  bucket = "kinesis-analytics-app-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Output the Kinesis stream ARN for reference
output "kinesis_stream_arn" {
  value = aws_kinesis_stream.analytics_input_stream.arn
}

# Output the Kinesis Analytics application name for reference
output "analytics_application_name" {
  value = aws_kinesisanalyticsv2_application.flink_application.application_name
}

