      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kinesisanalyticsv2_application" "flink_application" {
  name = "flink-apps-streaming-app"

  runtime_environment {
    type = "FlinkV2_2_0"
    scala_version = "2.12"
    application_code_location {
      s3_location {
        bucket_arn = aws_s3_bucket.flink_application_bucket.arn
        file_key    = "flink-app.jar"
      }
    }
    service_execution_role_arn = aws_iam_role.flink_application_role.arn
  }

  application_configuration {
    application_code_configuration {
      code_content_type = "ZIP"
      code_content      = filebase64("path/to/your/flink-app.zip") # Replace with actual path to your Flink app zip
    }
  }
}

resource "aws_s3_bucket" "flink_application_bucket" {
  bucket = "flink-app-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "flink_application_role" {
  name = "flink-apps-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "flink_application_policy" {
  role       = aws_iam_role.flink_application_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

resource "aws_kinesisanalyticsv2_application_version" "flink_application_version" {
  application_name = aws_kinesisanalyticsv2_application.flink_application.name
  version_name     = "flink-app-v1"
  configuration {
    application_code_configuration {
      code_content_type = "ZIP"
      code_content      = filebase64("path/to/your/flink-app.zip") # Replace with actual path to your Flink app zip
    }
  }
}

resource "aws_kinesisanalyticsv2_application_environment_properties" "flink_environment" {
  application_name = aws_kinesisanalyticsv2_application.flink_application.name
  properties = {
    "application.parallelism" = "1"
    "flink.application.id"    = "flink-app"
    "flink.checkpointing.interval" = "60000"
    "flink.checkpointing.mode" = "EXACTLY_ONCE"
    "flink.state.backend" = "rocksdb"
    "flink.state.backend.incremental" = "true"
    "flink.state.backend.rocksdb.compaction-lifecycle" = "defaultCompactionStrategy"
    "flink.state.backend.rocksdb.compaction-lifecycle.default-compaction-strategy" = "defaultCompactionStrategy"
  }
}
