terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an IAM role for Kinesis Data Firehose to assume
resource "aws_iam_role" "firehose_delivery_role" {
  name = "firehose-delivery-role-to-redshift"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policies to the IAM role
resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_delivery_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "firehose_redshift_access" {
  role       = aws_iam_role.firehose_delivery_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRedshiftFullAccess"
}

# Create an S3 bucket for temporary buffering
resource "aws_s3_bucket" "firehose_buffer_bucket" {
  bucket = "firehose-buffer-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "firehose_buffer_bucket" {
  bucket = aws_s3_bucket.firehose_buffer_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Create a Kinesis Data Firehose delivery stream targeting Redshift
resource "aws_kinesisfirehose_delivery_stream" "redshift_delivery_stream" {
  name        = "redshift-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_delivery_role.arn
    bucket_arn = aws_s3_bucket.firehose_buffer_bucket.arn
    prefix     = "firehose-data/"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesisfirehose_delivery_stream.redshift_delivery_stream.name}"
      log_stream_name = "S3ExtendedDelivery"
    }

    processing_configuration {
      enabled = "false"
    }
  }

  s3_backup_configuration {
    role_arn   = aws_iam_role.firehose_delivery_role.arn
    bucket_arn = aws_s3_bucket.firehose_buffer_bucket.arn
    prefix     = "firehose-backup/"

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesisfirehose_delivery_stream.redshift_delivery_stream.name}"
      log_stream_name = "S3BackupDelivery"
    }
  }

  tags = {
    Name = "RedshiftDeliveryStream"
  }
}

# Create a Redshift cluster (simplified example)
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this to a secure password
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Configure Redshift to accept data from Firehose
  iam_roles = [
    aws_iam_role.firehose_delivery_role.arn
  ]

  # Enable enhanced VPC routing
  publicly_accessible = false
  skip_final_snapshot = true
}

# Create a Redshift table for the incoming data (simplified example)
resource "aws_redshift_data_api_permission" "firehose_permission" {
  database = aws_redshift_cluster.example.database_name
  iam_role_arns = [
    aws_iam_role.firehose_delivery_role.arn
  ]
}

# Create a Redshift COPY command to load data from S3 (example)
resource "aws_redshift_data_api_grant" "firehose_grant" {
  database = aws_redshift_cluster.example.database_name
  iam_role_arns = [
    aws_iam_role.firehose_delivery_role.arn
  ]
}

# Note: You'll need to manually create a Redshift table and set up a COPY command
# to load data from the S3 bucket into Redshift. This is typically done via SQL.
# Example SQL:
# CREATE TABLE IF NOT EXISTS firehose_data (
#   column1 VARCHAR(255),
#   column2 INT
# );
# COPY firehose_data FROM 's3://firehose-buffer-bucket-XXXX/firehose-data/'
# CREDENTIALS 'aws_iam_role=arn:aws:iam::ACCOUNT_ID:role/firehose-delivery-role-to-redshift'
# FORMAT AS JSON 'auto';

