resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this to a secure password
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Configure Redshift to accept data from Firehose
  iam_roles = [
    aws_iam_role.firehose_delivery_role.arn
  ]

  # Enable enhanced VPC routing
  publicly_accessible = false
  skip_final_snapshot = true
}

# Create a Redshift table for the incoming data (simplified example)
resource "aws_redshift_data_api_permission" "firehose_permission" {
  database = aws_redshift_cluster.example.database_name
  iam_role_arns = [
    aws_iam_role.firehose_delivery_role.arn
  ]
}

# Create a Redshift COPY command to load data from S3 (example)
resource "aws_redshift_data_api_grant" "firehose_grant" {
  database = aws_redshift_cluster.example.database_name
  iam_role_arns = [
    aws_iam_role.firehose_delivery_role.arn
  ]
}

# Note: You'll need to manually create a Redshift table and set up a COPY command
# to load data from the S3 bucket into Redshift. This is typically done via SQL.
# Example SQL:
# CREATE TABLE IF NOT EXISTS firehose_data (
#   column1 VARCHAR(255),
#   column2 INT
# );
# COPY firehose_data FROM 's3://firehose-buffer-bucket-XXXX/firehose-data/'
# CREDENTIALS 'aws_iam_role=arn:aws:iam::ACCOUNT_ID:role/firehose-delivery-role-to-redshift'
# FORMAT AS JSON 'auto';
