    hec_endpoint = var.splunk_hec_endpoint    # Replace with your Splunk HEC endpoint
    hec_token    = var.splunk_hec_token      # Replace with your Splunk HEC token
    hec_tls      = "ENABLED"                 # Enable TLS for secure connection
    index        = var.splunk_index          # Replace with your Splunk index name
    region        = var.splunk_region        # Replace with your Splunk region (e.g., "us1")
  }

  buffer_size    = 5 # Buffer size in MB (5-128)
  buffer_interval = 300 # Buffer interval in seconds (60-900)

  cloudwatch_logging_options {
    enabled         = true
    log_group_name  = "/aws/kinesisfirehose/splunk-delivery-stream"
    log_stream_name = "Delivery"
  }

  tags = {
    Name        = "SplunkDeliveryStream"
    Environment = "Production"
  }
}

