provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_stream" {
  name        = "elasticsearch-delivery-stream"
  destination = "extended_s3_compatible"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_elasticsearch_role.arn
    bucket_arn = aws_s3_bucket.firehose_buffer_bucket.arn
    prefix     = "firehose/elasticsearch/"
    buffering_hints {
      size    = 5 # MB
      interval = 300 # seconds
    }
    compression_format = "GZIP"
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_cloudwatch_log_group.firehose_log_group.name}"
      log_stream_name = "firehose-elasticsearch-stream"
    }
    error_output_prefix = "firehose/errors/"
  }

  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.elasticsearch_domain.arn
    index_name = "firehose-data"
    type_name  = "_doc"
    role_arn   = aws_iam_role.firehose_elasticsearch_role.arn
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_cloudwatch_log_group.firehose_log_group.name}"
      log_stream_name = "firehose-elasticsearch-stream"
    }
    retry_options {
      duration = 300 # seconds
    }
    vpc_configuration {
      security_group_ids = [aws_security_group.firehose_elasticsearch_sg.id]
      subnet_ids         = [aws_subnet.firehose_subnet_1.id, aws_subnet.firehose_subnet_2.id]
    }
  }
}

resource "aws_elasticsearch_domain" "elasticsearch_domain" {
  domain_name           = "firehose-elasticsearch-domain"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "t3.small.elasticsearch"
    instance_count = 1
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 20
  }

  vpc_options {
    security_group_ids = [aws_security_group.elasticsearch_sg.id]
    subnet_ids         = [aws_subnet.elasticsearch_subnet_1.id, aws_subnet.elasticsearch_subnet_2.id]
  }

  access_policies = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          AWS = aws_iam_role.firehose_elasticsearch_role.arn
        },
        Action = [
          "es:*"
        ],
        Resource = "arn:aws:es:${var.region}:${data.aws_caller_identity.current.account_id}:domain/${aws_elasticsearch_domain.elasticsearch_domain.domain_name}/*"
      }
    ]
  })
}

resource "aws_s3_bucket" "firehose_buffer_bucket" {
  bucket = "firehose-buffer-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "firehose_elasticsearch_role" {
  name = "firehose-elasticsearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_elasticsearch_policy" {
  name = "firehose-elasticsearch-policy"
  role = aws_iam_role.firehose_elasticsearch_role.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetBucketLocation"
        ],
        Resource = [
          aws_s3_bucket.firehose_buffer_bucket.arn,
          "${aws_s3_bucket.firehose_buffer_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogGroup",
          "logs:CreateLogStream"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "es:ESHttpPost",
          "es:ESHttpPut"
        ],
        Resource = aws_elasticsearch_domain.elasticsearch_domain.arn
      },
      {
        Effect = "Allow",
        Action = [
          "kms:Decrypt"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name = "/aws/kinesisfirehose/firehose-elasticsearch-stream"
}

resource "aws_security_group" "firehose_elasticsearch_sg" {
  name        = "firehose-elasticsearch-sg"
  description = "Allow traffic between Firehose and Elasticsearch"
  vpc_id      = aws_vpc.main.id

