resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "opensearch-delivery-stream"
  destination = "extended_s3" # Temporary placeholder, will be updated for OpenSearch

  # Configure OpenSearch destination
  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/"
    buffering_hints {
      size    = 5 # MB
      interval = 300 # seconds
    }
  }

  # OpenSearch destination configuration (requires OpenSearch Service)
  http_endpoint_configuration {
    url          = "https://${aws_opensearch_domain.opensearch_domain.endpoint}"
    name         = "opensearch-destination"
    role_arn     = aws_iam_role.firehose_role.arn
    buffering_hints {
      size    = 1 # MB
      interval = 60 # seconds
    }
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.opensearch_stream.name}"
      log_stream_name = "Delivery"
    }
    processing_configuration {
      enabled = "true"
    }
    vpc_configuration {
      security_group_ids = [aws_security_group.firehose_sg.id]
      subnet_ids         = [aws_subnet.firehose_subnet.id]
    }
  }
}

resource "aws_opensearch_domain" "opensearch_domain" {
  domain_name    = "firehose-opensearch-domain"
  version        = "OpenSearch_1.3" # Adjust version as needed
  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
  }
  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }
  encrypt_at_rest {
    enabled = true
  }
  node_to_node_encryption {
    enabled = true
  }
  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }
  tags = {
    Name = "firehose-opensearch-domain"
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-opensearch-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:AbortMultipartUpload",
          "s3:ListMultipartUploadParts"
        ],
        Resource = [
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogGroup",
          "logs:CreateLogStream"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "opensearch:ESHttpPost",
          "opensearch:ESHttpPut"
        ],
        Resource = [
          "arn:aws:opensearch:${var.region}:${data.aws_caller_identity.current.account_id}:domain/${aws_opensearch_domain.opensearch_domain.domain_name}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "kms:Decrypt"
        ],
        Resource = "*"
      }
    ]
  })
}

