  policy_arn = aws_iam_policy.kinesis_analytics_policy.arn
}

# Kinesis Data Stream for input
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-data-stream"
  shard_count      = 1
  retention_period = 24 # in hours
}

# Kinesis Data Analytics Application
resource "aws_kinesisanalytics_application" "analytics_app" {
  name = "simple-kinesis-analytics-app"

  application_mode = "STREAM_PROCESSING"

  runtime_environment {
    type = "FLINK"
    image_uri = "flink:1.15"
    service_execution_role = aws_iam_role.kinesis_analytics_role.arn
  }

  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_code_s3 {
      code_location = "s3://your-bucket-name/path/to/your/application-code.jar"
      code_location_type = "S3"
    }
  }

  input {
    name = "input-stream"
    kinesis_stream_input {
      resource_arn = aws_kinesis_stream.input_stream.arn
      input_parallelism = 1
    }
  }

  output {
    name = "output-stream"
    kinesis_firehose_output {
      resource_arn = aws_kinesis_firehose_delivery_stream.firehose_stream.arn
    }
  }
}

# Kinesis Firehose Delivery Stream for output (optional)
