provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_kendra_index" "example" {
  name = "example-kendra-index"

  versioning_configuration {
    versioning_enabled = true
  }

  document_metadata_configuration {
    dynamic "document_metadata_configurations" {
      for_each = [
        {
          name        = "Author"
          type        = "STRING"
          description = "Author of the document"
        },
        {
          name        = "DateCreated"
          type        = "DATE"
          description = "Date when the document was created"
        },
        {
          name        = "Department"
          type        = "STRING"
          description = "Department the document belongs to"
        },
        {
          name        = "DocumentType"
          type        = "STRING"
          description = "Type of the document (e.g., PDF, Word)"
        }
      ]

      content {
        name        = document_metadata_configurations.value.name
        type        = document_metadata_configurations.value.type
        description = document_metadata_configurations.value.description
      }
    }
  }

  # Standard DocumentMetadataConfigurationUpdates
  document_metadata_configuration_update {
    name        = "LastUpdated"
    type        = "DATE"
    description = "Last time the document was updated"
  }

  document_metadata_configuration_update {
    name        = "Owner"
    type        = "STRING"
    description = "Owner of the document"
  }

  document_metadata_configuration_update {
    name        = "Priority"
    type        = "STRING"
    description = "Priority level of the document (e.g., High, Medium, Low)"
  }

  # Optional: Throttling configuration
  throttling_configuration {
    requests_per_call = 10
    requests_per_second = 100
  }
}

