terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a hosted zone for the primary domain
resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your primary domain
}

# Create a health check for the primary service
resource "aws_route53_health_check" "primary_health_check" {
  name = "primary_health_check"

  health_check_config {
    type                = "HTTPS"
    fully_qualified_domain_name = "api.example.com" # Replace with your FQDN
    resource_path       = "/health" # Replace with your health check endpoint
    failure_threshold   = 3
    request_interval    = 30
    type                = "HTTP"
    ip_protocol_support = "IPV4_ONLY"
    port               = "443"
    enabled             = true
  }
}

# Create a failover record set for active-passive failover
resource "aws_route53_record" "active_passive_failover" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "api.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name # Replace with your ALB/DNS name
    zone_id                = aws_lb.primary.zone_id # Replace with your ALB/Zone ID
    evaluate_target_health = true
    failover_routing_policy {
      type = "PRIMARY"
    }
  }

  set_identifier = "primary"
}

# Create a secondary failover record set (passive)
resource "aws_route53_record" "secondary_failover" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "api.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name # Replace with your secondary ALB/DNS name
    zone_id                = aws_lb.secondary.zone_id # Replace with your secondary ALB/Zone ID
    evaluate_target_health = true
    failover_routing_policy {
      type = "SECONDARY"
    }
  }

  set_identifier = "secondary"
  health_check_id = aws_route53_health_check.primary_health_check.id
}

