  zone_id = data.aws_route53_zone.main.zone_id
  name    = "primary.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name # Replace with your primary load balancer DNS name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.primary_health_check.id
  }

  set_identifier = "primary"
  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Create secondary failover record set
resource "aws_route53_record" "secondary_failover" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "secondary.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name # Replace with your secondary load balancer DNS name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.secondary_health_check.id
  }

