terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create primary health check
resource "aws_health_check" "primary_health_check" {
  name          = "primary_health_check"
  health_check_rr_set_name = "primary.example.com" # Replace with your FQDN
  type           = "HTTPS"
  resource_path  = "/" # Adjust based on your endpoint
  fully_qualified_domain_name = "primary.example.com" # Replace with your FQDN
  port           = 443
  failure_threshold = 3
  request_interval = 30
  invert_healthy_state = false
}

# Create secondary health check
resource "aws_health_check" "secondary_health_check" {
  name          = "secondary_health_check"
  health_check_rr_set_name = "secondary.example.com" # Replace with your FQDN
  type           = "HTTPS"
  resource_path  = "/" # Adjust based on your endpoint
  fully_qualified_domain_name = "secondary.example.com" # Replace with your FQDN
  port           = 443
  failure_threshold = 3
  request_interval = 30
  invert_healthy_state = false
}

# Reference hosted zone
data "aws_route53_zone" "main" {
  name         = "example.com" # Replace with your hosted zone name
  private_zone = false
}

# Create primary failover record set
resource "aws_route53_record" "primary_failover" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "primary.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name # Replace with your primary load balancer DNS name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.primary_health_check.id
  }

  set_identifier = "primary"
  failover_routing_policy {
    type = "PRIMARY"
  }
}

# Create secondary failover record set
resource "aws_route53_record" "secondary_failover" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "secondary.example.com" # Replace with your FQDN
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name # Replace with your secondary load balancer DNS name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.secondary_health_check.id
  }

  set_identifier = "secondary"
  failover_routing_policy {
    type = "SECONDARY"
  }
}

# Create failover record set for the main domain
resource "aws_route53_record" "main_failover" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "example.com" # Replace with your main domain
  type    = "A"

  alias {
    name                   = aws_lb.primary.dns_name # Replace with your primary load balancer DNS name
    zone_id                = aws_lb.primary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.primary_health_check.id
  }

  failover_routing_policy {
    type = "PRIMARY"
    failover_routing_method = "ACTIVE"
  }

  set_identifier = "primary"
}

# Create secondary failover record set for the main domain
resource "aws_route53_record" "main_failover_secondary" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "example.com" # Replace with your main domain
  type    = "A"

  alias {
    name                   = aws_lb.secondary.dns_name # Replace with your secondary load balancer DNS name
    zone_id                = aws_lb.secondary.zone_id
    evaluate_target_health = true
    health_check_id        = aws_health_check.secondary_health_check.id
  }

  failover_routing_policy {
    type = "SECONDARY"
    failover_routing_method = "STANDBY"
  }

  set_identifier = "secondary"
}

# Example load balancers (uncomment and configure if needed)
# resource "aws_lb" "primary" {
