terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Route 53 hosted zone named "primary"
resource "aws_route53_zone" "primary" {
  name = "primary"
}

# Create a Route 53 traffic policy for geographic routing
resource "aws_route53_traffic_policy" "geo_policy" {
  name          = "geo-routing-policy"
  description   = "Route users to US or EU based on their location"
  type          = "GEO"
  zone_id       = aws_route53_zone.primary.zone_id

  record_set {
    name    = aws_route53_zone.primary.name
    type    = "A"
    ttl     = 300
    value   = "10.0.0.1" # Replace with your US endpoint IP
    region  = "US"
  }

  record_set {
    name    = aws_route53_zone.primary.name
    type    = "A"
    ttl     = 300
    value   = "10.0.0.2" # Replace with your EU endpoint IP
    region  = "EU"
  }
}

# Create a Route 53 traffic policy instance
resource "aws_route53_traffic_policy_instance" "geo_instance" {
  name          = "geo-routing-instance"
  description   = "Instance for geographic routing"
  policy_id     = aws_route53_traffic_policy.geo_policy.id
  zone_id       = aws_route53_zone.primary.zone_id
}

# Create a Route 53 hosted zone record set for the traffic policy
resource "aws_route53_record" "primary_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = aws_route53_zone.primary.name
  type    = "A"

  alias {
    name                   = aws_route53_traffic_policy_instance.geo_instance.fqdn
    zone_id                = aws_route53_traffic_policy_instance.geo_instance.zone_id
    evaluate_target_health = false
  }
}

