      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_route53_health_check" "example_health_check" {
  for_each = {
    "health_check_1" = "example.com",
    "health_check_2" = "api.example.com"
  }

  fqdn             = each.value
  type             = "HTTPS"
  resource_path    = "/health" # Adjust based on your health check endpoint
  fully_qualified_domain_name = each.value
  port             = "443"
  request_interval = "30"
  failure_threshold = "3"
}

resource "aws_route53_health_check_config" "example_config" {
  type             = "HTTPS"
  resource_path    = "/health" # Adjust based on your health check endpoint
  fully_qualified_domain_name = "example.com" # Update to your domain
  port             = "443"
  request_interval = "30"
  failure_threshold = "3"
}

resource "aws_route53_health_check_config_subscription" "example_subscription" {
  health_check_config_id = aws_route53_health_check_config.example_config.id
}

resource "aws_route53_health_check" "example_health_check_config" {
  depends_on = [aws_route53_health_check_config_subscription.example_subscription]
  fqdn             = aws_route53_health_check_config.example_config.fully_qualified_domain_name
  type             = aws_route53_health_check_config.example_config.type
  resource_path    = aws_route53_health_check_config.example_config.resource_path
  fully_qualified_domain_name = aws_route53_health_check_config.example_config.fully_qualified_domain_name
  port             = aws_route53_health_check_config.example_config.port
  request_interval = aws_route53_health_check_config.example_config.request_interval
  failure_threshold = aws_route53_health_check_config.example_config.failure_threshold
}

resource "aws_route53_geolocation_record_set" "example_geolocation" {
  zone_id = "YOUR_HOSTED_ZONE_ID" # Replace with your hosted zone ID

  name    = "example.com"
  type    = "A"
  geolocation_single_region = "US"
  set_identifier = "us_region"
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.example_health_check["health_check_1"].id
  alias {
    name                   = aws_route53_health_check.example_health_check["health_check_1"].fqdn
    zone_id                = aws_route53_health_check.example_health_check["health_check_1"].zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_latency_record_set" "example_latency" {
  zone_id = "YOUR_HOSTED_ZONE_ID" # Replace with your hosted zone ID

  name    = "example.com"
  type    = "A"
  latency_region_code = "US-EAST-1"
  set_identifier = "us_east_1"
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.example_health_check["health_check_1"].id
  alias {
    name                   = aws_route53_health_check.example_health_check["health_check_1"].fqdn
    zone_id                = aws_route53_health_check.example_health_check["health_check_1"].zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_weighted_record_set" "example_weighted" {
  zone_id = "YOUR_HOSTED_ZONE_ID" # Replace with your hosted zone ID

  name    = "example.com"
  type    = "A"
  records = ["192.0.2.1", "198.51.100.1"] # Replace with your IP addresses
  weights = [10, 90] # Adjust weights as needed
  set_identifier = "weighted_example"
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.example_health_check["health_check_1"].id
  alias {
