    zone_id                = aws_route53_health_check.example_health_check["health_check_1"].zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_failover_record_set" "example_failover" {
  zone_id = "YOUR_HOSTED_ZONE_ID" # Replace with your hosted zone ID

  name    = "example.com"
  type    = "A"
  records = ["192.0.2.1", "198.51.100.1"] # Replace with your primary and secondary IPs
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.example_health_check["health_check_1"].id
  alias {
    name                   = aws_route53_health_check.example_health_check["health_check_1"].fqdn
    zone_id                = aws_route53_health_check.example_health_check["health_check_1"].zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_failover_record_set" "example_failover_secondary" {
  zone_id = "YOUR_HOSTED_ZONE_ID" # Replace with your hosted zone ID

  name    = "example.com"
  type    = "A"
  records = ["192.0.2.2", "198.51.100.2"] # Replace with your secondary IPs
  failover_routing_policy {
    type = "SECONDARY"
  }
  health_check_id = aws_route53_health_check.example_health_check["health_check_2"].id
  alias {
    name                   = aws_route53_health_check.example_health_check["health_check_2"].fqdn
    zone_id                = aws_route53_health_check.example_health_check["health_check_2"].zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_traffic_policy_instance" "example_policy" {
  name = "example-traffic-policy"

