        type    = "A"
        value   = "192.0.2.1"
        ttl     = 300
      }
    }

    failover {
      type = "SECONDARY"
      records {
        name    = "example.com"
        type    = "A"
        value   = "198.51.100.1"
        ttl     = 300
      }
    }

    geolocation {
      country_code = "US"
      records {
        name    = "example.com"
        type    = "A"
        value   = "192.0.2.1"
        ttl     = 300
      }
    }
  }
