provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Fetch AWS caller identity
data "aws_caller_identity" "current" {}

# Optional: Lookup most recent stable ECR image tag
data "aws_ecr_repository" "eks_image_repo" {
  name = "your-ecr-repo-name" # Replace with your ECR repository name
}

data "aws_ecr_repository_tag_mutability" "eks_image_repo" {
  repository = data.aws_ecr_repository.eks_image_repo.name
}

locals {
  # Define image tag (use stable tag if available, otherwise latest)
  image_tag = try(
    data.aws_ecr_repository_tag_mutability.eks_image_repo.mutability == "MUTABLE" ?
    (data.aws_ecr_repository_tag_mutability.eks_image_repo.mutability == "MUTABLE" ?
    (data.aws_ecr_repository_tag_mutability.eks_image_repo.mutability == "MUTABLE" ?
    "stable" : "latest") : "stable") : "latest",
    "latest"
  )

  # AWS tags for resources
  aws_tags = {
    Environment = "production"
    Terraform   = "true"
    ManagedBy   = "eks-cluster"
  }

  # Workspace name (defaults to current workspace)
  workspace_name = terraform.workspace
}

# EKS Module Configuration
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = "my-eks-cluster"
  cluster_version = "1.28"

  vpc_id     = "vpc-12345678" # Replace with your VPC ID
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs

  node_groups = {
    eks_nodes = {
      desired_capacity = 2
      max_capacity     = 3
      min_capacity     = 1

      instance_types = ["t3.medium"]

      iam_role_additional_policies = {
        AmazonEC2ContainerRegistryReadOnly = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
      }

      iam_role_use_name_prefix = true
    }
  }

  cluster_addons = {
    aws-ebs-csi-driver = {
      most_recent = true
    }
  }

  tags = local.aws_tags
}

# Fetch EKS cluster metadata
data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_id
}

data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_id
}

# Configure Kubernetes provider
provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

# Configure Helm provider
provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}
