# Define the IAM policy document for the custom policy
resource "aws_iam_policy" "example" {
  name        = "example-eks-namespace-policy"
  description = "Policy to restrict access to a specific namespace in EKS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "eks:DescribeCluster",
          "eks:ListClusters",
          "eks:AccessKubernetesApi"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "eks:DescribeCluster",
          "eks:ListClusters",
          "eks:ListNamespaces",
          "eks:ListPodIdentifiers",
          "eks:ListPods",
          "eks:ListPodsInNamespace",
          "eks:ListPodsForGroup",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace",
          "eks:ListPodsForGroupInNamespace"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "eks:DescribeNamespace",
          "eks:ListNamespaces"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}/namespace/${var.target_namespace}"
