  default     = "restricted-namespace" # Replace with your target namespace
}

variable "region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

# Get the current AWS account ID
data "aws_caller_identity" "current" {}

# Attach the IAM role to the EKS cluster
resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.27" # Specify your desired Kubernetes version

  depends_on = [
    aws_iam_role_policy_attachment.example,
    aws_iam_role_policy_attachment.example_custom_policy
  ]
}

# Create an IAM policy for a principal to access the EKS cluster with namespace restriction
resource "aws_iam_policy" "principal_policy" {
  name        = "example-principal-namespace-policy"
  description = "Policy to restrict a principal's access to a specific namespace in EKS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::${var.principal_account_id}:role/${var.principal_role_name}" # Replace with your principal ARN
        },
        Action = [
          "eks:DescribeCluster",
          "eks:AccessKubernetesApi"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "eks:ListNamespaces",
          "eks:ListPods",
          "eks:ListPodsInNamespace"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "eks:DescribeNamespace",
          "eks:ListPodsInNamespace",
          "eks:ListDeploymentsInNamespace",
          "eks:ListServicesInNamespace",
          "eks:ListConfigMapsInNamespace",
          "eks:ListSecretsInNamespace"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}/namespace/${var.target_namespace}"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "eks:DescribePod",
          "eks:DescribeDeployment",
          "eks:DescribeService",
          "eks:DescribeConfigMap",
          "eks:DescribeSecret"
        ],
        Resource = [
          "arn:aws:eks:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}/namespace/${var.target_namespace}/*"
        ]
      }
    ]
  })
}

# Variables for principal ARN
variable "principal_account_id" {
  description = "AWS account ID of the principal"
  type        = string
  default     = "123456789012" # Replace with your principal account ID
}

variable "principal_role_name" {
  description = "IAM role name of the principal"
  type        = string
  default     = "example-principal-role" # Replace with your principal role name
}

