  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "platform_infra" {
  bucket_prefix = "wellcomecollection-platform-infra-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.platform_infra.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "platform_infra" {
  depends_on = [ aws_s3_bucket_ownership_controls.example ]

  bucket = aws_s3_bucket.platform_infra.id
  acl    = "private"
}

resource "aws_s3_bucket_lifecycle_configuration" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  rule {
    id = "tmp"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }

    status = "Enabled"
  }

  rule {
    id = "expire_old_versions"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }

    status = "Enabled"
  }
}

resource "aws_s3_bucket_versioning" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  versioning_configuration {
    status = "Enabled"
  }
}

response:
```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_s3_bucket" "wellcomecollection_platform_infra" {
  bucket = "wellcomecollection-platform-infra"

  # Prevent accidental deletion
  force_destroy = false

  # Enable versioning
  versioning {
    enabled = true
  }

  # Set bucket ACL to private
  acl = "private"

  # Enable server-side encryption by default
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Lifecycle rule for objects under 'tmp/' prefix
  lifecycle_rule {
    id      = "tmp-objects-rule"
    prefix  = "tmp/"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    expiration {
      days = 30
    }
  }

  # Lifecycle rule for previous versions of objects
  lifecycle_rule {
    id      = "previous-versions-rule"
    enabled = true

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
      noncurrent_version = true
    }

    expiration {
      days          = 90
      noncurrent_version = true
    }
  }
}

# Block public access to the bucket
resource "aws_s3_bucket_public_access_block" "wellcomecollection_platform_infra" {
  bucket = aws_s3_bucket.wellcomecollection_platform_infra.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
```

