variable "bucket_suffix" {
  description = "Suffix to append to the bucket names"
  type        = string
  default     = "test"
}

# CloudGoat data bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_acl" "cloudgoat_data_acl" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

resource "aws_s3_bucket_policy" "cloudgoat_data_policy" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect    = "Allow",
        Principal = {
          AWS = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
        },
        Action    = "s3:PutObject",
        Resource  = "${aws_s3_bucket.cloudgoat_data.arn}/*",
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
          }
        }
      }
    ]
  })
}

# Website data bucket
resource "aws_s3_bucket" "website_data" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_public_access_block" "website_data_public_access" {
  bucket = aws_s3_bucket.website_data.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_ownership_controls" "website_data_ownership" {
  bucket = aws_s3_bucket.website_data.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

resource "aws_s3_bucket_policy" "website_data_policy" {
  bucket = aws_s3_bucket.website_data.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect    = "Allow",
        Principal = "*",
        Action    = "s3:PutObject",
        Resource  = "${aws_s3_bucket.website_data.arn}/*"
      }
    ]
  })
}

resource "aws_s3_object" "upload_order_data" {
  bucket = aws_s3_bucket.website_data.id
  key    = "order_data2.csv"
  source = "order_data2.csv"
  etag   = filemd5("order_data2.csv")
}

data "aws_caller_identity" "current" {}

