terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a private S3 bucket
resource "aws_s3_bucket" "private_bucket" {
  bucket = "my-private-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

# Create a public S3 bucket for log delivery
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-delivery-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

# Generate a random suffix for bucket names to ensure uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Set ACL for private bucket (private by default)
resource "aws_s3_bucket_acl" "private_bucket_acl" {
  bucket = aws_s3_bucket.private_bucket.id
  acl    = "private"
}

# Set ACL for log bucket (log-delivery write access)
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# Enable logging on private bucket to deliver logs to log bucket
resource "aws_s3_bucket_logging" "private_bucket_logging" {
  bucket = aws_s3_bucket.private_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "logs/private-bucket/"
}

# Ensure bucket ACLs are applied before logging configuration
resource "null_resource" "acl_dependency" {
  triggers = {
    private_bucket_acl = aws_s3_bucket_acl.private_bucket_acl.id
    log_bucket_acl    = aws_s3_bucket_acl.log_bucket_acl.id
  }
}

# Output bucket names
output "private_bucket_name" {
  value = aws_s3_bucket.private_bucket.bucket
}

output "log_bucket_name" {
  value = aws_s3_bucket.log_bucket.bucket
}

