  bucket = "my-private-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

# Create a public S3 bucket for log delivery
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-delivery-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

# Generate a random suffix for bucket names to ensure uniqueness
