extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create VPC
resource "aws_vpc" "custom_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "custom-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.custom_vpc.id
  tags = {
    Name = "custom-igw"
  }
}

# Create Public Subnets
resource "aws_subnet" "public_subnet_a" {
  vpc_id                  = aws_vpc.custom_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-a"
  }
}

resource "aws_subnet" "public_subnet_b" {
  vpc_id                  = aws_vpc.custom_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-b"
  }
}

# Create Route Table and Route
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.custom_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public_subnet_a_association" {
  subnet_id      = aws_subnet.public_subnet_a.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table_association" "public_subnet_b_association" {
  subnet_id      = aws_subnet.public_subnet_b.id
  route_table_id = aws_route_table.public_route_table.id
}

# Get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-ebs"]
  }
}

# Create Security Group
resource "aws_security_group" "instance_sg" {
  name        = "instance-sg"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "instance-sg"
  }
}

# Launch EC2 Instance in Subnet A
resource "aws_instance" "instance_a" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnet_a.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  associate_public_ip_address = true
  key_name               = "your-key-pair-name" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              echo "Hello from EC2 Instance A" > /home/ec2-user/message.txt
                              EOF
  tags = {
    Name = "ec2-instance-a"
  }
}

# Attach EBS Volume to EC2 Instance A
resource "aws_ebs_volume" "ebs_volume_a" {
  availability_zone = "us-east-1a"
  size              = 50
  type              = "gp3"
  tags = {
    Name = "ebs-volume-a"
  }
}

resource "aws_volume_attachment" "ebs_attach_a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_a.id
  instance_id = aws_instance.instance_a.id
}

# Launch EC2 Instance in Subnet B
resource "aws_instance" "instance_b" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnet_b.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]
  associate_public_ip_address = true
  key_name               = "your-key-pair-name" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              echo "Hello from EC2 Instance B" > /home/ec2-user/message.txt
                              EOF
  tags = {
    Name = "ec2-instance-b"
  }
}

# Attach EBS Volume to EC2 Instance B
resource "aws_ebs_volume" "ebs_volume_b" {
  availability_zone = "us-east-1b"
  size              = 50
  type              = "gp3"
  tags = {
    Name = "ebs-volume-b"
  }
}

resource "aws_volume_attachment" "ebs_attach_b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_b.id
  instance_id = aws_instance.instance_b.id
}

