# AWS Redis (ElastiCache) Configuration
provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_elasticache_cluster" "redis" {
  cluster_id           = "my-redis-cluster"
  engine               = "redis"
  node_type            = "cache.t3.micro" # Free tier eligible
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379

  # Optional: Enable automatic failover
  auto_minor_version_upgrade = true
  replication_group_id      = aws_elasticache_replication_group.redis.id

  tags = {
    Name = "RedisCluster"
  }
}

resource "aws_elasticache_replication_group" "redis" {
  replication_group_id = "my-redis-replication-group"
  description          = "Redis replication group for failover"
  engine               = "redis"
  engine_version       = "7.0"
  port                 = 6379
  parameter_group_name = "default.redis7"
  node_type            = "cache.t3.micro"
  num_node_groups      = 1
  replication_group_description = "Primary replication group for Redis"

  tags = {
    Name = "RedisReplicationGroup"
  }
}

# GCP Redis (Memorystore) Configuration
provider "google" {
  project = "your-gcp-project-id" # Replace with your GCP project ID
  region  = "us-central1"         # Change to your preferred region
}

resource "google_redis_instance" "redis" {
  name           = "my-redis-instance"
  tier           = "BASIC" # Free tier eligible
  memory_size_mb = 1000
  region         = "us-central1"

  redis_config {
    redis_version = "REDIS_7_0"
    maxmemory_policy = "allkeys-lru"
  }

  labels = {
    environment = "dev"
  }
}

# Azure Redis Cache Configuration
