terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Redshift to assume (if needed for cross-account access)
resource "aws_iam_role" "redshift_cross_account_role" {
  name = "redshift-cross-account-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::012345678910:root" # Replace with your AWS account ID
        }
      }
    ]
  })
}

# IAM Policy for Redshift to assume (if needed)
resource "aws_iam_policy" "redshift_cross_account_policy" {
  name        = "redshift-cross-account-policy"
  description = "Policy for Redshift to access resources in another account"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "redshift:*",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_cross_account_attachment" {
  role       = aws_iam_role.redshift_cross_account_role.name
  policy_arn = aws_iam_policy.redshift_cross_account_policy.arn
}

# Redshift Cluster
resource "aws_redshift_cluster" "two_node_cluster" {
  cluster_identifier      = "two-node-cluster"
  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  publicly_accessible     = false
  skip_final_snapshot     = true # Set to false if you want a final snapshot

  # Optional: Enable enhanced VPC routing for private clusters
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Optional: Configure IAM roles for Redshift
  iam_roles = [aws_iam_role.redshift_cross_account_role.arn]
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your VPC CIDR or allowlist
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Redshift Endpoint Authorization (Cross-Account Access)
resource "aws_redshift_endpoint_authorization" "cross_account_auth" {
  cluster_identifier = aws_redshift_cluster.two_node_cluster.cluster_identifier
  principal          = "arn:aws:iam::012345678910:root" # Replace with the target AWS account ID
}

