terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "redshift-vpc"
  }
}

# Public Subnets (for NAT Gateway)
resource "aws_subnet" "public_subnet_1a" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-1a"
  }
}

resource "aws_subnet" "public_subnet_1b" {
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-1b"
  }
}

# Private Subnets (for Redshift)
resource "aws_subnet" "private_subnet_1a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet-1a"
  }
}

resource "aws_subnet" "private_subnet_1b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.4.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet-1b"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.redshift_vpc.id
  tags = {
    Name = "redshift-igw"
  }
}

# NAT Gateway (for private subnet outbound access)
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat_gw" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public_subnet_1a.id
  tags = {
    Name = "redshift-nat-gw"
  }
}

# Route Tables
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public_subnet_1a_association" {
  subnet_id      = aws_subnet.public_subnet_1a.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table_association" "public_subnet_1b_association" {
  subnet_id      = aws_subnet.public_subnet_1b.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

resource "aws_route_table_association" "private_subnet_1a_association" {
  subnet_id      = aws_subnet.private_subnet_1a.id
  route_table_id = aws_route_table.private_route_table.id
}

resource "aws_route_table_association" "private_subnet_1b_association" {
  subnet_id      = aws_subnet.private_subnet_1b.id
  route_table_id = aws_route_table.private_route_table.id
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to specific IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "fault_tolerant_cluster" {
  cluster_identifier = "fault-tolerant-redshift-cluster"
  database_name      = "devdb"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this in production!
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Distribute nodes across AZs
  availability_zone = "us-east-1a" # Primary AZ
  publicly_accessible = false

  # VPC Configuration
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
  subnet_ids             = [aws_subnet.private_subnet_1a.id, aws_subnet.private_subnet_1b.id]

  # Encryption and Backup
  encrypted              = true
  skip_final_snapshot    = true # Disable for production

  # Maintenance
  maintenance_window = "sun:03:00-sun:05:00"
  preferred_maintenance_window = "sun:06:00-sun:08:00"

  tags = {
    Name = "fault-tolerant-redshift-cluster"
  }
}

# Redshift Parameter Group (Optional: Customize settings)
resource "aws_redshift_parameter_group" "custom_param_group" {
  name   = "custom-redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "wlm_json_configuration"
    value = jsonencode({
      "query_concurrency": 5,
      "result_cache_mode": "auto"
    })
  }
}

resource "aws_redshift_cluster_parameter_group_association" "param_association" {
  cluster_parameter_group_name = aws_redshift_parameter_group.custom_param_group.name
  cluster_identifier           = aws_redshift_cluster.fault_tolerant_cluster.cluster_identifier
}

