}

# Create a subnet for the Redshift cluster in us-east-1
resource "aws_subnet" "redshift_subnet_us_east_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-us-east-1"
  }
}

# Create a subnet for the Redshift replica in us-east-2
resource "aws_subnet" "redshift_subnet_us_east_2" {
  provider      = aws.us_east_2
  vpc_id        = aws_vpc.redshift_vpc.id
  cidr_block    = "10.0.2.0/24"
  availability_zone = "us-east-2a"
  tags = {
    Name = "redshift-subnet-us-east-2"
  }
}

# Configure provider for us-east-2
provider "aws" "us_east_2" {
  region = "us-east-2"
}

# Create a security group for the Redshift cluster
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Create a Redshift cluster with replication
resource "aws_redshift_cluster" "primary_cluster" {
  cluster_identifier      = "primary-redshift-cluster"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change this to a secure password
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  publicly_accessible      = false
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  availability_zone       = "us-east-1a"
  subnet_ids              = [aws_subnet.redshift_subnet_us_east_1.id]

  cluster_parameter_group_name = aws_redshift_parameter_group.default.name
  skip_final_cluster_snapshot = true
}

# Create a Redshift parameter group
resource "aws_redshift_parameter_group" "default" {
  name   = "default-parameter-group"
  family = "redshift-1.0"
}

# Create a Redshift cluster replica in us-east-2
resource "aws_redshift_cluster" "replica_cluster" {
  provider = aws.us_east_2
  cluster_identifier      = "replica-redshift-cluster"
  database_name           = "dev"
  master_username         = "admin"
  replication_source_identifier = aws_redshift_cluster.primary_cluster.cluster_identifier
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible      = false
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  availability_zone       = "us-east-2a"
  subnet_ids              = [aws_subnet.redshift_subnet_us_east_2.id]

  skip_final_cluster_snapshot = true
}

# Output the endpoints of the clusters
output "primary_cluster_endpoint" {
  value = aws_redshift_cluster.primary_cluster.endpoint
}

output "replica_cluster_endpoint" {
  value = aws_redshift_cluster.replica_cluster.endpoint
}

