# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Redshift (basic permissions)
resource "aws_iam_policy" "redshift_policy" {
  name        = "redshift-cluster-policy"
  description = "Policy for Redshift cluster permissions"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:ListBucket",
          "s3:PutObject",
          "s3:DeleteObject"
        ],
        Resource = [
          "arn:aws:s3:::your-bucket-name/*",
          "arn:aws:s3:::your-bucket-name"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = ["arn:aws:logs:*:*:*"]
      }
    ]
  })
}

# Attach the policy to the IAM role
resource "aws_iam_role_policy_attachment" "redshift_attach_policy" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = aws_iam_policy.redshift_policy.arn
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "example-redshift-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change to a secure password or use AWS Secrets Manager
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  iam_roles = [
    aws_iam_role.redshift_role.arn
  ]

  skip_final_snapshot = true # Set to false to create snapshots on deletion

  # Optional: Configure logging
  logging_properties = {
    bucket_name = "your-logging-bucket-name" # Replace with your S3 bucket name
    s3_key_prefix = "redshift-logs"
    enable_log_exports = ["clientlog", "connectionlog", "commandlog", "useractivitylog"]
  }
}

