provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_cloudwatch_metric_alarm" "foobar" {
  alarm_name          = "foobar"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 120 # 2 minutes in seconds
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "Alarm when EC2 CPU utilization is >= 80% for 2 consecutive 2-minute periods"
  alarm_actions       = [] # No actions configured

  dimensions = {
    InstanceId = "i-1234567890abcdef0" # Replace with your EC2 instance ID or use a variable
  }

  insufficient_data_actions = [] # No actions if data is insufficient
  treat_missing_data       = "notBreaching" # No alarm state if data is missing
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a DynamoDB table for Contributor Insights
resource "aws_dynamodb_table" "contributor_insights_table" {
  name           = "ContributorInsightsTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "PK"
  range_key      = "SK"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  # Enable Contributor Insights on the table
  server_side_encryption {
    enabled     = true
    kms_key_arn = aws_kms_key.contributor_insights_key.arn
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Name        = "ContributorInsightsTable"
    Environment = "Production"
  }
}

# Create a KMS key for DynamoDB encryption
resource "aws_kms_key" "contributor_insights_key" {
  description             = "KMS key for DynamoDB Contributor Insights encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.kms_policy.json
}

# IAM policy for KMS key
data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }

  statement {
    sid    = "Allow access for Key Administrators"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:role/KeyAdministrator"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

# Enable Contributor Insights on the DynamoDB table
resource "aws_dynamodb_table_contributor_insights" "contributor_insights" {
  table_name = aws_dynamodb_table.contributor_insights_table.name

  # Customize Contributor Insights settings
  insights_configuration {
    insights_type = "QUERY_AND_SCAN"

    # Enable Contributor Insights metrics
    metrics_enabled = [
      "ConsumedReadCapacityUnits",
      "ConsumedWriteCapacityUnits",
      "ThrottledRequests",
      "SuccessfulRequestLatency",
      "UnsuccessfulRequestLatency",
      "ItemCount",
      "ConsumedWriteCapacityUnitsPerSecond",
      "ConsumedReadCapacityUnitsPerSecond"
    ]

    # Enable Contributor Insights for specific operations
    filter_expression_enabled = true
    projection_expression_enabled = true
    sort_key_enabled = true
  }
}

# Output the table ARN for reference
output "dynamodb_table_arn" {
  value = aws_dynamodb_table.contributor_insights_table.arn
}

# Get current AWS account ID
data "aws_caller_identity" "current" {}

