resource "aws_kinesis_stream" "dynamodb_stream" {
  name             = "dynamodb-stream-destination"
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours
}

resource "aws_dynamodb_table" "source_table" {
  name           = "source-dynamodb-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  stream_specification {
    stream_enabled = true
    stream_view_type = "NEW_AND_OLD_IMAGES"
  }

  lifecycle {
    ignore_changes = [stream_specification]
  }
}

resource "aws_kinesis_firehose_delivery_stream" "dynamodb_to_kinesis" {
  name        = "dynamodb-to-kinesis-firehose"
  destination = "extended_s3" # This is a placeholder; adjust based on actual destination

  kinesis_source_configuration {
    kinesis_stream_arn = aws_kinesis_stream.dynamodb_stream.arn
    role_arn           = aws_iam_role.firehose_role.arn
  }
}

