  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_dynamodb_table_iam" "stream_access" {
  table_arn = aws_dynamodb_table.source_table.arn
  name      = "dynamodb-stream-access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Action = [
          "dynamodb:DescribeStream",
          "dynamodb:GetRecords",
          "dynamodb:GetShardIterator",
          "dynamodb:ListStreams"
        ]
        Resource = aws_dynamodb_table.source_table.stream_arn
      }
    ]
  })
}

