provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dynamodb_table" "example_table" {
  name           = "example-dynamodb-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }
}

resource "aws_kinesis_stream" "dynamodb_stream" {
  name             = "dynamodb-stream-destination"
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours
}

resource "aws_dynamodb_table" "source_table" {
  name           = "source-dynamodb-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  stream_specification {
    stream_enabled = true
    stream_view_type = "NEW_AND_OLD_IMAGES"
  }

  lifecycle {
    ignore_changes = [stream_specification]
  }
}

