  region = "us-east-1" # Primary region for the global table
}

resource "aws_dynamodb_global_table" "global_dynamodb_table" {
  name           = "global-example-table"
  hash_key       = "id"
  range_key      = "sort_key"

  attribute {
    name = "id"
    type = "S"
  }

  attribute {
    name = "sort_key"
    type = "S"
  }

  billing_mode = "PAY_PER_REQUEST"

  global_table_name = "global-example-table"

  replica {
    region_name = "eu-west-1" # Secondary region for the replica
  }

  replica {
    region_name = "ap-southeast-1" # Tertiary region for the replica
  }
}

output "global_table_name" {
  value = aws_dynamodb_global_table.global_dynamodb_table.name
}

output "global_table_arn" {
  value = aws_dynamodb_global_table.global_dynamodb_table.arn
}

