# variables.tf
variable "aws_region" {
  description = "AWS region to deploy the resources"
  type        = string
  default     = "us-east-1"
}

variable "dax_cluster_name" {
  description = "Name of the DAX cluster"
  type        = string
  default     = "personalized-dax-cluster"
}

variable "dax_node_type" {
  description = "Node type for the DAX cluster"
  type        = string
  default     = "dax.r4.large"
}

variable "dax_parameter_group_name" {
  description = "Name of the DAX parameter group"
  type        = string
  default     = "personalized-dax-param-group"
}

variable "redis_parameter_group_name" {
  description = "Name of the Redis parameter group (DAX uses Redis parameters)"
  type        = string
  default     = "default.redis6.x"
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DAX cluster"
  type        = list(string)
  default     = []
}

variable "security_group_ids" {
  description = "List of security group IDs for the DAX cluster"
  type        = list(string)
  default     = []
}

# main.tf
provider "aws" {
  region = var.aws_region
}

resource "aws_dax_parameter_group" "personalized_dax_param_group" {
  name        = var.dax_parameter_group_name
  description = "Personalized DAX parameter group for custom Redis parameters"

  parameter {
    name  = "maxmemory-policy"
    value = "allkeys-lru" # Custom policy for memory management
  }

  parameter {
    name  = "hash-max-ziplist-entries"
    value = "5" # Customize hash entry limit
  }

  parameter {
    name  = "hash-max-ziplist-value"
    value = "64" # Customize hash value limit
  }

  parameter {
    name  = "list-max-ziplist-entries"
    value = "512" # Customize list entry limit
  }

  parameter {
    name  = "list-max-ziplist-value"
    value = "64" # Customize list value limit
  }

  parameter {
    name  = "set-max-intset-entries"
    value = "5" # Customize set integer entries limit
  }

  parameter {
    name  = "timeout"
    value = "300" # Customize client timeout
  }

  parameter {
    name  = "client-output-buffer-limit"
    value = "normal 0 0" # Customize client output buffer limits
  }

  parameter {
    name  = "repl-backlog-size"
    value = "1gb" # Customize replication backlog size
  }

  parameter {
    name  = "repl-timeout"
    value = "60" # Customize replication timeout
  }

  parameter {
    name  = "aof-rewrite-incremental-fsync"
    value = "yes" # Enable incremental AOF rewrite
  }

  parameter {
    name  = "aof-rewrite-perc"
    value = "100" # Customize AOF rewrite percentage
  }

  parameter {
    name  = "dax-cluster-discovery-enabled"
    value = "true" # Enable DAX cluster discovery
  }
}

resource "aws_dax_cluster" "personalized_dax_cluster" {
  cluster_name    = var.dax_cluster_name
  node_type       = var.dax_node_type
  parameter_group = aws_dax_parameter_group.personalized_dax_param_group.name
  subnet_ids      = var.subnet_ids
  security_group_ids = var.security_group_ids

  replication_group_id = aws_dax_replication_group.personalized_dax_replication_group.id
}

resource "aws_dax_replication_group" "personalized_dax_replication_group" {
  replication_group_id = "${var.dax_cluster_name}-replication-group"
  node_type            = var.dax_node_type
  parameter_group_name = aws_dax_parameter_group.personalized_dax_param_group.name

  multi_az_enabled = true

  tags = {
    Name = "${var.dax_cluster_name}-replication-group"
  }
}

# outputs.tf
output "dax_cluster_arn" {
  description = "ARN of the DAX cluster"
  value       = aws_dax_cluster.personalized_dax_cluster.arn
}

output "dax_cluster_endpoint" {
  description = "Endpoint of the DAX cluster"
  value       = aws_dax_cluster.personalized_dax_cluster.endpoint
}

output "dax_parameter_group_name" {
  description = "Name of the DAX parameter group"
  value       = aws_dax_parameter_group.personalized_dax_param_group.name
}

