}

resource "aws_sagemaker_domain" "example_domain" {
  domain_name             = "my-sagemaker-domain"
  auth_mode               = "IAM" # or "SSO" if using AWS SSO
  default_user_settings {
    execution_role        = aws_iam_role.sagemaker_execution_role.arn
    security_groups       = [aws_security_group.sagemaker_sg.id]
    kms_key_id            = aws_kms_key.sagemaker_key.arn
  }
  domain_settings {
    notebook_output_settings {
      s3_output_path = "s3://${aws_s3_bucket.sagemaker_notebooks.bucket}/notebook-output"
    }
    default_code_repository {
      s3_code_repository {
        bucket = aws_s3_bucket.sagemaker_notebooks.bucket
        bucket_prefix = "code-repositories"
      }
    }
    # Optional: Jupyter server app settings
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "serverless"
      }
    }
  }
}

# IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_execution_role_policy" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Security Group for SageMaker
resource "aws_security_group" "sagemaker_sg" {
  name        = "sagemaker-security-group"
  description = "Allow SageMaker traffic"
  vpc_id      = aws_vpc.example.id # Replace with your VPC ID or create one

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# KMS Key for SageMaker
resource "aws_kms_key" "sagemaker_key" {
  description             = "KMS key for SageMaker encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# S3 Bucket for notebook outputs and code repositories
