  # Optional: User profile settings
  user_settings {
    execution_role = var.execution_role_arn # Replace with your execution role ARN
    managed_endpoints {
      managed_endpoint_config_name = var.managed_endpoint_config_name # Replace with your endpoint config name
    }
  }
}

