variable "sagemaker_domain_id" {
  description = "The ID of the SageMaker domain where the user profile will be created."
  type        = string
}

variable "user_name" {
  description = "The name of the SageMaker user profile."
  type        = string
}

variable "execution_role_arn" {
  description = "The ARN of the execution role for the SageMaker user profile."
  type        = string
  default     = null
}

variable "managed_endpoint_config_name" {
  description = "The name of the managed endpoint config for the SageMaker user profile."
  type        = string
  default     = null
}

