extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_sagemaker_notebook_instance" "sagemaker_app" {
  name_prefix         = "jupyter-server-"
  notebook_instance_name = "sagemaker-jupyter-server"
  role_arn            = aws_iam_role.sagemaker_notebook_role.arn
  instance_type       = "ml.t3.medium" # Adjust based on your needs
  volume_size_in_gb   = 20              # Adjust based on your needs

  # Optional configurations
  accelerator_type    = "ml.eia1.medium" # Optional: For GPU support
  accelerator_count   = 0                # Set to 1 if using GPU
  lifecycle_config {
    default_cell_instance_count = 1
    default_cell_type           = "Standard"
  }

  # Security group configuration
  security_group_ids = [aws_security_group.sagemaker_notebook_sg.id]

  # Optional: Enable additional features
  enable_volume_encryption = true
  tags = {
    Name = "SageMaker-Jupyter-Server"
  }
}

# IAM Role for SageMaker Notebook
resource "aws_iam_role" "sagemaker_notebook_role" {
  name = "sagemaker-jupyter-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker Notebook execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_notebook_policy" {
  role       = aws_iam_role.sagemaker_notebook_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Security Group for SageMaker Notebook
resource "aws_security_group" "sagemaker_notebook_sg" {
  name        = "sagemaker-jupyter-sg"
  description = "Allow Jupyter traffic to SageMaker Notebook"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "SageMaker-Jupyter-SG"
  }
}

