  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for SageMaker Endpoint
resource "aws_iam_role" "sagemaker_endpoint_role" {
  name = "sagemaker-endpoint-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SageMaker Endpoint
resource "aws_iam_policy" "sagemaker_endpoint_policy" {
  name        = "sagemaker-endpoint-policy"
  description = "Policy for SageMaker Endpoint"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::your-model-bucket-name/*",
          "arn:aws:s3:::your-model-bucket-name"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = ["arn:aws:logs:*:*:*"]
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "sagemaker_endpoint_attachment" {
  role       = aws_iam_role.sagemaker_endpoint_role.name
  policy_arn = aws_iam_policy.sagemaker_endpoint_policy.arn
}

# SageMaker Model (replace with your model details)
resource "aws_sagemaker_model" "existing_model" {
  name               = "existing-model-name" # Replace with your existing model name
  execution_role_arn = aws_iam_role.sagemaker_endpoint_role.arn

  primary_container {
    image = "your-model-container-image" # Replace with your model container image URI
    model_data_url = "s3://your-model-bucket-name/path/to/model.tar.gz" # Replace with your model data URL
  }
}

# SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "endpoint_config" {
  name = "endpoint-config-name" # Replace with your desired endpoint configuration name

  production_variants {
    variant_name           = "AllTraffic" # Variant name
    model_name             = aws_sagemaker_model.existing_model.name # Reference to the model
    initial_instance_count = 1 # Initial instance count
    instance_type          = "ml.m5.large" # Instance type (adjust as needed)
