provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Public Subnet 1 (us-east-1a)
resource "aws_subnet" "public_subnet_1a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-1a"
  }
}

# Public Subnet 2 (us-east-1b)
resource "aws_subnet" "public_subnet_1b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-1b"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "public-rt"
  }
}

# Route Table Association for Subnet 1a
resource "aws_route_table_association" "public_rt_association_1a" {
  subnet_id      = aws_subnet.public_subnet_1a.id
  route_table_id = aws_route_table.public_rt.id
}

# Route Table Association for Subnet 1b
resource "aws_route_table_association" "public_rt_association_1b" {
  subnet_id      = aws_subnet.public_subnet_1b.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-security-group"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-sg"
  }
}

# Get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 Instance in Subnet 1a
resource "aws_instance" "ec2_instance_1a" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnet_1a.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = true
  tags = {
    Name = "ec2-instance-1a"
  }
}

# EBS Volume for EC2 Instance in Subnet 1a
resource "aws_ebs_volume" "ebs_volume_1a" {
  availability_zone = "us-east-1a"
  size              = 50
  type              = "gp2"
  tags = {
    Name = "ebs-volume-1a"
  }
}

# Attach EBS Volume to EC2 Instance in Subnet 1a
resource "aws_volume_attachment" "ebs_attach_1a" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_1a.id
  instance_id = aws_instance.ec2_instance_1a.id
}

# EC2 Instance in Subnet 1b
resource "aws_instance" "ec2_instance_1b" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public_subnet_1b.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = true
  tags = {
    Name = "ec2-instance-1b"
  }
}

# EBS Volume for EC2 Instance in Subnet 1b
resource "aws_ebs_volume" "ebs_volume_1b" {
  availability_zone = "us-east-1b"
  size              = 50
  type              = "gp2"
  tags = {
    Name = "ebs-volume-1b"
  }
}

# Attach EBS Volume to EC2 Instance in Subnet 1b
resource "aws_volume_attachment" "ebs_attach_1b" {
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.ebs_volume_1b.id
  instance_id = aws_instance.ec2_instance_1b.id
}

