  }
}

# Route Table Association for Public Subnet
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security Group for EC2 Fleet
resource "aws_security_group" "ec2_fleet_sg" {
  name        = "ec2-fleet-sg"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-fleet-sg"
  }
}

# Launch Template for EC2 Fleet
resource "aws_launch_template" "ec2_fleet_lt" {
  name_prefix   = "ec2-fleet-lt"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "your-key-pair" # Replace with your key pair name
  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.ec2_fleet_sg.id]
  }
  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              EOF
  )
  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
    }
  }
}

# Data Source for Latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 Fleet Configuration
resource "aws_ec2_fleet" "main" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_fleet_lt.id
      version            = "$Latest"
    }
    override_instance_types = ["t3.micro"]
  }

  target_capacity_specification {
    total_target_capacity = 9
    on_demand_target_capacity = 5
    spot_target_capacity    = 4
  }

  type = "maintain"

  tags = {
    Name = "ec2-fleet"
  }
}

# Output the public IPs of the EC2 instances
output "public_ips" {
  value = aws_ec2_fleet.main.on_demand_instances[*].public_ip
}

