  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "EFS-Mount-Demo-EFS-SG"
  }
}

# EFS Filesystem
resource "aws_efs_file_system" "efs" {
  creation_token = "efs-mount-demo"
  encrypted      = true
  tags = {
    Name = "EFS-Mount-Demo-Filesystem"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "mount_target" {
  count          = 2
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = element(aws_subnet.private[*].id, count.index)
  security_groups = [aws_security_group.efs_sg.id]
}

# EC2 Instances
resource "aws_instance" "ec2_instance" {
  count         = 2
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 (us-east-1)
  instance_type = "t3.micro"
  subnet_id     = element(aws_subnet.private[*].id, count.index)
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = false
  key_name      = "your-key-pair-name" # Replace with your key pair name
  iam_instance_profile = aws_iam_instance_profile.efs_profile.name
  user_data     = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo yum install -y amazon-efs-utils
              sudo mkdir -p /mnt/efs
              sudo mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 ${aws_efs_file_system.efs.dns_name}:/ /mnt/efs
              echo "${aws_efs_file_system.efs.dns_name}:/ /mnt/efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 0 0" | sudo tee -a /etc/fstab
              sudo chmod -R 777 /mnt/efs
              EOF
  tags = {
    Name = "EFS-Mount-Demo-EC2-${count.index + 1}"
  }
}

# IAM Role for EFS Access
resource "aws_iam_role" "efs_role" {
  name = "EFS-Mount-Demo-Role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for EFS Access
resource "aws_iam_role_policy_attachment" "efs_policy" {
  role       = aws_iam_role.efs_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonElasticFileSystemClientReadWriteAccess"
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "efs_profile" {
  name = "EFS-Mount-Demo-Profile"
  role = aws_iam_role.efs_role.name
}

