provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "EFS-Mount-Demo-VPC"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "EFS-Mount-Demo-GW"
  }
}

# Public Subnet (for NAT Gateway)
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "EFS-Mount-Demo-Public-Subnet"
  }
}

# Private Subnets (for EC2 instances)
resource "aws_subnet" "private" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.${count.index + 2}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  tags = {
    Name = "EFS-Mount-Demo-Private-Subnet-${count.index + 1}"
  }
}

# Route Table for Public Subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "EFS-Mount-Demo-Public-Route-Table"
  }
}

# Route Table Association for Public Subnet
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat" {
  vpc = true
  tags = {
    Name = "EFS-Mount-Demo-NAT-EIP"
  }
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id
  tags = {
    Name = "EFS-Mount-Demo-NAT-Gateway"
  }
}

# Route Table for Private Subnets
resource "aws_route_table" "private" {
  count  = 2
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
  tags = {
    Name = "EFS-Mount-Demo-Private-Route-Table-${count.index + 1}"
  }
}

# Route Table Association for Private Subnets
resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id     = element(aws_subnet.private[*].id, count.index)
  route_table_id = element(aws_route_table.private[*].id, count.index)
}

# Security Group for EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "EFS-Mount-Demo-EC2-SG"
  description = "Allow SSH and EFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "EFS-Mount-Demo-EC2-SG"
  }
}

# Security Group for EFS
resource "aws_security_group" "efs_sg" {
  name        = "EFS-Mount-Demo-EFS-SG"
  description = "Allow NFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "EFS-Mount-Demo-EFS-SG"
  }
}

# EFS Filesystem
resource "aws_efs_file_system" "efs" {
  creation_token = "efs-mount-demo"
  encrypted      = true
  tags = {
    Name = "EFS-Mount-Demo-Filesystem"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "mount_target" {
  count          = 2
  file_system_id = aws_efs_file_system.efs.id
  subnet_id      = element(aws_subnet.private[*].id, count.index)
  security_groups = [aws_security_group.efs_sg.id]
}

# EC2 Instances
resource "aws_instance" "ec2_instance" {
  count         = 2
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 (us-east-1)
  instance_type = "t3.micro"
  subnet_id     = element(aws_subnet.private[*].id, count.index)
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = false
  key_name      = "your-key-pair-name" # Replace with your key pair name
  iam_instance_profile = aws_iam_instance_profile.efs_profile.name
  user_data     = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo yum install -y amazon-efs-utils
              sudo mkdir -p /mnt/efs
              sudo mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 ${aws_efs_file_system.efs.dns_name}:/ /mnt/efs
              echo "${aws_efs_file_system.efs.dns_name}:/ /mnt/efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 0 0" | sudo tee -a /etc/fstab
              sudo chmod -R 777 /mnt/efs
              EOF
  tags = {
    Name = "EFS-Mount-Demo-EC2-${count.index + 1}"
  }
}

# IAM Role for EFS Access
resource "aws_iam_role" "efs_role" {
  name = "EFS-Mount-Demo-Role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for EFS Access
resource "aws_iam_role_policy_attachment" "efs_policy" {
  role       = aws_iam_role.efs_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonElasticFileSystemClientReadWriteAccess"
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "efs_profile" {
  name = "EFS-Mount-Demo-Profile"
  role = aws_iam_role.efs_role.name
}
```

