# Database Optimization Strategy: Implementing Read Replicas and Caching Layer
# This Terraform configuration deploys a read replica for an Aurora PostgreSQL database
# and a Redis cache layer to minimize direct database queries.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create VPC for database infrastructure
resource "aws_vpc" "db_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "db-vpc"
  }
}

# Create database subnet group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  tags = {
    Name = "aurora-subnet-group"
  }
}

# Create private subnets
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet-2"
  }
}

# Create Aurora PostgreSQL cluster with read replica
resource "aws_rds_cluster" "aurora_postgres" {
  cluster_identifier      = "aurora-postgres-cluster"
  engine                  = "aurora-postgresql"
  engine_mode             = "provisioned"
  database_name           = "app_database"
  master_username         = "admin"
  master_password         = random_password.db_password.result
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.db_sg.id]
}

resource "aws_rds_cluster_instance" "primary" {
  cluster_identifier = aws_rds_cluster.aurora_postgres.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.aurora_postgres.engine
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
}

resource "aws_rds_cluster_instance" "read_replica" {
  cluster_identifier = aws_rds_cluster.aurora_postgres.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.aurora_postgres.engine
  db_subnet_group_name = aws_db_subnet_group.db_subnet_group.name
  promotion_tier     = 1
}

# Create Redis cache (ElastiCache)
resource "aws_elasticache_cluster" "redis_cache" {
  cluster_id           = "app-cache-cluster"
  engine               = "redis"
  node_type            = "cache.r5.large"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379
  subnet_group_name    = aws_elasticache_subnet_group.cache_subnet_group.name
  security_group_ids   = [aws_security_group.cache_sg.id]
}

resource "aws_elasticache_subnet_group" "cache_subnet_group" {
  name       = "redis-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
}

# Security groups
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow database connections"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "cache_sg" {
  name        = "cache-security-group"
  description = "Allow cache connections"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random password generator
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Outputs
output "primary_db_endpoint" {
  value = aws_rds_cluster_instance.primary.endpoint
}

output "read_replica_endpoint" {
  value = aws_rds_cluster_instance.read_replica.endpoint
