    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random password generator
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Outputs
output "primary_db_endpoint" {
  value = aws_rds_cluster_instance.primary.endpoint
}

output "read_replica_endpoint" {
  value = aws_rds_cluster_instance.read_replica.endpoint
}

output "redis_cache_endpoint" {
  value = aws_elasticache_cluster.redis_cache.cache_nodes[0].address
}

output "db_password" {
  value     = random_password.db_password.result
  sensitive = true
}
```

**Key Optimization Strategies Implemented:**
1. **Read Replicas**: Aurora PostgreSQL cluster with a read replica to handle read-heavy workloads
2. **Caching Layer**: Redis ElastiCache for storing frequently accessed data
3. **Proper Networking**: Private subnets for database resources
4. **Security**: Appropriate security groups to restrict access

**Implementation Strategy:**
1. Route read queries to the read replica
2. Implement application-level caching using Redis
3. Use database connection pooling
4. Implement query optimization (indexes, explain plans)
5. Consider query caching at the application level for repeated identical queries

