provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dynamodb_table" "dax_cluster" {
  name           = "dax-cluster"
  billing_mode    = "PAY_PER_REQUEST"
  hash_key       = "PK"

  attribute {
    name = "PK"
    type = "S"
  }

  serverless_specification {
    auto_scaling_read {
      min_capacity = 1
      max_capacity = 10
    }
    auto_scaling_write {
      min_capacity = 1
      max_capacity = 10
    }
  }

  point_in_time_recovery {
    enabled = true
  }
}

resource "aws_dax_cluster" "main" {
  cluster_name    = "dax-cluster"
  node_type       = "dax.r4.large"
  replication_factor = 1
  parameter_group_name = aws_dax_parameter_group.example.name
  subnet_group_name = aws_dax_subnet_group.example.name
  description     = "DAX Cluster for DynamoDB acceleration"
}

resource "aws_dax_parameter_group" "example" {
  name = "dax-param-group"
  family {
    name = "dynamodb-default"
    engine_version = "5.3"
    parameters = {
      "cache-item-maximum-ttl-seconds" = "3600"
      "cache-item-minimum-ttl-seconds" = "60"
    }
  }
}

resource "aws_dax_subnet_group" "example" {
  name = "dax-subnet-group"

  subnet_ids = [
    aws_subnet.dax_subnet_1.id,
    aws_subnet.dax_subnet_2.id,
    aws_subnet.dax_subnet_3.id,
  ]
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "dax_subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "dax_subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_subnet" "dax_subnet_3" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow DAX traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_dax_subnet_group_association" "example" {
  subnet_group_name = aws_dax_subnet_group.example.name
  subnet_id         = aws_subnet.dax_subnet_1.id
}

resource "aws_dax_subnet_group_association" "example_2" {
  subnet_group_name = aws_dax_subnet_group.example.name
  subnet_id         = aws_subnet.dax_subnet_2.id
}

resource "aws_dax_subnet_group_association" "example_3" {
  subnet_group_name = aws_dax_subnet_group.example.name
  subnet_id         = aws_subnet.dax_subnet_3.id
}
