    revision = 1
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT" # Change to "TLS_PLAINTEXT", "TLS_PLAINTEXT_WITH_AUTHENTICATION", or "TLS_PLAINTEXT_WITH_AUTHENTICATION_AND_MUTUAL_AUTH"
      in_transit_encryption_type = "TLS"
    }
  }

  tags = {
    Environment = "production"
    Terraform   = "true"
  }
}

resource "aws_security_group" "msk_sg" {
