terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create an S3 bucket for MSK cluster logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM policy for MSK cluster to write logs to S3
resource "aws_iam_policy" "msk_s3_logging_policy" {
  name        = "msk-s3-logging-policy"
  description = "Policy for MSK cluster to write logs to S3"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.msk_logs_bucket.arn,
          "${aws_s3_bucket.msk_logs_bucket.arn}/*"
        ]
      }
    ]
  })
}

# IAM role for MSK cluster
resource "aws_iam_role" "msk_cluster_role" {
  name = "msk-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to the MSK role
resource "aws_iam_role_policy_attachment" "msk_s3_logging_attachment" {
  role       = aws_iam_role.msk_cluster_role.name
  policy_arn = aws_iam_policy.msk_s3_logging_policy.arn
}

# MSK cluster configuration
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-example"
  kafka_version          = "3.4.0" # Check for latest supported version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.2xlarge"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnets
    security_groups = [aws_security_group.msk_cluster_sg.id]
  }

  configuration_info {
    arn      = "arn:aws:kafka:us-east-1:123456789012:cluster/kafka-configuration/ExampleConfig-1234567890123456" # Replace with your config ARN
    name     = "ExampleConfig"
    revision = 1
  }

  logging_info {
    broker_logs {
      s3 {
        bucket_md5 = md5(aws_s3_bucket.msk_logs_bucket.arn)
        enabled    = true
        prefix     = "broker-logs/"
      }
    }
    consumer_logs {
      s3 {
        bucket_md5 = md5(aws_s3_bucket.msk_logs_bucket.arn)
        enabled    = true
        prefix     = "consumer-logs/"
      }
    }
    producer_logs {
      s3 {
        bucket_md5 = md5(aws_s3_bucket.msk_logs_bucket.arn)
        enabled    = true
        prefix     = "producer-logs/"
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker_optional_protocol = "TLS"
      in_cluster = true
    }
  }

  tags = {
    Environment = "dev"
  }
}

# Security group for MSK cluster
resource "aws_security_group" "msk_cluster_sg" {
  name        = "msk-cluster-sg"
  description = "Allow inbound traffic to MSK cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

