provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_msk_cluster" "kafka_cluster" {
  cluster_name           = "kafka-cluster-with-prometheus"
  kafka_version          = "3.6.1" # Latest stable version as of Terraform 1.0+
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type        = "kafka.m5.large"
    client_subnets       = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
    security_groups      = [aws_security_group.msk_sg.id] # Reference to security group below
    imds_support         = "ENABLED"
    storage_info {
      ebs_storage_info {
        volume_size = 100
        volume_type = "gp3"
      }
    }
  }

  configuration_info {
    arn      = "arn:aws:kafka:${var.region}:${data.aws_caller_identity.current.account_id}:configuration/kafka-metrics-prometheus-0-10-0" # Default MSK metrics config
    name     = "kafka-metrics-prometheus-0-10-0"
    revision = 1
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT" # Change to "TLS_PLAINTEXT" for production
      in_cluster     = true
    }
  }

  tags = {
    Environment = "dev"
    Terraform   = "true"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-prometheus-exporter-sg"
  description = "Security group for MSK cluster with Prometheus exporters"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict in production
  }

  ingress {
    from_port   = 9404 # JMX Exporter port
    to_port     = 9404
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict in production
  }

  ingress {
    from_port   = 9100 # Node Exporter port
    to_port     = 9100
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-prometheus-exporter-sg"
  }
}

resource "aws_iam_role" "msk_role" {
  name = "msk-prometheus-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_cloudwatch" {
  role       = aws_iam_role.msk_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonCloudWatchFullAccess"
}

resource "aws_iam_role_policy_attachment" "msk_ssm" {
  role       = aws_iam_role.msk_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_role_policy" "msk_custom" {
  name = "msk-prometheus-custom-policy"
  role = aws_iam_role.msk_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeSubnets"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/kafka/${aws_msk_cluster.kafka_cluster.cluster_name}"
  retention_in_days = 7
}

