resource "aws_msk_serverless_cluster" "example" {
  cluster_name           = "example-msk-serverless-cluster"
  configuration_name     = "dedicated.mskc.1" # Default MSK Serverless configuration
  hyperparameter_tuning = "auto"             # Enable auto-tuning for optimal performance

  kafka_version = "3.4.0" # Latest stable Kafka version for MSK Serverless

