extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_msk_serverless_cluster" "msk_serverless" {
  cluster_name           = "msk-serverless-cluster"
  configuration_name     = "dedicated-msk-2_12" # MSK Dedicated configuration for Apache Kafka 2.12
  kafka_version          = "3.6.1" # Latest stable version as of writing

  # Serverless configuration
  serverless {
    replication_factor = 3 # Three broker nodes
    min_tps            = 1 # Minimum throughput per partition (adjust based on needs)
    max_tps            = 2 # Maximum throughput per partition (adjust based on needs)
  }

  # Encryption settings
  encryption_info {
    encryption_in_transit {
      client_broker_encryption_in_transit = "TLS_PLAINTEXT" # Change to "TLS_PLAINTEXT" or "TLS_PLAINTEXT" + "TLS_PLAINTEXT" if needed
    }
    encryption_at_rest_kms_key_arn = aws_kms_key.ms_kms_key.arn
  }

  # IAM authentication
  iam {
    authentication_enabled = true
  }

  # Network configuration
  network_configuration {
    security_groups = [aws_security_group.ms_security_group.id]
    subnets         = aws_subnet.ms_subnet[*].id
  }

  # Broker configuration
  broker_configuration {
    broker_id = 1 # Broker ID (automatically assigned in serverless)
  }
}

resource "aws_kms_key" "ms_kms_key" {
  description = "KMS key for MSK Serverless cluster encryption"
  policy      = data.aws_iam_policy_document.ms_kms_policy.json
}

data "aws_iam_policy_document" "ms_kms_policy" {
  statement {
    actions   = ["kms:*"]
    resources = ["*"]

    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
  }
}

data "aws_caller_identity" "current" {}

resource "aws_security_group" "ms_security_group" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless cluster"
  vpc_id      = aws_vpc.ms_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to your VPC CIDR in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "ms_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "ms_subnet" {
  count                   = 2 # At least 2 subnets required for MSK
  vpc_id                  = aws_vpc.ms_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true
}

data "aws_availability_zones" "available" {
  state = "available"
}

