      client_broker_encryption_in_transit = "TLS_RSA"
    }
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
  }
  hyperparameter_tuning {
    client_automatic_broker_failover = "ENABLED"
  }
  tags = {
    Environment = "Production"
    Terraform   = "true"
  }
}

resource "aws_kms_key" "msk_encryption" {
  description             = "KMS key for MSK Serverless cluster encryption"
  deletion_window_in_days = 30
  enable_key_rotation    = true
  policy                  = data.aws_iam_policy_document.msk_kms_policy.json
}

