extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket for MSK logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-${random_id.bucket_suffix.hex}"
  force_destroy = true

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Create a Kinesis Data Firehose delivery stream
resource "aws_kinesis_firehose_delivery_stream" "msk_logs_stream" {
  name        = "msk-cluster-logs-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3_role.arn
    bucket_arn = aws_s3_bucket.ms3_logs_bucket.arn
    prefix     = "msk-logs/"

    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.ms3_logs_group.name
      log_stream_name = "firehose-logs"
    }
  }
}

# Create IAM role for Firehose to write to S3
resource "aws_iam_role" "firehose_s3_role" {
  name = "firehose-s3-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_policy" {
  role       = aws_iam_role.firehose_s3_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# Create CloudWatch Log Group for MSK logs
resource "aws_cloudwatch_log_group" "msk_logs_group" {
  name              = "/msk/cluster-logs"
  retention_in_days = 7
}

# Create IAM policy for MSK to send logs to CloudWatch
resource "aws_iam_policy" "msk_cloudwatch_policy" {
  name        = "msk-cloudwatch-logs-policy"
  description = "Policy for MSK to send logs to CloudWatch"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = [
          "arn:aws:logs:${var.region}:${data.aws_caller_identity.current.account_id}:log-group:/msk/*"
        ]
      }
    ]
  })
}

# Create IAM role for MSK cluster
resource "aws_iam_role" "msk_role" {
  name = "msk-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.ms.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_cloudwatch_policy_attachment" {
  role       = aws_iam_role.msk_role.name
  policy_arn = aws_iam_policy.msk_cloudwatch_policy.arn
}

# Create MSK cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-example"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    client_subnet = aws_subnet.msk_subnet.id
    instance_type = "kafka.t3.2xlarge"
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker_encryption_in_transit = "tls"
    }
    encryption_in_rest {
      data_volume_encryption_enabled = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs_group.name
      }
      s3 {
        enabled = true
        bucket = aws_s3_bucket.ms3_logs_bucket.bucket
        prefix = "broker-logs/"
      }
      firehose {
        enabled = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
      }
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  tags = {
    Environment = "dev"
  }
}

# Create VPC and subnet for MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "msk_subnet" {
  vpc_id     = aws_vpc.msk_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id
}

resource "aws_route_table" "msk_route_table" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.msk_igw.id
  }
}

resource "aws_route_table_association" "msk_route_association" {
  subnet_id      = aws_subnet.msk_subnet.id
  route_table_id = aws_route_table.msk_route_table.id
}

# Create security group for MSK cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-cluster-sg"
  description = "Allow inbound traffic to MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Get current AWS account ID
data "aws_caller_identity" "current" {}

