resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster-${random_id.cluster_suffix.hex}"
  kafka_version          = "3.6.1" # Latest stable version as of writing
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.2xlarge"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnets
    security_groups = [aws_security_group.msk_cluster_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  tags = {
    Environment = "dev"
  }
}

resource "random_id" "cluster_suffix" {
  byte_length = 4
}

