  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM role for Aurora PostgreSQL cluster
resource "aws_iam_role" "aurora_postgres_role" {
  name = "aurora-postgres-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Aurora PostgreSQL cluster
resource "aws_iam_policy" "aurora_postgres_policy" {
  name        = "aurora-postgres-policy"
  description = "Policy for Aurora PostgreSQL cluster"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach the policy to the IAM role
resource "aws_iam_role_policy_attachment" "aurora_postgres_attachment" {
  role       = aws_iam_role.aurora_postgres_role.name
  policy_arn = aws_iam_policy.aurora_postgres_policy.arn
}

# Security group for Aurora PostgreSQL cluster
resource "aws_security_group" "aurora_postgres_sg" {
  name        = "aurora-postgres-sg"
  description = "Security group for Aurora PostgreSQL cluster"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your allowed CIDR block
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Aurora PostgreSQL cluster
resource "aws_db_cluster" "aurora_postgres" {
  cluster_identifier      = "aurora-postgres-cluster"
  engine                  = "aurora-postgresql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = "admin" # Change to a secure username
  master_password         = "your-secure-password" # Change to a secure password
  port                    = 5432
  skip_final_snapshot     = true # Set to false to create a final snapshot before deletion

  iam_database_authentication_enabled = true
  enable_http_endpoint                 = true

  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"

  storage_encrypted = true

  vpc_security_group_ids = [aws_security_group.aurora_postgres_sg.id]

  db_cluster_parameter_group_name = aws_db_parameter_group.aurora_postgres.name
  db_subnet_group_name           = aws_db_subnet_group.aurora_postgres.name

  tags = {
    Name = "Aurora PostgreSQL Cluster"
  }
}

# Aurora PostgreSQL parameter group
resource "aws_db_parameter_group" "aurora_postgres" {
  name        = "aurora-postgres-parameter-group"
  family      = "aurora-postgresql13"
  description = "Parameter group for Aurora PostgreSQL cluster"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "max_connections"
    value = "200"
  }
}

# Aurora PostgreSQL subnet group
resource "aws_db_subnet_group" "aurora_postgres" {
  name       = "aurora-postgres-subnet-group"
  subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-xxxxxxxxxxxxxxxxx"] # Replace with your subnet IDs

  tags = {
    Name = "Aurora PostgreSQL Subnet Group"
  }
}

# Aurora PostgreSQL instance
resource "aws_db_instance" "aurora_postgres_writer" {
  identifier             = "aurora-postgres-writer"
  cluster_identifier     = aws_db_cluster.aurora_postgres.id
  engine                 = aws_db_cluster.aurora_postgres.engine
  engine_version         = aws_db_cluster.aurora_postgres.engine_version
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.aurora_postgres.name
  vpc_security_group_ids = [aws_security_group.aurora_postgres_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true

  tags = {
    Name = "Aurora PostgreSQL Writer Instance"
  }
}

# Output the cluster endpoint
output "cluster_endpoint" {
  value = aws_db_cluster.aurora_postgres.endpoint
}

