terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 4.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
}

variable "region" {
  description = "The GCP region where resources will be created"
  type        = string
  default     = "us-central1"
}

variable "zones" {
  description = "The GCP zones where the cluster will be deployed"
  type        = list(string)
  default     = ["us-central1-a", "us-central1-b", "us-central1-c"]
}

resource "google_sql_database_instance" "mysql_cluster" {
  name             = "mysql-cluster-${random_id.suffix.hex}"
  database_version = "MYSQL_8_0"
  region           = var.region

  settings {
    tier = "db-custom-1-3840" # 1 vCPU, 3840 GB RAM (adjust as needed for 100GB storage)

    backup_configuration {
      enabled    = true
      start_time = "02:00"
    }

    ip_configuration {
      authorized_networks {
        name  = "private-ip"
        value = "0.0.0.0/0" # Adjust based on your network requirements
      }
      ipv4_enabled    = true
      private_network = google_compute_network.vpc.name
      require_ssl     = true
    }

    availability_config {
      backup_reservation_period = "240h" # 10 days
      failover_target           = false
      location_preference {
        zone = element(var.zones, count.index)
      }
      backup_type = "LOG_BACKUP_AND_FILE_BACKUP"
    }
  }

  depends_on = [google_compute_network.vpc]
}

resource "google_compute_network" "vpc" {
  name                    = "mysql-cluster-vpc"
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "subnets" {
  count                   = length(var.zones)
  name                    = "mysql-cluster-subnet-${element(var.zones, count.index)}"
  region                  = var.region
  network                 = google_compute_network.vpc.name
  ip_cidr_range           = "10.10.${count.index}.0/24"
  private_ip_google_access = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

