terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for MySQL cluster
resource "aws_vpc" "mysql_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "mysql-cluster-vpc"
  }
}

# Subnets for availability zones
resource "aws_subnet" "mysql_subnet_a" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "mysql-subnet-a"
  }
}

resource "aws_subnet" "mysql_subnet_b" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "mysql-subnet-b"
  }
}

resource "aws_subnet" "mysql_subnet_c" {
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "mysql-subnet-c"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "mysql_igw" {
  vpc_id = aws_vpc.mysql_vpc.id
  tags = {
    Name = "mysql-igw"
  }
}

# Route Table
resource "aws_route_table" "mysql_route_table" {
  vpc_id = aws_vpc.mysql_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.mysql_igw.id
  }
  tags = {
    Name = "mysql-route-table"
  }
}

# Route Table Associations
resource "aws_route_table_association" "mysql_route_association_a" {
  subnet_id      = aws_subnet.mysql_subnet_a.id
  route_table_id = aws_route_table.mysql_route_table.id
}

resource "aws_route_table_association" "mysql_route_association_b" {
  subnet_id      = aws_subnet.mysql_subnet_b.id
  route_table_id = aws_route_table.mysql_route_table.id
}

resource "aws_route_table_association" "mysql_route_association_c" {
  subnet_id      = aws_subnet.mysql_subnet_c.id
  route_table_id = aws_route_table.mysql_route_table.id
}

# Security Group for MySQL
resource "aws_security_group" "mysql_sg" {
  name        = "mysql-security-group"
  description = "Allow MySQL traffic"
  vpc_id      = aws_vpc.mysql_vpc.id

  ingress {
    description = "MySQL access"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-sg"
  }
}

# RDS Proxy for MySQL cluster
resource "aws_db_proxy" "mysql_proxy" {
  name                     = "mysql-proxy"
  engine_family            = "MYSQL"
  require_tls              = true
  role_arn                 = aws_iam_role.db_proxy_role.arn
  vpc_subnet_ids           = [aws_subnet.mysql_subnet_a.id, aws_subnet.mysql_subnet_b.id, aws_subnet.mysql_subnet_c.id]
  security_group_ids       = [aws_security_group.mysql_sg.id]
