# AWS RDS PostgreSQL Instance
provider "aws" {
  region = "us-east-1"
}

resource "aws_db_instance" "postgresql" {
  identifier             = "postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = "admin"
  password               = "your-secure-password" # Change this to a secure password or use AWS Secrets Manager
  db_name                = "postgresdb"
  skip_final_snapshot    = true
  publicly_accessible    = false
  multi_az               = false
  backup_retention_period = 7
  tags = {
    Name = "PostgreSQL Instance"
  }
}

# GCP Cloud SQL PostgreSQL Instance
