  region = "us-east-1" # Primary region for initial setup
  alias  = "primary"
}

provider "aws" {
  region = "us-east-2"
  alias  = "us-east-2"
}

provider "aws" {
  region = "us-west-2"
  alias  = "us-west-2"
}

resource "aws_dynamodb_table" "global_table" {
  name           = "GlobalAppTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  global_table_settings {
    replication_group {
      region_name = "us-east-2"
      read_capacity = 5
      write_capacity = 5
    }

    replication_group {
      region_name = "us-west-2"
      read_capacity = 5
      write_capacity = 5
    }
  }

  tags = {
    Name        = "GlobalAppTable"
    Environment = "Production"
  }
}

resource "aws_dynamodb_table_replication" "global_replication" {
  count = 2

  table_arn = aws_dynamodb_table.global_table.arn

  dynamic "replication_group" {
    for_each = count.index == 0 ? ["us-east-2"] : ["us-west-2"]
    content {
      region_name = replication_group.value
    }
  }
}

