terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_dax_cluster" "main" {
  cluster_name      = "my-dax-cluster"
  description       = "DAX cluster for caching DynamoDB"
  node_type         = "dax.r4.large" # Adjust node type based on your needs
  replication_group_id = aws_dax_replication_group.main.id
  iam_role_arn      = aws_iam_role.dax_role.arn
  parameter_group_name = aws_dax_parameter_group.main.name
  security_group_ids = [aws_security_group.dax_sg.id]
  tags = {
    Name = "DAXCluster"
  }
}

resource "aws_dax_replication_group" "main" {
  replication_group_id = "dax-replication-group"
  node_type           = aws_dax_cluster.main.node_type
  description         = "DAX replication group for high availability"
  multi_az            = true
  parameter_group_name = aws_dax_parameter_group.main.name
  tags = {
    Name = "DAXReplicationGroup"
  }
}

resource "aws_dax_parameter_group" "main" {
  name      = "dax-param-group"
  family    = "dax1.0"
  parameters = {
    "cluster_enabled" = "true"
    "max_connections" = "10000"
    "idle_client_timeout" = "60000"
    "maintenance_window" = "sun:05:00-sun:09:00"
  }
}

resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Security group for DAX cluster"
  vpc_id      = aws_vpc.main.id # Ensure you have a VPC defined or replace with your VPC ID

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust based on your security requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "DAXSecurityGroup"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "DAXVPC"
  }
}

resource "aws_iam_role" "dax_role" {
  name = "dax-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dax_attachment" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

