    enable_accept_encoding_brotli = false
    enable_accept_encoding_gzip   = false
    cookies_config {
      cookie_behavior = "none"
    }
    headers_config {
      header_behavior = "none"
    }
    query_strings_config {
      query_string_behavior = "none"
    }
  }
}

resource "aws_cloudfront_distribution" "example" {
  origin {
    domain_name = "example.com" # Replace with your origin domain
    origin_id   = "S3-Example-Origin"

    s3_origin_config {
      bucket_name = "your-bucket-name" # Replace with your S3 bucket name
      origin_access_identity = aws_cloudfront_origin_access_identity.example.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-Example-Origin"
    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }
    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = var.ttl_days * 86400 # Convert days to seconds
    max_ttl                = var.ttl_days * 86400 # Convert days to seconds
    cache_policy_id        = aws_cloudfront_cache_policy.custom_ttl_policy.id
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_cloudfront_origin_access_identity" "example" {
  comment = "OAI for S3 bucket"
}
```

---
**Note:**
- This example uses **AWS CloudFront** to manage TTL for cached content.
- Replace `example.com` and `your-bucket-name` with your actual domain and S3 bucket.
- Adjust `ttl_days` in the `variable` section to set your desired expiration time.
- For **GCP (Cloud CDN + Cloud Storage)**, let me know if you'd prefer a similar setup there.

