  vpc_id = aws_vpc.vpc_1.id
  tags = {
    Name = "IGW-1"
  }
}

# Route Table for VPC 1
resource "aws_route_table" "rt_1" {
  vpc_id = aws_vpc.vpc_1.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw_1.id
  }
  tags = {
    Name = "RouteTable-1"
  }
}

# Route Table Association for Subnet 1a
resource "aws_route_table_association" "rta_1a" {
  subnet_id      = aws_subnet.subnet_1a.id
  route_table_id = aws_route_table.rt_1.id
}

# Route Table Association for Subnet 1b
resource "aws_route_table_association" "rta_1b" {
  subnet_id      = aws_subnet.subnet_1b.id
  route_table_id = aws_route_table.rt_1.id
}

# VPC 2
resource "aws_vpc" "vpc_2" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "VPC-2"
  }
}

# Subnet 2a for VPC 2
resource "aws_subnet" "subnet_2a" {
  vpc_id            = aws_vpc.vpc_2.id
  cidr_block        = "10.1.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "Subnet-2a"
  }
}

# Subnet 2b for VPC 2
