  vpc_id = aws_vpc.vpc_2.id
  tags = {
    Name = "IGW-2"
  }
}

# Route Table for VPC 2
resource "aws_route_table" "rt_2" {
  vpc_id = aws_vpc.vpc_2.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw_2.id
  }
  tags = {
    Name = "RouteTable-2"
  }
}

# Route Table Association for Subnet 2a
