  subnet_id      = aws_subnet.subnet_2b.id
  route_table_id = aws_route_table.rt_2.id
}

# VPC Peering Connection
resource "aws_vpc_peering_connection" "vpc_peer" {
  vpc_id      = aws_vpc.vpc_1.id
  peer_vpc_id = aws_vpc.vpc_2.id
  auto_accept = true
  tags = {
    Name = "VPC-Peering-Connection"
  }
}

# Route for VPC 1 to VPC 2
resource "aws_route" "route_vpc1_to_vpc2" {
  route_table_id            = aws_route_table.rt_1.id
  destination_cidr_block    = aws_vpc.vpc_2.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peer.id
  depends_on = [aws_vpc_peering_connection.vpc_peer]
}

# Route for VPC 2 to VPC 1
resource "aws_route" "route_vpc2_to_vpc1" {
  route_table_id            = aws_route_table.rt_2.id
  destination_cidr_block    = aws_vpc.vpc_1.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peer.id
  depends_on = [aws_vpc_peering_connection.vpc_peer]
}

