provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Create a custom route table
resource "aws_route_table" "custom" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0" # Replace with your designated CIDR range if different
    gateway_id = aws_internet_gateway.gw.id
    description = "Route to Internet Gateway"
  }
  tags = {
    Name = "custom-route-table"
  }
}

# Associate the custom route table with the VPC (or specific subnets)
resource "aws_route_table_association" "a" {
  subnet_id      = aws_vpc.main.id # Replace with a specific subnet ID if needed
  route_table_id = aws_route_table.custom.id
}

