terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Custom Neptune Parameter Group
resource "aws_neptune_parameter_group" "custom_neptune_pg" {
  name        = "custom-neptune-pg"
  description = "Custom parameter group for Amazon Neptune"
  family      = "neptune-1.0" # Update to the appropriate family version for your Neptune version

  parameter {
    name  = "neptune_cluster_logging"
    value = "INFO"
  }

  parameter {
    name  = "gds_max_concurrent_jobs"
    value = "10"
  }

  parameter {
    name  = "gds_max_job_execution_time"
    value = "3600"
  }

  # Add more custom parameters as needed
}

# Amazon Neptune Cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier      = "my-neptune-cluster"
  engine                  = "neptune"
  engine_version          = "1.0" # Update to the appropriate version
  instance_type           = "db.r6g.large" # Adjust based on your requirements
  preferred_maintenance_window = "sun:05:00-sun:09:00"
  apply_immediately       = true
  copy_tags_to_cluster    = true

  # Use the custom parameter group
  parameter_group_name = aws_neptune_parameter_group.custom_neptune_pg.name

  # Enable serverless scaling (optional)
  serverless_scaling_configuration {
    min_capacity = 0.5
    max_capacity = 2.0
  }

  # Enable public access (adjust based on your security requirements)
  enable_http_endpoint = true

  # Enable backup (optional)
  backup_retention_period = 7

  # Enable enhanced monitoring (optional)
  enable_cloudwatch_logs_exports = ["error", "general", "performance"]

  # Enable deletion protection (optional)
  deletion_protection = true
}

# Neptune Cluster Subnet Group
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name        = "neptune-subnet-group"
  subnet_ids  = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
  description = "Subnet group for Neptune cluster"
}

# Associate the subnet group with the Neptune cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  # Reuse the existing cluster resource block
  # The subnet_group_name is added here
  subnet_group_name = aws_neptune_subnet_group.neptune_subnet_group.name
}

# Security Group for Neptune Cluster (optional)
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Security group for Neptune cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 8182 # Neptune port
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust based on your security requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Associate the security group with the Neptune cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  # Reuse the existing cluster resource block
  # The security_group_names is added here
  security_group_names = [aws_security_group.neptune_sg.name]
}

