    value = "1"
  }
}

# Create a Neptune cluster with restricted access to specific subnets
resource "aws_neptune_cluster" "restricted_neptune_cluster" {
  cluster_name           = "restricted-neptune-cluster"
  engine                 = "neptune"
  engine_version         = "1.0"
  instance_type          = "db.r5.large"
  preferred_maintenance_window = "sun:05:00-sun:09:00"
  apply_immediately      = true
  copy_tags_to_cluster   = true
  parameter_group_name   = aws_neptune_parameter_group.custom_neptune_pg.name
  skip_final_snapshot    = true # Set to false if you want final snapshots

  vpc_security_group_ids = [aws_security_group.neptune_sg.id]

  # Restrict cluster access to specific subnets via security group rules
}

# Create a security group for the Neptune cluster
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-restricted-sg"
  description = "Security group for Neptune cluster with restricted access"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  # Allow inbound traffic from specific subnets on Neptune port (8182)
  dynamic "ingress" {
    for_each = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
    content {
      from_port   = 8182
      to_port     = 8182
      protocol    = "tcp"
      cidr_blocks = ["${ingress.value}/32"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

