terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create two encrypted AWS Chime Voice Connectors
resource "aws_chime_voice_connector" "connector_1" {
  name        = "chime-voice-connector-1"
  description = "First encrypted voice connector for Chime"
  media_encryption_settings {
    media_encryption_key {
      key_type = "KMS"
      key_arn  = aws_kms_key.chime_key.arn
    }
  }
}

resource "aws_chime_voice_connector" "connector_2" {
  name        = "chime-voice-connector-2"
  description = "Second encrypted voice connector for Chime"
  media_encryption_settings {
    media_encryption_key {
      key_type = "KMS"
      key_arn  = aws_kms_key.chime_key.arn
    }
  }
}

# Create a KMS key for encryption (required for Chime Voice Connectors)
resource "aws_kms_key" "chime_key" {
  description             = "KMS key for encrypting Chime Voice Connectors"
  deletion_window_in_days = 30
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.chime_key_policy.json
}

data "aws_iam_policy_document" "chime_key_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}

# Define a Chime Voice Connector Group containing both connectors
resource "aws_chime_voice_connector_group" "connector_group" {
  name        = "chime-voice-connector-group"
  description = "Group containing both encrypted voice connectors"

  connector {
    connector_arn = aws_chime_voice_connector.connector_1.arn
  }

  connector {
    connector_arn = aws_chime_voice_connector.connector_2.arn
  }
}

