  region = "us-east-1" # Change to your preferred region
}

resource "aws_chime_voice_connector" "primary" {
  name = "Primary-Voice-Connector"
  description = "Primary AWS Chime Voice Connector"
  media_attachment {
    media_attachment_type = "SIP"
    sip_credentials {
      authentication_uri = "sip:auth.example.com" # Replace with your auth URI
      password = var.sip_password # Replace with your SIP password (use variables or secrets manager)
      username = var.sip_username # Replace with your SIP username
    }
    sip_uri = "sip:example.com" # Replace with your SIP URI
  }
  encryption_configuration {
    encryption_type = "SRTP"
    certificate_arn = aws_acm_certificate.chime_cert.arn # Replace with your ACM certificate ARN or use a placeholder
  }
}

resource "aws_chime_voice_connector" "secondary" {
  name = "Secondary-Voice-Connector"
  description = "Secondary AWS Chime Voice Connector"
  media_attachment {
    media_attachment_type = "SIP"
    sip_credentials {
      authentication_uri = "sip:auth.example.com" # Replace with your auth URI
      password = var.sip_password # Replace with your SIP password
      username = var.sip_username # Replace with your SIP username
    }
    sip_uri = "sip:example.com" # Replace with your SIP URI
  }
  encryption_configuration {
    encryption_type = "SRTP"
    certificate_arn = aws_acm_certificate.chime_cert.arn # Replace with your ACM certificate ARN or use a placeholder
  }
}

resource "aws_acm_certificate" "chime_cert" {
  domain_name       = "your-domain.com" # Replace with your domain
