provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create AWS Chime Voice Connector
resource "aws_chime_voice_connector" "example" {
  name = "example-voice-connector"
  description = "Voice Connector for AWS Chime"
  media_usage_metrics_enabled = true
  sip_media_port = 5060
  sip_signaling_port = 5061
  sip_transport = "UDP"
  sip_authentication = "DIGEST"
  sip_authentication_credentials {
    username = "sip-username" # Replace with your SIP username
    password = "sip-password" # Replace with your SIP password
  }
  sip_authentication_credentials_rotation {
    enabled = true
    rotation_interval = "30d"
  }
  sip_authentication_credentials_rotation_schedule {
    day_of_week = "MONDAY"
    time_of_day = "03:00:00"
  }
  sip_authentication_credentials_rotation_schedule {
    day_of_week = "THURSDAY"
    time_of_day = "03:00:00"
  }
  sip_authentication_credentials_rotation_schedule {
    day_of_week = "SUNDAY"
    time_of_day = "03:00:00"
  }
  sip_authentication_credentials_rotation_schedule {
    day_of_week = "WEDNESDAY"
    time_of_day = "03:00:00"
  }
}

# Create AWS Chime Voice Connector Logging Configuration
resource "aws_chime_voice_connector_logging_configuration" "example" {
  voice_connector_id = aws_chime_voice_connector.example.id
  sip_logging_enabled = false
  media_metrics_logging_enabled = true
  log_delivery {
    http_endpoint {
      url = "https://your-log-endpoint.example.com" # Replace with your HTTP endpoint URL
    }
  }
}

