provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an SNS topic for notifications
resource "aws_sns_topic" "chime_notifications" {
  name = "chime-voice-connector-notifications"
}

# Create an IAM policy for Chime Voice Connector
resource "aws_iam_policy" "chime_voice_connector_policy" {
  name        = "chime-voice-connector-policy"
  description = "Policy for Chime Voice Connector"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ]
        Resource = [
          "arn:aws:s3:::aws-chime-voice-connector-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.chime_notifications.arn
      }
    ]
  })
}

# Create an IAM role for Chime Voice Connector
resource "aws_iam_role" "chime_voice_connector_role" {
  name = "chime-voice-connector-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "chime_voice_connector_attachment" {
  role       = aws_iam_role.chime_voice_connector_role.name
  policy_arn = aws_iam_policy.chime_voice_connector_policy.arn
}

# Create the Chime Voice Connector
resource "aws_chime_voice_connector" "example" {
  name        = "example-voice-connector"
  description = "Voice Connector for Chime with 5-hour recording retention"
  media_storage_s3_bucket_arn = "arn:aws:s3:::aws-chime-media-storage-${var.aws_region}" # Default bucket for media storage
  media_archive_s3_bucket_arn = "arn:aws:s3:::aws-chime-media-archive-${var.aws_region}" # Default bucket for media archive

  recording_configuration {
    recording_enabled = true
    recording_retention_in_hours = 5
    recording_notification_sns_topic_arn = aws_sns_topic.chime_notifications.arn
    recording_kinesis_stream_arn = "" # Empty to disable Kinesis streaming
  }

  tags = {
    Name = "example-voice-connector"
  }
}

# Output the SNS topic ARN for notifications
output "sns_topic_arn" {
  value = aws_sns_topic.chime_notifications.arn
}

# Output the Chime Voice Connector ID
output "voice_connector_id" {
  value = aws_chime_voice_connector.example.id
}

