provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Chime Voice Connector
resource "aws_iam_role" "chime_voice_connector_role" {
  name = "chime-voice-connector-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis access
resource "aws_iam_policy" "kinesis_access_policy" {
  name        = "chime-voice-connector-kinesis-policy"
  description = "Policy for Chime Voice Connector to write to Kinesis"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords",
          "kinesis:DescribeStream"
        ],
        Resource = [
          "arn:aws:kinesis:${var.aws_region}:${data.aws_caller_identity.current.account_id}:stream/*"
        ]
      }
    ]
  })
}

# Attach policy to the IAM role
resource "aws_iam_role_policy_attachment" "kinesis_access_attachment" {
  role       = aws_iam_role.chime_voice_connector_role.name
  policy_arn = aws_iam_policy.kinesis_access_policy.arn
}

# Kinesis Data Stream for Chime media
resource "aws_kinesis_stream" "chime_media_stream" {
  name             = "chime-voice-connector-media-stream"
  shard_count      = 1 # Adjust based on expected throughput
  retention_period = 24 # Hours (default: 24)
}

# Chime Voice Connector
resource "aws_chime_voice_connector" "media_stream_connector" {
  name = "chime-media-to-kinesis-connector"

  media_ingestion_configuration {
    destination {
      kinesis_stream_arn = aws_kinesis_stream.chime_media_stream.arn
    }
  }

  media_ingestion_role_arn = aws_iam_role.chime_voice_connector_role.arn
}

# Outputs
output "chime_voice_connector_id" {
  value = aws_chime_voice_connector.media_stream_connector.id
}

output "kinesis_stream_name" {
  value = aws_kinesis_stream.chime_media_stream.name
}

output "kinesis_stream_arn" {
  value = aws_kinesis_stream.chime_media_stream.arn
}

# Get current AWS account ID
data "aws_caller_identity" "current" {}

