terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "redshift-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "redshift_igw" {
  vpc_id = aws_vpc.redshift_vpc.id
  tags = {
    Name = "redshift-igw"
  }
}

# Create Route Table
resource "aws_route_table" "redshift_route_table" {
  vpc_id = aws_vpc.redshift_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.redshift_igw.id
  }
  tags = {
    Name = "redshift-route-table"
  }
}

# Create Subnets
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Associate Subnets with Route Table
resource "aws_route_table_association" "redshift_subnet_1_association" {
  subnet_id      = aws_subnet.redshift_subnet_1.id
  route_table_id = aws_route_table.redshift_route_table.id
}

resource "aws_route_table_association" "redshift_subnet_2_association" {
  subnet_id      = aws_subnet.redshift_subnet_2.id
  route_table_id = aws_route_table.redshift_route_table.id
}

# Create Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Create Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "redshift-cluster"
  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change this to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible     = false
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  tags = {
    Name = "redshift-cluster"
  }
}

# Create Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow Redshift access"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your specific IP ranges in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Create Redshift Endpoint Access
resource "aws_redshift_endpoint_access" "redshift_endpoint_access" {
  cluster_identifier = aws_redshift_cluster.redshift_cluster.id
  endpoint_access {
    name        = "endpoint-access"
    subnet_ids  = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
    security_group_ids = [aws_security_group.redshift_sg.id]
  }
}

