provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC for the Redshift cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "redshift-vpc"
  }
}

# Create two private subnets for Redshift
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b" # Change to your preferred AZ
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Create a Redshift cluster with a public subnet group (using private subnets)
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
}

# Create an IAM role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Redshift policy to the role
resource "aws_iam_role_policy_attachment" "redshift_amazon_redshift_default_role" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRedshiftFullAccess"
}

# Create the Redshift cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier      = "example-cluster"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node" # Change to "multi-node" for multi-node cluster
  skip_final_snapshot     = true # Set to false to create snapshots
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  iam_roles               = [aws_iam_role.redshift_role.arn]
  publicly_accessible      = false # Ensure the cluster is not publicly accessible
  encrypted               = true # Enable encryption
  enable_logging          = true
  log_data                = ["STDOUT", "STDERR"]
  log_export_configuration {
    logfile_format = "JSON"
    s3_bucket      = aws_s3_bucket.redshift_logs.bucket
    s3_prefix      = "redshift-logs"
  }
}

# Create a security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24", "10.0.2.0/24"] # Allow traffic from the subnets
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Create an S3 bucket for Redshift logs
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "redshift-cluster-logs-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Output the Redshift cluster endpoint
output "redshift_cluster_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

