terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Redshift to send notifications
resource "aws_iam_role" "redshift_notification_role" {
  name = "redshift-notification-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SNS notification
resource "aws_iam_policy" "redshift_notification_policy" {
  name        = "redshift-notification-policy"
  description = "Policy for Redshift to publish to SNS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["sns:Publish"]
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "redshift_notification_attachment" {
  role       = aws_iam_role.redshift_notification_role.name
  policy_arn = aws_iam_policy.redshift_notification_policy.arn
}

# SNS Topic for notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-cluster-notifications"
}

# Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier      = "my-redshift-cluster"
  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible     = false
  skip_final_snapshot     = true # Set to false to create snapshots

  # Enable logging
  logging {
    enable_log_exports = ["STL_LOAD_ERRORS", "STL_QUERY_METRICS"]
    s3_logging {
      bucket_name = aws_s3_bucket.redshift_logs.bucket
      encryption = "AES256"
    }
  }

  # Enable event notifications
  notification_configuration {
    topic_arn     = aws_sns_topic.redshift_notifications.arn
    notification_email_address = "admin@example.com" # Change to your email
    notification_sns_topic_arn  = aws_sns_topic.redshift_notifications.arn
  }

  # VPC Configuration (if needed)
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

# S3 Bucket for Redshift logs
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "my-redshift-cluster-logs-bucket"
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# SNS Subscription for notifications
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.redshift_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com" # Change to your email
}

