  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "YourSecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible     = false
  skip_final_snapshot     = true # Set to false to create snapshots

  # Enable logging
  logging {
    enable_log_exports = ["STL_LOAD_ERRORS", "STL_QUERY_METRICS"]
    s3_logging {
      bucket_name = aws_s3_bucket.redshift_logs.bucket
      encryption = "AES256"
    }
  }

  # Enable event notifications
  notification_configuration {
    topic_arn     = aws_sns_topic.redshift_notifications.arn
    notification_email_address = "admin@example.com" # Change to your email
    notification_sns_topic_arn  = aws_sns_topic.redshift_notifications.arn
  }

  # VPC Configuration (if needed)
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

# S3 Bucket for Redshift logs
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "my-redshift-cluster-logs-bucket"
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# SNS Subscription for notifications
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.redshift_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com" # Change to your email
}
