terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for Redshift to publish to SNS
resource "aws_iam_role" "redshift_sns_role" {
  name = "redshift-sns-publish-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SNS publishing
resource "aws_iam_policy" "redshift_sns_policy" {
  name        = "redshift-sns-publish-policy"
  description = "Allows Redshift to publish to SNS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["sns:Publish"]
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "redshift_sns_attachment" {
  role       = aws_iam_role.redshift_sns_role.name
  policy_arn = aws_iam_policy.redshift_sns_policy.arn
}

# SNS Topic for Redshift notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-cluster-notifications"
}

# Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "my-redshift-cluster"
  database_name      = "devdb"
  master_username    = "admin"
  master_password    = "YourSecurePassword123!" # Change this to a secure password or use AWS Secrets Manager
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Enable enhanced VPC routing
  publicly_accessible = false
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # IAM role for Redshift to publish to SNS
  iam_roles = [aws_iam_role.redshift_sns_role.arn]

  # Enable logging
  logging_properties {
    bucket_arn    = aws_s3_bucket.redshift_logs.arn
    s3_key_prefix = "redshift-logs/"
    enable       = true
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.main.id # Ensure you have a VPC defined or replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your specific IP ranges in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# S3 Bucket for Redshift logs (required for event notifications)
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "my-redshift-cluster-logs-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Redshift Event Subscription for SNS
resource "aws_redshift_event_subscription" "sns_subscription" {
  name            = "redshift-sns-subscription"
  event_categories = ["CLUSTER_STATUS_CHANGE", "COPY_STATUS_CHANGE", "LOAD_STATUS_CHANGE", "QUERY_STATUS_CHANGE"]
  sns_topic_arn   = aws_sns_topic.redshift_notifications.arn
  iam_role_arn    = aws_iam_role.redshift_sns_role.arn
  notification_category = "CLUSTER_STATUS_CHANGE"
}

# Outputs
output "redshift_cluster_endpoint" {
  value = aws_redshift_cluster.main.endpoint
}

output "sns_topic_arn" {
  value = aws_sns_topic.redshift_notifications.arn
}

