terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a sample Redshift parameter group
resource "aws_redshift_parameter_group" "sample_param_group" {
  name        = "sample-redshift-param-group"
  description = "Sample parameter group for Redshift cluster"

  parameter {
    name  = "wlm_json_configuration"
    value = '{"query_concurrency": 5}'
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }
}

# Create a Redshift cluster with the parameter group
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier      = "example-redshift-cluster"
  database_name           = "devdb"
  master_username         = "admin"
  master_password         = "SecurePassword123!" # Change to a secure password
  node_type               = "dc2.large"
  cluster_type            = "single-node"
  publicly_accessible     = false
  skip_final_snapshot     = true
  parameter_group_name    = aws_redshift_parameter_group.sample_param_group.name
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id] # Requires VPC setup
  cluster_subnet_group_name = aws_redshift_subnet_group.example_subnet_group.name # Requires subnet group setup
}

# Create a security group for Redshift (simplified example)
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow Redshift traffic"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create a Redshift subnet group (simplified example)
resource "aws_redshift_subnet_group" "example_subnet_group" {
  name       = "example-redshift-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
}

# Create an SNS topic for Redshift event notifications
resource "aws_sns_topic" "redshift_events_topic" {
  name = "redshift-parameter-group-events"
}

# Create a Redshift event subscription to route parameter-group-related events
resource "aws_redshift_event_subscription" "param_group_events_subscription" {
  name            = "redshift-param-group-events-subscription"
  event_categories = ["parameter-group-modify"]
  sns_topic_arn   = aws_sns_topic.redshift_events_topic.arn
  source_ids      = [aws_redshift_cluster.example_cluster.id]
  enabled         = true
}
```

