  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket for storing images
resource "aws_s3_bucket" "website_images" {
  bucket = "my-website-images-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  acl    = "private" # Set to "public-read" if you want public access (not recommended for security)

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Website Images Bucket"
    Environment = "Production"
  }
}

# Generate a random suffix to ensure bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Optional: Block public access (recommended for security)
resource "aws_s3_bucket_public_access_block" "block_public_access" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Optional: Configure bucket lifecycle rules (e.g., transition old images to S3 Glacier)
resource "aws_s3_bucket_lifecycle_configuration" "image_lifecycle" {
  bucket = aws_s3_bucket.website_images.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    expiration {
      days = 365 # Delete after 1 year (optional)
