extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create the primary S3 bucket
resource "aws_s3_bucket" "primary_bucket" {
  bucket = "primary-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true # WARNING: Deletes all objects and versions

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# Generate a random suffix for bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create the secondary S3 bucket for weekly inventory
resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "inventory-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true # WARNING: Deletes all objects and versions

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

# IAM Role for S3 Inventory Delivery
resource "aws_iam_role" "s3_inventory_role" {
  name = "s3-inventory-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 Inventory Delivery
resource "aws_iam_policy" "s3_inventory_policy" {
  name        = "s3-inventory-policy"
  description = "Policy for S3 Inventory Delivery"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.primary_bucket.arn,
          "${aws_s3_bucket.primary_bucket.arn}/*",
          aws_s3_bucket.inventory_bucket.arn,
          "${aws_s3_bucket.inventory_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "s3_inventory_attachment" {
  role       = aws_iam_role.s3_inventory_role.name
  policy_arn = aws_iam_policy.s3_inventory_policy.arn
}

# Enable S3 Inventory on the primary bucket
resource "aws_s3_bucket_inventory_configuration" "primary_bucket_inventory" {
  bucket = aws_s3_bucket.primary_bucket.id
  name   = "weekly-inventory"

  destination {
    s3_bucket {
      account_id = data.aws_caller_identity.current.account_id
      bucket     = aws_s3_bucket.inventory_bucket.id
      prefix     = "inventory-reports/"
      format     = "CSV"
    }
  }

  included_object_versions = "All"
  filter {
    prefix = "" # Include all objects
  }

  schedule {
    frequency = "Weekly"
  }

  idempotency_token = timestamp()
}

# Get current AWS account ID
data "aws_caller_identity" "current" {}

