terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket
resource "aws_s3_bucket" "payment_config_bucket" {
  bucket = "payment-config-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name with random suffix
  tags = {
    Name        = "PaymentConfigBucket"
    Environment = "Production"
  }
}

# Enable versioning on the S3 bucket
resource "aws_s3_bucket_versioning" "payment_config_versioning" {
  bucket = aws_s3_bucket.payment_config_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable server-side encryption by default
resource "aws_s3_bucket_server_side_encryption_configuration" "payment_config_encryption" {
  bucket = aws_s3_bucket.payment_config_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access to the bucket
resource "aws_s3_bucket_public_access_block" "payment_config_public_access" {
  bucket = aws_s3_bucket.payment_config_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Generate a random suffix for the bucket name to ensure uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Sample payment configuration file (example JSON)
resource "aws_s3_object" "payment_config_file" {
  bucket = aws_s3_bucket.payment_config_bucket.id
  key    = "payment_config.json"
  source = "${path.module}/payment_config.json" # Ensure this file exists locally
  etag   = filemd5("${path.module}/payment_config.json")

  # Example content if file doesn't exist locally
  content = <<EOF
{
  "payment_processor": "stripe",
  "api_key": "sk_test_1234567890",
  "webhook_secret": "whsec_1234567890",
  "default_currency": "USD",
  "retention_policy": {
    "days": 90,
    "max_files": 1000
  }
}
EOF
}

# Optional: Bucket policy to restrict access (adjust as needed)
resource "aws_s3_bucket_policy" "payment_config_policy" {
  bucket = aws_s3_bucket.payment_config_bucket.id
  policy = data.aws_iam_policy_document.payment_config_policy.json
}

data "aws_iam_policy_document" "payment_config_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.payment_config_bucket.arn}/*"]

    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::123456789012:role/payment-service-role"] # Replace with actual role ARN
    }
  }
}

