  policy = data.aws_iam_policy_document.bucket_payment_settings.json
}

data "aws_iam_policy_document" "bucket_payment_settings" {
  statement {
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.example_bucket.arn}/*"]

    principals {
      type        = "AWS"
      identifiers = ["${aws_s3_bucket.example_bucket.owner_id}"]
    }

    condition {
      test     = "Bool"
      variable = "s3:x-amz-request-payer"
      values   = ["BucketOwner"]
    }
  }
}

output "bucket_name" {
  value = aws_s3_bucket.example_bucket.bucket
}

output "bucket_arn" {
