provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create the main S3 bucket
resource "aws_s3_bucket" "main_bucket" {
  bucket = "my-main-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true # Set to false if you want to preserve objects on deletion

  tags = {
    Name        = "Main S3 Bucket"
    Environment = "Production"
  }
}

# Create the logging bucket
resource "aws_s3_bucket" "logging_bucket" {
  bucket = "my-logging-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true

  tags = {
    Name        = "Logging S3 Bucket"
    Environment = "Production"
  }
}

# Generate a random suffix to ensure bucket names are unique
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable versioning on the main bucket
resource "aws_s3_bucket_versioning" "main_bucket_versioning" {
  bucket = aws_s3_bucket.main_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure server access logging for the main bucket
resource "aws_s3_bucket_logging" "main_bucket_logging" {
  bucket = aws_s3_bucket.main_bucket.id

  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "logs/" # Prefix for log files
}

# Block all public access to the main bucket
resource "aws_s3_bucket_public_access_block" "main_bucket_public_access" {
  bucket = aws_s3_bucket.main_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Block all public access to the logging bucket
resource "aws_s3_bucket_public_access_block" "logging_bucket_public_access" {
  bucket = aws_s3_bucket.logging_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Optional: Configure bucket lifecycle rules for the logging bucket
resource "aws_s3_bucket_lifecycle_configuration" "logging_bucket_lifecycle" {
  bucket = aws_s3_bucket.logging_bucket.id

  rule {
    id     = "log-cleanup"
    status = "Enabled"

    expiration {
      days = 30 # Delete logs older than 30 days
    }

    filter {
      prefix = "logs/"
    }
  }
}

