terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    github = {
      source  = "integrations/github"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "github" {
  owner = "your-org-name" # Replace with your GitHub organization name
  token = var.github_token  # Store this in a variable or secrets manager
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild_autograding_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_policy" "codebuild_policy" {
  name        = "codebuild_autograding_policy"
  description = "Policy for CodeBuild autograding system"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.codebuild_bucket.arn,
          "${aws_s3_bucket.codebuild_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "codecommit:GitPull"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# S3 Bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_bucket" {
  bucket = "codebuild-autograding-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# GitHub App for CodeBuild Webhooks
resource "github_app" "codebuild_webhook" {
  name    = "CodeBuild-Autograding"
  owner   = provider.github.owner
  repo    = "your-course-repo" # Replace with your course repo name
  homepage_url = "https://${aws_codebuild_project.autograding_project.build_arn}"
  url      = "https://github.com/${provider.github.owner}/${github_app.codebuild_webhook.name}"
  webhook_configuration {
    url      = aws_codebuild_project.autograding_project.build_arn
    content_type = "json"
    inactive = false
    events = [
      "push"
    ]
  }
}

# CodeBuild Project
resource "aws_codebuild_project" "autograding_project" {
  name          = "autograding-project"
  description   = "Autograding system for computer science course"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-course-repo" # Replace with your course repo name
    }

    environment_variable {
      name  = "GITHUB_BRANCH"
      value = "main" # Default branch
    }

    environment_variable {
      name  = "GITHUB_OWNER"
      value = provider.github.owner
    }
  }

  source {
    type = "GITHUB"
    location = "https://github.com/${provider.github.owner}/${github_app.codebuild_webhook.name}"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install pytest pytest-cov
        pre_build:
          commands:
            - echo "Checking out repository..."
            - git clone https://${GITHUB_TOKEN}@github.com/${GITHUB_OWNER}/${GITHUB_REPO}.git /src
            - cd /src
            - git checkout ${GITHUB_BRANCH}
        build:
          commands:
            - echo "Running tests..."
            - python -m pytest --cov=./ tests/ -v
            - echo "Generating coverage report..."
            - python -m pytest --cov-report=xml:coverage.xml tests/
            - echo "Uploading results..."
            - aws s3 cp coverage.xml s3://${S3_BUCKET}/results/
      artifacts:
        files: '**/*'
      cache:
        paths:
          - '/root/.cache/pip'
      post_build:
        commands:
          - echo "Build completed on `date`"
    EOT
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }
}

# S3 Bucket for storing results
resource "aws_s3_bucket" "results_bucket" {
  bucket = "autograding-results-${random_id.results_suffix.hex}"
}

resource "random_id" "results_suffix" {
  byte_length = 8
}

# Lambda function to process results (optional)
resource "aws_lambda_function" "process_results" {
  function_name = "process-autograding-results"
  runtime       = "python3.8"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.lambda_role.arn
  filename      = "lambda_function.zip"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.results_bucket.bucket
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_autograding_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "lambda_s3_access_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
