```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    github = {
      source  = "integrations/github"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "github" {
  owner = "your_github_org"  # Replace with your GitHub organization
  token = var.github_token    # Store this securely using AWS Secrets Manager or environment variables
}

# S3 Bucket for storing student submissions and build artifacts
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = "autograding-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM Role for CodeBuild to access S3 and other services
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_ssm_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMReadOnlyAccess"
}

resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "autograding-codebuild-custom-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ],
        Resource = "*"
      }
    ]
  })
}

# CodeBuild Project for executing student submissions
resource "aws_codebuild_project" "autograding_project" {
  name          = "autograding-project"
  description   = "Autograding system for computer science course"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_bucket.bucket
    packaging = "ZIP"
    path      = "build-artifacts"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your_github_repo"  # Replace with the student submission repo
    }

    environment_variable {
      name  = "GITHUB_BRANCH"
      value = "main"  # Or any branch where students submit
    }

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograding_bucket.bucket
    }

    environment_variable {
      name  = "ENVIRONMENT_IMAGE"
      value = "your_base_image_uri"  # Predefined environment image (e.g., Docker image with dependencies)
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your_github_org/student-submissions"  # Replace with the actual repo
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  tags = {
    Name = "AutogradingSystem"
  }
}

# Lambda Function to trigger CodeBuild on GitHub push events
resource "aws_lambda_function" "github_webhook_handler" {
  function_name = "autograding-webhook-handler"
  runtime       = "python3.9"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.lambda_role.arn
  s3_bucket     = aws_s3_bucket.lambda_bucket.name
  s3_key        = aws_s3_object.lambda_function.key

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding_project.name
      GITHUB_WEBHOOK_SECRET = var.github_webhook_secret  # Store securely
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "autograding-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_codebuild_access" {
  name = "autograding-lambda-codebuild-access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "codebuild:StartBuild"
        ],
        Resource = aws_codebuild_project.autograding_project.arn
      }
    ]
  })
}

resource "aws_lambda_permission" "allow_github_webhook" {
  statement_id  = "AllowExecutionFromGitHub"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.github_webhook_handler.function_name
  principal     = "services.github.com"
  source_arn    = "arn:aws:events:us-east-1:123456789012:rule/github-webhook-trigger"  # Replace with your actual rule ARN
}

# S3 Bucket for Lambda deployment package
resource "aws_s3_bucket" "lambda_bucket" {
  bucket = "autograding-lambda-bucket-${random_id.bucket_suffix.hex}"
}

resource "aws_s3_object" "lambda_function" {
  bucket = aws_s3_bucket.lambda_bucket.id
  key    = "autograding-webhook-handler.zip"
  source = "path/to/your/lambda/deployment/package.zip"  # Replace with actual path
}

# CloudWatch Event Rule to trigger Lambda on GitHub webhook
resource "aws_cloudwatch_event_rule" "github_webhook_trigger" {
  name                = "github-webhook-trigger"
  description         = "Trigger Lambda on GitHub webhook events"
  schedule_expression = "rate(1 minute)"  # Adjust as needed or use event pattern
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.github_webhook_trigger.name
  target_id = "trigger-lambda"
  arn       = aws_lambda_function.github_webhook_handler.arn
}

# SNS Topic for notifications (e.g., grading results)
resource "aws_sns_topic" "grading_notifications" {
  name = "autograding-grading-notifications"
}

resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.grading_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com"  # Replace with admin email
}

# CodeBuild Build Spec (stored in S3)
resource "aws_s3_object" "build_spec" {
  bucket = aws_s3_bucket.autograding_bucket.id
  key    = "buildspec.yml"
  content = <<-EOT
version: 0.2
phases:
  install:
    runtime-versions:
      python: 3.9
    commands:
      - echo "Installing dependencies..."
      - pip install pytest coverage
  pre_build:
    commands:
      - echo "Downloading student code from GitHub..."
      - git clone https://${GITHUB_TOKEN}@github.com/${GITHUB_REPO}.git /code
      - cd /code && git checkout ${GITHUB_BRANCH}
  build:
    commands:
      - echo "Building and testing student code..."
      - docker run --rm -v ${PWD}:/code -w /code ${ENVIRONMENT_IMAGE} bash -c "python -m pytest tests/ --cov=src/ -o json=report.json"
      - echo "Generating grading report..."
      - python3 generate_grade.py report.json > grade_report.json
  post_build:
    commands:
      - echo "Uploading results to S3..."
      - aws s3 cp grade_report.json s3://${S3_BUCKET}/grades/${GITHUB_REPO}_${GITHUB_BRANCH}_${CODEBUILD_BUILD_ID}.json
      - aws sns publish --topic-arn ${GRADING_NOTIFICATIONS_TOPIC} --message "Grading completed for ${GITHUB_REPO} branch ${GITHUB_BRANCH}"
EOT
}

# Lambda Function to process grading results (optional)
resource "aws_lambda_function" "grade_processor" {
  function_name = "autograding-grade-processor"
  runtime       = "python3.9"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.lambda_role.arn
  s3_bucket     = aws_s3_bucket.lambda_bucket.name
  s3_key        = aws_s3_object.grade_processor.key

  environment {
    variables = {
      S3_BUCKET = aws_s3_bucket.autograding_bucket.bucket
      DYNAMODB_TABLE = aws_dynamodb_table.grades_table.name
    }
  }
}

resource "aws_s3_object" "grade_processor" {
  bucket = aws_s3_bucket.lambda_bucket.id
  key    = "grade-processor.zip"
  source = "path/to/grade-processor/lambda/package.zip"  # Replace with actual path
}

# DynamoDB Table to store grades
resource "aws_dynamodb_table" "grades_table" {
  name           = "autograding-grades"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "student_id"

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "course_id"
    type = "S"
  }

  global_secondary_index {
    name            = "course-index"
    hash_key        = "course_id"
    projection_type = "ALL"
  }
}

# IAM Policy for Lambda to access DynamoDB
resource "aws_iam_role_policy" "lambda_dynamodb_access" {
  name = "autograding-lambda-dynamodb-access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:UpdateItem"
        ],
        Resource = aws_dynamodb_table.grades_table.arn
      }
    ]
  })
}

# API Gateway to expose grading status (optional)
resource "aws_api_gateway_rest_api" "autograding_api" {
  name        = "autograding-api"
  description = "API for querying grading status"
}

resource "aws_api_gateway_resource" "grades" {
  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  parent_id   = aws_api_gateway_rest_api.autograding_api.root_resource_id
  path_part   = "grades"
}

resource "aws_api_gateway_method" "get_grades" {
  rest_api_id   = aws_api_gateway_rest_api.autograding_api.id
  resource_id   = aws_api_gateway_resource.grades.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  resource_id = aws_api_gateway_resource.grades.id
  http_method = aws_api_gateway_method.get_grades.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.grade_processor.invoke_arn
}

resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.grade_processor.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.autograding_api.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "deployment" {
  depends_on = [aws_api_gateway_integration.lambda_integration]
  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  stage_name  = "prod"
}

# Variables
variable "github_token" {
  description = "GitHub Personal Access Token for CodeBuild"
  type        = string
  sensitive   = true
}

variable "github_webhook_secret" {
  description = "Secret for GitHub webhook verification"
  type        = string
  sensitive   = true
}
```

