```hcl
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# S3 Bucket for storing student submissions and grading outputs
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = "cs-autograding-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "CS-Autograding-Bucket"
    Environment = "Production"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM Role for CodeBuild to interact with S3
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild permissions
resource "aws_iam_policy" "codebuild_policy" {
  name        = "cs-autograding-codebuild-policy"
  description = "Policy for CS autograding CodeBuild project"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.autograding_bucket.arn,
          "${aws_s3_bucket.autograding_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project for autograding
resource "aws_codebuild_project" "autograding_project" {
  name          = "cs-autograding-project"
  description   = "Autograding system for CS course submissions"
  build_timeout = "60"

  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "BUCKET_NAME"
      value = aws_s3_bucket.autograding_bucket.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO_URL"
      value = "https://github.com/your-org/your-repo" # Replace with actual GitHub repo
    }

    environment_variable {
      name  = "GRADER_SCRIPT"
      value = "autograder.sh" # Path to your autograder script
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/your-repo" # Replace with actual GitHub repo
    git_clone_depth = 1
  }

  source_version = "main" # Replace with your branch/tag/commit

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }
}

# CloudWatch Log Group for CodeBuild logs
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/cs-autograding-project"
  retention_in_days = 7
}

# Example buildspec file (can be stored in S3 or GitHub)
resource "aws_s3_object" "buildspec_file" {
  bucket = aws_s3_bucket.autograding_bucket.id
  key    = "buildspec.yml"
  content = <<-EOF
    version: 0.2
    phases:
      install:
        runtime-versions:
          python: 3.8
        commands:
          - pip install pytest
          - pip install pytest-cov
      pre_build:
        commands:
          - echo "Downloading student submission..."
          - aws s3 cp s3://${aws_s3_bucket.autograding_bucket.bucket}/submissions/${GITHUB_WORKFLOW_ID}/submission.zip .
          - unzip submission.zip
      build:
        commands:
          - echo "Running autograder..."
          - python3 ${GITHUB_WORKFLOW_ID}/autograder.py
          - echo "Saving results..."
          - aws s3 cp results.json s3://${aws_s3_bucket.autograding_bucket.bucket}/results/${GITHUB_WORKFLOW_ID}/
    artifacts:
      files: '**/*'
    EOF
}

# Example IAM Policy for GitHub Actions (if using GitHub Actions to trigger CodeBuild)
resource "aws_iam_policy" "github_actions_policy" {
  name        = "github-actions-codebuild-trigger"
  description = "Policy for GitHub Actions to trigger CodeBuild"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "codebuild:StartBuild"
        ],
        Resource = [
          aws_codebuild_project.autograding_project.arn
        ]
      }
    ]
  })
}

# Example Lambda Function for triggering CodeBuild (optional)
resource "aws_lambda_function" "trigger_lambda" {
  filename      = "lambda_function.zip"
  function_name = "trigger-autograding"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.8"
  timeout       = 30

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding_project.name
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_codebuild_trigger" {
  name = "lambda-codebuild-trigger-policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "codebuild:StartBuild"
        ],
        Resource = [
          aws_codebuild_project.autograding_project.arn
        ]
      }
    ]
  })
}

# Example API Gateway for triggering Lambda (optional)
resource "aws_api_gateway_rest_api" "autograding_api" {
  name = "cs-autograding-api"
}

resource "aws_api_gateway_resource" "trigger_resource" {
  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  parent_id   = aws_api_gateway_rest_api.autograding_api.root_resource_id
  path_part   = "trigger"
}

resource "aws_api_gateway_method" "trigger_method" {
  rest_api_id   = aws_api_gateway_rest_api.autograding_api.id
  resource_id   = aws_api_gateway_resource.trigger_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  resource_id = aws_api_gateway_resource.trigger_resource.id
  http_method = aws_api_gateway_method.trigger_method.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.trigger_lambda.invoke_arn
}

resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_lambda.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.autograding_api.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "autograding_deployment" {
  depends_on = [
    aws_api_gateway_integration.lambda_integration,
  ]

  rest_api_id = aws_api_gateway_rest_api.autograding_api.id
  stage_name  = "prod"
}
