terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for isolated execution
resource "aws_vpc" "autograding_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "AutogradingVPC"
  }
}

# Private Subnet for CodeBuild
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "AutogradingPrivateSubnet"
  }
}

# Internet Gateway (for NAT Gateway)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograding_vpc.id
  tags = {
    Name = "AutogradingIGW"
  }
}

# NAT Gateway for CodeBuild to access S3
resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.private_subnet.id
  tags = {
    Name = "AutogradingNAT"
  }
}

# Route Table for private subnet
resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.autograding_vpc.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
  tags = {
    Name = "AutogradingPrivateRouteTable"
  }
}

resource "aws_route_table_association" "private_route_association" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_route_table.id
}

# Security Group for CodeBuild (no internet access)
resource "aws_security_group" "codebuild_sg" {
  name        = "AutogradingCodeBuildSG"
  description = "Restrict CodeBuild to VPC only"
  vpc_id      = aws_vpc.autograding_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "AutogradingCodeBuildSG"
  }
}

# S3 Bucket for storing student submissions and results
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = "autograding-${random_id.bucket_suffix.hex}"
  force_destroy = true
  tags = {
    Name = "AutogradingBucket"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "AutogradingCodeBuildRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild (restricted permissions)
resource "aws_iam_policy" "codebuild_policy" {
  name        = "AutogradingCodeBuildPolicy"
  description = "Restricted permissions for CodeBuild"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = ["arn:aws:logs:*:*:*"]
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.autograding_bucket.arn,
          "${aws_s3_bucket.autograding_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild Project for autograding
resource "aws_codebuild_project" "autograding_project" {
  name          = "AutogradingProject"
  description   = "Autograding system for student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = false
    image_pull_credentials_type = "CODEBUILD"
    environment_variable {
      name  = "BUCKET_NAME"
      value = aws_s3_bucket.autograding_bucket.bucket
    }
    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-student-repos" # Replace with your GitHub repo pattern
    }
    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token # Use a sensitive variable
    }
    environment_variable {
      name  = "TEST_SCRIPT"
      value = "test.sh" # Path to your test script
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/your-repo.git" # Replace with your repo
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - pip install pytest
        pre_build:
          commands:
            - echo Logging in to Amazon ECR...
            - aws ecr get-login-password --region $AWS_DEFAULT_REGION | docker login --username AWS --password-stdin $AWS_ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com
        build:
          commands:
            - echo Building the Docker image...
            - docker build -t autograding-image .
            - docker tag autograding-image:latest $AWS_ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com/autograding-image:latest
            - docker push $AWS_ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com/autograding-image:latest
            - echo Running tests...
            - python3 -m pytest tests/ --junitxml=test-results.xml
            - echo Saving results to S3...
            - aws s3 cp test-results.xml s3://${BUCKET_NAME}/results/
      post_build:
        commands:
          - echo Build completed on `date`
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.cache/pip/**/*'
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }
}

# Lambda Function for triggering CodeBuild
resource "aws_lambda_function" "github_webhook" {
  function_name = "AutogradingWebhook"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  filename      = "data/autograding-webhook.zip" # Upload your Lambda function code
  memory_size   = 128
  timeout       = 30

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding_project.name
      BUCKET_NAME       = aws_s3_bucket.autograding_bucket.bucket
    }
  }
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "AutogradingLambdaRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
