# Private subnet for CodeBuild
resource "aws_subnet" "autograding_subnet" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "AutogradingSubnet"
  }
}

# Security group allowing only necessary traffic
resource "aws_security_group" "autograding_sg" {
  name        = "autograding-security-group"
  description = "Allow SSH and internal traffic only"
  vpc_id      = aws_vpc.autograding_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"] # Restrict to VPC only
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.1.0/24"] # Block all outbound internet access
  }

  tags = {
    Name = "AutogradingSecurityGroup"
  }
}

# S3 bucket for storing student submissions and grading results
resource "aws_s3_bucket" "autograding_bucket" {
  bucket = "autograding-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# IAM role for CodeBuild with minimal permissions
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "autograding-codebuild-custom-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "ecr:GetAuthorizationToken",
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for executing student submissions
resource "aws_codebuild_project" "autograding_project" {
  name          = "autograding-project"
  description   = "Execute student submissions in isolated environment"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = true
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "BUCKET_NAME"
      value = aws_s3_bucket.autograding_bucket.bucket
    }

    environment_variable {
      name  = "SUBMISSION_DIR"
      value = "submissions"
    }

    environment_variable {
      name  = "OUTPUT_DIR"
      value = "output"
    }

    environment_variable {
      name  = "BLOCK_INTERNET"
      value = "true"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-course-repo/student-submissions.git"
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.autograding_subnet.id]
    security_group_ids = [aws_security_group.autograding_sg.id]
  }

  tags = {
    Name = "AutogradingCodeBuild"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograding_logs" {
  name              = "/aws/codebuild/autograding-project"
  retention_in_days = 7
}

# Buildspec file for CodeBuild
resource "aws_s3_bucket_object" "buildspec" {
  bucket = aws_s3_bucket.autograding_bucket.bucket
  key    = "buildspec.yml"
  source = "${path.module}/buildspec.yml"
  etag   = filemd5("${path.module}/buildspec.yml")
}

# Example buildspec.yml (should be created in the same directory)
# This file would contain the actual build logic to execute student code
# and generate grades while blocking internet access
# Example content:
# version: 0.2
# phases:
#   install:
#     runtime-versions:
#       python: 3.8
#     commands:
#       - echo "Installing dependencies..."
#       - pip install pytest
#   pre_build:
#     commands:
#       - echo "Setting up environment..."
#       - mkdir -p ${OUTPUT_DIR}
#   build:
#     commands:
#       - echo "Running tests..."
#       - python -m pytest ${SUBMISSION_DIR}/ --no-header -q --tb=short | tee ${OUTPUT_DIR}/test_results.txt
#   post_build:
#     commands:
#       - echo "Grading complete"
#       - echo "Uploading results to S3..."
#       - aws s3 cp ${OUTPUT_DIR}/test_results.txt s3://${BUCKET_NAME}/results/
# artifacts:
#   files:
#     - '**/*'
# cache:
#   paths:
#     - '/root/.cache/pip/**/*'

