# AWS CodeBuild Project
resource "aws_codebuild_project" "student_build" {
  name          = "student-build-project"
  description   = "Build project for students"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.build_artifacts.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "alpine"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "SERVICE_ROLE"
    privileged_mode             = true
    vpc_config {
      vpc_id             = aws_vpc.main.id
      subnets            = [aws_subnet.private.id]
      security_group_ids = [aws_security_group.no_access.id]
    }
  }

  source {
    type      = "GITHUB"
    git_clone_depth     = 1
    location  = "github.com/source-location" # Replace with actual repo location
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "student-build-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

# IAM Policy for S3 access
resource "aws_iam_role_policy" "s3_access" {
  name = "student-build-s3-access"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow",
        Action   = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:DeleteObjectVersion",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ],
        Resource = [
          "${aws_s3_bucket.build_artifacts.arn}/*"
        ]
      }
    ]
  })
}
