terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.3"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_exec" {
  name = "cat-api-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Lambda to access S3
resource "aws_iam_policy" "lambda_s3_policy" {
  name        = "cat-api-lambda-s3-policy"
  description = "Policy for Lambda to access S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "lambda_s3_attachment" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = aws_iam_policy.lambda_s3_policy.arn
}

# S3 Bucket for cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-api-images-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Block public access to S3 bucket
resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Lambda function for uploading cat images
data "archive_file" "upload_lambda" {
  type        = "zip"
  source_file = "lambda/upload_cat_image.py"
  output_path = "lambda/upload_cat_image.zip"
}

resource "aws_lambda_function" "upload_cat_image" {
  filename      = data.archive_file.upload_lambda.output_path
  function_name = "uploadCatImage"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "upload_cat_image.lambda_handler"
  runtime       = "python3.9"
  s3_bucket     = aws_s3_bucket.cat_images.bucket
  s3_key        = "lambda/upload_cat_image.zip"
  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.bucket
    }
  }
}

# Lambda function for returning random cat images
data "archive_file" "random_lambda" {
  type        = "zip"
  source_file = "lambda/get_random_cat_image.py"
  output_path = "lambda/get_random_cat_image.zip"
}

resource "aws_lambda_function" "get_random_cat_image" {
  filename      = data.archive_file.random_lambda.output_path
  function_name = "getRandomCatImage"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "get_random_cat_image.lambda_handler"
  runtime       = "python3.9"
  s3_bucket     = aws_s3_bucket.cat_images.bucket
  s3_key        = "lambda/get_random_cat_image.zip"
  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.bucket
    }
  }
}

# API Gateway for the web API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "cat-api-gateway"
  description = "API for uploading and retrieving cat images"
}

# Upload endpoint
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "upload_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload_resource.id
  http_method = aws_api_gateway_method.upload_method.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.upload_cat_image.invoke_arn
}

# Get random cat image endpoint
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

resource "aws_api_gateway_method" "random_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "random_integration" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.random_method.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.get_random_cat_image.invoke_arn
}

# Deploy API Gateway
resource "aws_api_gateway_deployment" "api_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration,
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

# Lambda permissions for API Gateway
resource "aws_lambda_permission" "upload_permission" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat_image.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/POST/upload"
}

resource "aws_lambda_permission" "random_permission" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat_image.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*/GET/random"
}

# Output the API Gateway URL
output "api_gateway_url" {
  value = "${aws_api_gateway_deployment.api_deployment.invoke_url}"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_dynamodb_table" "caas" {
  name           = "cat_names"
  hash_key       = "name"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_s3_bucket" "caas" {
  bucket_prefix = "cat-image"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_api_gateway_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda_policy"
  role   = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.caas.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.caas.arn
      }
    ]
  })
}

resource "aws_api_gateway_rest_api" "caas" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_cat_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "caas_cat_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

data "archive_file" "caas_cat" {
  type        = "zip"
  source_file = "./supplement/caas_cat.py"
  output_path = "./supplement/caas_cat.zip"
}

resource "aws_lambda_function" "caas_cat" {
  function_name = "caas_cat"
  role          = aws_iam_role.lambda_role.arn
  filename      = data.archive_file.caas_cat.output_path
  source_code_hash = data.archive_file.caas_cat.output_base64sha256
  handler       = "caas_cat.handler"
  runtime       = "python3.12"

  environment {
    variables = {
      CAAS_S3_BUCKET = "${aws_s3_bucket.caas.id}"
      DYNAMODB_TABLE_NAME = "${aws_dynamodb_table.caas.id}"
    }
  }
}

resource "aws_api_gateway_integration" "caas_cat_get" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_get.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "GET"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_api_gateway_integration" "caas_cat_put" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_put.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "PUT"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_lambda_permission" "caas_cat" {
  action        = "lambda:InvokeFunction"
  principal     = "apigateway.amazonaws.com"
  function_name = aws_lambda_function.caas_cat.function_name

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  depends_on  = [aws_api_gateway_integration.caas_cat_get, 
                 aws_api_gateway_integration.caas_cat_put]
}

resource "aws_api_gateway_stage" "api_stage" {
  deployment_id = aws_api_gateway_deployment.api_deployment.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "dev"
}

output "api_id" {
  value = aws_api_gateway_rest_api.caas.id
  description = "The API Gateway ID"
}

