```hcl
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for storing cat images
resource "aws_s3_bucket" "cat_images_bucket" {
  bucket = "cat-images-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# DynamoDB table for tracking uploaded images
resource "aws_dynamodb_table" "cat_images_metadata" {
  name           = "CatImagesMetadata"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "image_id"

  attribute {
    name = "image_id"
    type = "S"
  }
}

# Lambda function for handling uploads and random cat image retrieval
resource "aws_lambda_function" "cat_service" {
  filename      = "lambda_function.zip"
  function_name = "cat-service-lambda"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images_bucket.bucket
      TABLE_NAME  = aws_dynamodb_table.cat_images_metadata.name
    }
  }
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Lambda
resource "aws_iam_policy" "lambda_policy" {
  name        = "lambda_s3_dynamodb_policy"
  description = "Policy for Lambda to access S3 and DynamoDB"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.cat_images_bucket.arn,
          "${aws_s3_bucket.cat_images_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Query"
        ],
        Resource = aws_dynamodb_table.cat_images_metadata.arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = aws_iam_policy.lambda_policy.arn
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_service_api" {
  name        = "cat-service-api"
  description = "API for uploading and retrieving cat images"
}

# API Gateway Resource for uploads
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_service_api.id
  parent_id   = aws_api_gateway_rest_api.cat_service_api.root_resource_id
  path_part   = "upload"
}

# API Gateway Resource for random cat image
resource "aws_api_gateway_resource" "random_cat_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_service_api.id
  parent_id   = aws_api_gateway_rest_api.cat_service_api.root_resource_id
  path_part   = "random"
}

# API Gateway Method for uploads (POST)
resource "aws_api_gateway_method" "upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_service_api.id
  resource_id   = aws_api_gateway_resource.upload_resource.id
  http_method   = "POST"
  authorization = "NONE"
}

# API Gateway Method for random cat image (GET)
resource "aws_api_gateway_method" "random_cat_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_service_api.id
  resource_id   = aws_api_gateway_resource.random_cat_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

# Lambda Permission for API Gateway to invoke Lambda
resource "aws_lambda_permission" "apigw_lambda_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_service.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_service_api.execution_arn}/*/${aws_api_gateway_method.upload_method.http_method}/${aws_api_gateway_resource.upload_resource.path}"
}

resource "aws_lambda_permission" "apigw_lambda_random_cat" {
  statement_id  = "AllowAPIGatewayInvokeRandomCat"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_service.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_service_api.execution_arn}/*/${aws_api_gateway_method.random_cat_method.http_method}/${aws_api_gateway_resource.random_cat_resource.path}"
}

# API Gateway Deployment
resource "aws_api_gateway_deployment" "cat_service_deployment" {
  depends_on = [
    aws_api_gateway_method.upload_method,
    aws_api_gateway_method.random_cat_method
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_service_api.id
  stage_name  = "prod"
}

# Output the API Gateway URL
output "api_gateway_url" {
  value = "${aws_api_gateway_deployment.cat_service_deployment.invoke_url}"
}
```

