terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC for the EC2 instance
resource "aws_vpc" "backup_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "BackupVPC"
  }
}

# Create a subnet for the EC2 instance
resource "aws_subnet" "backup_subnet" {
  vpc_id     = aws_vpc.backup_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "BackupSubnet"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "backup_igw" {
  vpc_id = aws_vpc.backup_vpc.id
  tags = {
    Name = "BackupIGW"
  }
}

# Create a route table
resource "aws_route_table" "backup_route_table" {
  vpc_id = aws_vpc.backup_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.backup_igw.id
  }
  tags = {
    Name = "BackupRouteTable"
  }
}

# Associate the route table with the subnet
resource "aws_route_table_association" "backup_route_association" {
  subnet_id      = aws_subnet.backup_subnet.id
  route_table_id = aws_route_table.backup_route_table.id
}

# Create a security group for the EC2 instance
resource "aws_security_group" "backup_sg" {
  name        = "backup_sg"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.backup_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "BackupSecurityGroup"
  }
}

# Create an EC2 instance
resource "aws_instance" "backup_instance" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.backup_subnet.id
  vpc_security_group_ids = [aws_security_group.backup_sg.id]
  tags = {
    Name = "BackupInstance"
  }
}

# Create a backup plan for the EC2 instance
resource "aws_backup_plan" "ec2_backup_plan" {
  name = "EC2DailyBackupPlan"

  rule {
    rule_name         = "DailyBackupRule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule_expression = "cron(0 0 * * ? *)" # Daily at 12:00 AM UTC
    start_window       = 60 # 60 minutes window for the backup job
    completion_window  = 1440 # 24 hours window for the backup job to complete
    lifecycle {
      delete_after = 30 # Delete backups after 30 days
    }
  }
}

# Create a backup selection for the EC2 instance
resource "aws_backup_selection" "ec2_backup_selection" {
  name              = "EC2BackupSelection"
  iam_role_arn      = aws_iam_role.backup_role.arn
  plan_id           = aws_backup_plan.ec2_backup_plan.id

  resources = [
    aws_instance.backup_instance.arn
  ]
}

# Create a backup vault
resource "aws_backup_vault" "backup_vault" {
  name = "EC2BackupVault"
}

# Create an IAM role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "AWSBackupEC2Role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS Backup policy to the IAM role
resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSBackupDefaultPolicy"
}

# Create an IAM policy for EC2 instance metadata access
resource "aws_iam_policy" "ec2_metadata_policy" {
  name        = "EC2MetadataAccessPolicy"
  description = "Policy for EC2 instance to access its own metadata"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "ec2:DescribeInstances",
          "ec2:DescribeInstanceStatus"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach the EC2 metadata policy to the IAM role
resource "aws_iam_role_policy_attachment" "ec2_metadata_policy_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = aws_iam_policy.ec2_metadata_policy.arn
}

