provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# IAM Role for EC2 to allow AWS Backup to manage it
resource "aws_iam_role" "ec2_backup_role" {
  name = "ec2-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_backup_policy" {
  role       = aws_iam_role.ec2_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupDefaultServiceRole"
}

# IAM Instance Profile for EC2
resource "aws_iam_instance_profile" "ec2_backup_profile" {
  name = "ec2-backup-profile"
  role = aws_iam_role.ec2_backup_role.name
}

# Security Group for EC2
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-backup-sg"
  description = "Allow SSH and HTTP traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Instance
resource "aws_instance" "backup_instance" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t2.micro"
  key_name      = "your-key-pair" # Replace with your key pair name
  iam_instance_profile = aws_iam_instance_profile.ec2_backup_profile.name
  security_groups = [aws_security_group.ec2_sg.name]

  tags = {
    Name = "BackupTestInstance"
  }
}

# AWS Backup Plan
resource "aws_backup_plan" "ec2_backup_plan" {
  name = "ec2-daily-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.ec2_backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Daily at 12:00 AM UTC
    start_window      = 60 # 60 minutes window to start the backup
    delete_after      = 7  # Delete backups after 7 days
    lifecycle {
      move_to_cold_storage_after = 30 # Move to cold storage after 30 days
    }
  }
}

# AWS Backup Vault
resource "aws_backup_vault" "ec2_backup_vault" {
  name = "ec2-backup-vault"
}

# AWS Backup Selection for EC2 Instance
resource "aws_backup_selection" "ec2_backup_selection" {
  name         = "ec2-backup-selection"

  iam_role_arn = aws_iam_role.ec2_backup_role.arn
  plan_id      = aws_backup_plan.ec2_backup_plan.id

  resources = [
    aws_instance.backup_instance.arn
  ]
}

# AWS Backup Copy Plan (Optional: For cross-region replication)
resource "aws_backup_copy_plan" "ec2_copy_plan" {
  name = "ec2-cross-region-copy-plan"

  rule {
    copy_action {
      destination_backup_vault_arn = aws_backup_vault.ec2_backup_vault.arn
      destination_region           = "us-west-2" # Change to your preferred region
    }
    target_backup_vault_arn = aws_backup_vault.ec2_backup_vault.arn
    schedule_expression       = "cron(0 0 * * ? *)"
  }
}

