  description         = "Triggers Lambda function daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)" # UTC time: 07:00 daily
}

resource "aws_lambda_function" "supplement_lambda" {
  filename      = "./supplement/lambda_func.zip"
  function_name = "supplement-lambda"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler" # Adjust based on your Lambda function's entry point
  runtime       = "nodejs18.x"    # Adjust runtime based on your Lambda function
  depends_on    = [aws_iam_role_policy_attachment.lambda_logs]
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_cron.name
  target_id = "lambda_target"
  arn       = aws_lambda_function.supplement_lambda.arn
}

resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.supplement_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_cron.arn
}
