    Environment = "Production"
  }
}

# Lambda Function for video processing (example: transcoding)
resource "aws_lambda_function" "video_processor" {
  function_name = "video-processing-function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "main.lambda_handler"
  runtime       = "python3.9"
  s3_bucket     = aws_s3_bucket.global_assets.id
  s3_key        = "lambda/video_processor.zip"

  environment {
    variables = {
      VIDEO_BUCKET = aws_s3_bucket.video_files[0].id
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_s3_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "lambda_dynamodb_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamDBFullAccess"
}

# EventBridge Rule for triggering video processing
resource "aws_cloudwatch_event_rule" "video_upload" {
  name        = "video-upload-rule"
  description = "Trigger video processing on S3 upload"

  event_pattern = jsonencode({
    source      = ["aws.s3"]
    detail_type = ["Object Created"]
    detail = {
      bucket = {
        name = [aws_s3_bucket.video_files[0].name]
      }
      object = {
        key = [".*\.(mp4|mov|avi)$"]
      }
    }
  })
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.video_upload.name
  target_id = "InvokeVideoProcessor"
  arn       = aws_lambda_function.video_processor.arn
}

# API Gateway for managing video metadata (REST API)
resource "aws_apigatewayv2_api" "video_api" {
  name          = "video-streaming-api"
  protocol_type = "HTTP"
  target        = aws_lambda_function.video_processor.arn
}

resource "aws_apigatewayv2_integration" "lambda_integration" {
  api_id           = aws_apigatewayv2_api.video_api.id
  integration_type = "AWS_PROXY"
  integration_uri  = aws_lambda_function.video_processor.invoke_arn
}

resource "aws_apigatewayv2_route" "video_route" {
  api_id    = aws_apigatewayv2_api.video_api.id
  route_key = "ANY /videos/{proxy+}"
  target    = "integrations/${aws_apigatewayv2_integration.lambda_integration.id}"
}

resource "aws_apigatewayv2_stage" "default_stage" {
  api_id      = aws_apigatewayv2_api.video_api.id
  name        = "$default"
  auto_deploy = true
}

# CloudFront Function for dynamic video URL generation
resource "aws_cloudfront_function" "video_url_generator" {
  name    = "video-url-generator"
  runtime = "cloudfront-js-1.0"
  publish = true

  code = <<-EOF
    function handler(event) {
      var request = event.request;
      var videoId = request.querystring.videoId;

      if (!videoId) {
        return request;
      }

      request.querystring = "region=us-east-1&videoId=" + videoId;
      request.headers["x-video-id"] = { value: videoId };

      return request;
    }
    EOF
}

# CloudFront Distribution Behavior for Function
resource "aws_cloudfront_distribution" "video_streaming_with_function" {
  origin {
    domain_name = aws_s3_bucket.video_files[0].bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_files[0].id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_files[0].id}"

    forwarded_values {
      query_string = true
      cookies {
        forward = "none"
      }
    }

    function_association {
      event_type = "viewer-request"
      function_arn = aws_cloudfront_function.video_url_generator.arn
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  aliases = ["stream.example.com"]

  price_class = "PriceClass_100"
}

# CloudWatch Logs for CloudFront
resource "aws_cloudwatch_log_group" "cloudfront_logs" {
  name              = "/aws/cloudfront/video-streaming"
  retention_in_days = 30
}

# Outputs
output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_streaming_with_function.domain_name
}

output "api_gateway_url" {
  value = aws_apigatewayv2_api.video_api.api_endpoint
}
