  public_subnets  = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  private_subnets = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = true
  one_nat_gateway_per_az = false

  enable_dns_hostnames = true
  enable_dns_support   = true

  public_subnet_tags = {
    "kubernetes.io/role/elb" = "1"
  }

  private_subnet_tags = {
    "kubernetes.io/role/internal-elb" = "1"
  }
}

# S3 Bucket for Video Storage
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-content-${random_id.bucket_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name = "Video Streaming Content"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# CloudFront Distribution for CDN
resource "aws_cloudfront_distribution" "video_streaming_cdn" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.bucket}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.cdn_origin_access_identity.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.bucket}"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_cloudfront_origin_access_identity" "cdn_origin_access_identity" {
  comment = "Access Identity for Video Streaming S3 Bucket"
}

# IAM Role for EC2 Instances
resource "aws_iam_role" "ec2_streaming_role" {
  name = "ec2-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_streaming_basic_execution" {
  role       = aws_iam_role.ec2_streaming_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_iam_instance_profile" "ec2_streaming_profile" {
  name = "ec2-streaming-profile"
  role = aws_iam_role.ec2_streaming_role.name
}

# Security Groups
resource "aws_security_group" "video_streaming_sg" {
  name        = "video-streaming-sg"
  description = "Allow traffic for video streaming platform"
  vpc_id      = module.video_streaming_vpc.vpc_id

  ingress {
    description = "HTTP from ALB"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  ingress {
    description = "HTTPS from ALB"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Video Streaming Security Group"
  }
}

resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP/HTTPS traffic to ALB"
  vpc_id      = module.video_streaming_vpc.vpc_id

  ingress {
    description = "HTTP from Internet"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS from Internet"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ALB Security Group"
  }
}

# EC2 Instances for Video Streaming
resource "aws_instance" "video_streaming_server" {
  count         = 3
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t3.large"
  key_name      = "video-streaming-key" # Replace with your key pair name
  subnet_id     = element(module.video_streaming_vpc.public_subnets, count.index)
  vpc_security_group_ids = [aws_security_group.video_streaming_sg.id]
  iam_instance_profile = aws_iam_instance_profile.ec2_streaming_profile.name

  user_data = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo yum install -y nginx
              sudo systemctl start nginx
              sudo systemctl enable nginx
              EOF

  tags = {
    Name = "VideoStreamingServer-${count.index + 1}"
  }
}

# Application Load Balancer
resource "aws_lb" "video_streaming_alb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.video_streaming_vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Environment = "Production"
  }
}

resource "aws_lb_target_group" "video_streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.video_streaming_vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200-299"
  }
}

resource "aws_lb_listener" "video_streaming_listener" {
  load_balancer_arn = aws_lb.video_streaming_alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

resource "aws_lb_listener" "video_streaming_https_listener" {
  load_balancer_arn = aws_lb.video_streaming_alb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.video_streaming_cert.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

# Register EC2 instances with the target group
resource "aws_lb_target_group_attachment" "video_streaming_tg_attachment" {
  count            = 3
  target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  target_id        = aws_instance.video_streaming_server[count.index].id
  port             = 80
}

# Route 53 Hosted Zone and Record
resource "aws_route53_zone" "video_streaming_domain" {
  name = "videostreaming.example" # Replace with your domain name
}

resource "aws_route53_record" "video_streaming_record" {
  zone_id = aws_route53_zone.video_streaming_domain.zone_id
  name    = aws_route53_zone.video_streaming_domain.name
  type    = "A"

  alias {
    name                   = aws_lb.video_streaming_alb.dns_name
    zone_id                = aws_lb.video_streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# ACM Certificate for HTTPS
resource "aws_acm_certificate" "video_streaming_cert" {
  domain_name       = aws_route53_record.video_streaming_record.name
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.video_streaming_cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.video_streaming_domain.zone_id
}

resource "aws_acm_certificate_validation" "video_streaming_cert_validation" {
  certificate_arn         = aws_acm_certificate.video_streaming_cert.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

# DynamoDB for Session Management
resource "aws_dynamodb_table" "video_streaming_session" {
  name           = "VideoStreamingSession"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "SessionId"

  attribute {
    name = "SessionId"
    type = "S"
  }

  tags = {
    Name = "VideoStreamingSession"
  }
}

# CloudWatch Logs for Monitoring
resource "aws_cloudwatch_log_group" "video_streaming_logs" {
  name              = "/video-streaming-platform"
  retention_in_days = 30
}

# Outputs
output "alb_dns_name" {
  description = "The DNS name of the ALB"
  value       = aws_lb.video_streaming_alb.dns_name
}

output "s3_bucket_name" {
  description = "The name of the S3 bucket for video content"
  value       = aws_s3_bucket.video_content.bucket
}

output "cloudfront_domain_name" {
  description = "The domain name of the CloudFront distribution"
  value       = aws_cloudfront_distribution.video_streaming_cdn.domain_name
}
```

