provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "postgres-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "postgres-igw"
  }
}

# Create Public Subnets
resource "aws_subnet" "public" {
  count             = 2 # At least 2 subnets for HA
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "postgres-public-subnet-${count.index}"
  }
}

# Create Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "postgres-public-rt"
  }
}

# Associate Route Table with Public Subnets
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Create Security Group for PostgreSQL
resource "aws_security_group" "postgres" {
  name        = "postgres-sg"
  description = "Allow PostgreSQL and SSH access"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to VPC CIDR or use specific IPs
  }

  ingress {
    description = "SSH access"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to VPC CIDR or use specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# Create RDS Subnet Group
resource "aws_db_subnet_group" "postgres" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.public[*].id
  tags = {
    Name = "postgres-subnet-group"
  }
}

# Create PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  allocated_storage    = 5
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro" # Adjust based on your needs
  db_name              = "postgresdb"
  username             = "adminuser" # Change to a secure username
  password             = "your_secure_password" # Change to a secure password
  parameter_group_name = "default.postgres17"
  skip_final_snapshot  = true # Disable for production
  vpc_security_group_ids = [aws_security_group.postgres.id]
  db_subnet_group_name   = aws_db_subnet_group.postgres.name
  publicly_accessible    = false
  storage_encrypted      = true # Enable encryption for production
  backup_retention_period = 7 # Adjust based on your needs
  multi_az               = false # Set to true for production

  tags = {
    Name = "postgres-instance"
  }
}

# Output the RDS endpoint
output "postgres_endpoint" {
  value = aws_db_instance.postgres.endpoint
}

