    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Create a subnet group for the RDS instance
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-postgresql-subnet-group"
  subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyy"] # Replace with your subnet IDs
  description = "Subnet group for PostgreSQL RDS instance"
}

# Create the RDS PostgreSQL instance
resource "aws_db_instance" "postgresql" {
  allocated_storage      = 50
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.m5.large"
  db_name                = "mydatabase"
  username               = "adminuser"
  password               = "YourSecurePassword123!" # Change to a secure password or use AWS Secrets Manager
  parameter_group_name   = aws_db_parameter_group.postgresql_param_group.name
  skip_final_snapshot    = true
  multi_az               = true
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_kms_key.arn
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false
  backup_retention_period = 7
  copy_tags_to_snapshot  = true
  storage_type           = "gp2"
  tags = {
    Name = "postgresql-15-instance"
  }
}
