data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
  statement {
    sid    = "Allow RDS to use the key"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["rds.amazonaws.com"]
    }
    actions = [
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKey*",
      "kms:DescribeKey"
    ]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}

# Create a custom PostgreSQL parameter group
resource "aws_db_parameter_group" "postgres_param_group" {
  name        = "postgres-custom-param-group"
  family      = "postgres13" # Adjust based on your PostgreSQL version
  description = "Custom parameter group for PostgreSQL RDS instance"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000" # Log statements longer than 1000ms
  }

  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements" # Enable pg_stat_statements for query statistics
  }

  tags = {
    Name = "postgres-custom-param-group"
  }
}

# Create a security group for the RDS instance
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.postgres_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to VPC CIDR or specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# Create the PostgreSQL RDS instance
resource "aws_db_instance" "postgres_rds" {
  allocated_storage      = 20 # Adjust based on your needs
  engine                 = "postgres"
  engine_version         = "13.4" # Adjust based on your needs
  instance_class         = "db.t3.medium" # Adjust based on your needs
  db_name                = "mydatabase" # Replace with your database name
  username               = "admin" # Replace with your admin username
  password               = "your_password" # Replace with a secure password or use aws_ssm_parameter
  parameter_group_name   = aws_db_parameter_group.postgres_param_group.name
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot" # As requested
  multi_az               = true # Enable Multi-AZ
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.postgres_kms_key.arn
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  publicly_accessible    = false
  backup_retention_period = 7 # Adjust based on your backup policy
  tags = {
    Name = "postgres-rds-instance"
  }
}

# Create a DB subnet group for the private subnets
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "postgres-subnet-group"
  }
}
```

