terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0.0"
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC and Subnet Configuration (assuming these exist; adjust as needed)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "public" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
  filter {
    name   = "map-public-ip-on-launch"
    values = ["true"]
  }
}

# Security Group for RDS (allow PostgreSQL traffic from Airbyte)
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-postgres-sg"
  description = "Allow PostgreSQL traffic for Airbyte"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to Airbyte's IP range in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS PostgreSQL 15 Instance
resource "aws_db_instance" "airbyte_postgres" {
  identifier             = "airbyte-postgres-15"
  engine                 = "postgres"
  engine_version         = "15.4" # Latest stable as of writing
  instance_class         = "db.r5.large" # Balanced compute/memory for workloads
  allocated_storage      = 500
  storage_type           = "gp3" # General Purpose SSD
  storage_encrypted       = true
  publicly_accessible    = false # Use VPC endpoints or private connectivity
  db_name                = "airbyte"
  username               = "airbyte_user"
  password               = "SecurePassword123!" # Use AWS Secrets Manager in production
  parameter_group_name   = "default.postgres15"
  skip_final_snapshot    = true # Disable for production (use snapshot policy)
  backup_retention_period = 7 # Enable backups
  multi_az               = true # High availability
  db_subnet_group_name   = aws_db_subnet_group.airbyte.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Performance tuning for Airbyte workloads
  max_allocated_storage = 1000 # Auto-scaling storage
  copy_tags_to_snapshot = true
  tags = {
    Purpose = "Airbyte Connector Testing"
  }
}

# DB Subnet Group (attach to public subnets)
resource "aws_db_subnet_group" "airbyte" {
  name       = "airbyte-postgres-subnet-group"
  subnet_ids = data.aws_subnets.public.ids
  tags = {
    Name = "Airbyte PostgreSQL Subnet Group"
  }
}

# Optional: CloudWatch Alarm for CPU/Memory (example)
resource "aws_cloudwatch_metric_alarm" "high_cpu" {
  alarm_name          = "airbyte-postgres-high-cpu"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/RDS"
  period              = "300"
  statistic           = "Average"
  threshold           = "70"
  alarm_description   = "Airbyte PostgreSQL CPU > 70% for 5 minutes"
  alarm_actions       = [] # Add SNS topic in production
  dimensions = {
    DBInstanceIdentifier = aws_db_instance.airbyte_postgres.id
  }
}

