      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "primary-vpc"
  }
}

# Create public subnets in two different AZs
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.primary.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-${count.index}"
  }
}

# Get availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create security group for database traffic
resource "aws_security_group" "db_sg" {
  name        = "postgresql-sg"
  description = "Allow PostgreSQL traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgresql-sg"
  }
}

# Create RDS PostgreSQL instance
resource "aws_db_instance" "postgresql" {
  allocated_storage      = 20
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.t3.micro" # Adjust for production
  db_name                = "postgresdb"
  username               = "adminuser" # Change to a secure username
  password               = "your_secure_password" # Change to a secure password
  skip_final_snapshot    = true
  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.postgresql.name
  multi_az               = false # Set to true for production
  storage_encrypted      = false # Set to true for production
  tags = {
    Name = "postgresql-rds"
  }
}

# Create DB subnet group
