  name       = "postgresql-subnet-group"
  subnet_ids = aws_subnet.public[*].id
  tags = {
    Name = "postgresql-subnet-group"
  }
}

# Output the database endpoint
output "postgresql_endpoint" {
  value = aws_db_instance.postgresql.endpoint
