terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-mysql-public-access"
  description = "Allow public access to MySQL RDS instance"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID or use aws_vpc.default if not specified

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Public access (restrict in production!)
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-mysql-public-access-sg"
  }
}

resource "aws_db_instance" "mysql" {
  identifier             = "mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = "admin" # Change to your preferred username
  password               = random_password.db_password.result
  db_name                = "mydatabase"
  parameter_group_name   = "default.mysql8.0"
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true # Publicly accessible (restrict in production!)
  multi_az               = false # Set to true for production HA
  backup_retention_period = 7
  tags = {
    Name = "mysql-instance"
  }
}

output "rds_endpoint" {
  value = aws_db_instance.mysql.endpoint
}

output "rds_password" {
  value     = random_password.db_password.result
  sensitive = true
}

