  route_table_id = aws_route_table.private_route_table.id
}

# Security Group (restrictive for RDS)
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow PostgreSQL access within VPC"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"] # Restrict to private subnet only
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  allocated_storage    = 20 # GB
  engine               = "postgres"
  engine_version       = "15.3" # Major version (upgradable)
  instance_class       = "db.t3.micro" # Adjust based on needs
  db_name              = "mydatabase"
  username             = "adminuser"
  password             = "SecurePassword123!" # Change to a secure password
  parameter_group_name = "default.postgres15" # Auto-updates minor versions
  skip_final_snapshot  = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name = aws_db_subnet_group.private_subnet_group.name
  publicly_accessible  = false # Private instance
  storage_encrypted     = true # Enable encryption
  backup_retention_period = 7 # Days
  multi_az             = false # Set to true for production HA
  storage_type         = "gp2" # General Purpose SSD
  tags = {
    Name = "private-postgres-db"
  }
  # Allow major version upgrades
  apply_immediately = true
  final_snapshot_identifier = "final-snapshot-postgres"
}

# DB Subnet Group (for private subnet)
resource "aws_db_subnet_group" "private_subnet_group" {
  name       = "private-subnet-group"
  subnet_ids = [aws_subnet.private_subnet.id]
  tags = {
    Name = "private-subnet-group"
  }
}
```

