```hcl
terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC Configuration
resource "aws_vpc" "db_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "Aurora-MySQL-VPC"
  }
}

# Public Subnets
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.db_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true
  tags = {
    Name = "Public-Subnet-${count.index}"
  }
}

# Private Subnets for RDS
resource "aws_subnet" "private_subnets" {
  count             = 2
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.${count.index + 2}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)
  tags = {
    Name = "Private-Subnet-${count.index}"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.db_vpc.id
  tags = {
    Name = "Aurora-MySQL-IGW"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.db_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "Public-Route-Table"
  }
}

# Route Table Association for Public Subnets
resource "aws_route_table_association" "public_association" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow inbound traffic to RDS Proxy"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Allow within VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS-Proxy-Security-Group"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS-Security-Group"
  }
}

# IAM Role for Secrets Manager
resource "aws_iam_role" "secrets_manager_role" {
  name = "rds-secrets-manager-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "secretsmanager.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Secrets Manager
resource "aws_iam_policy" "secrets_manager_policy" {
  name        = "rds-secrets-manager-policy"
  description = "Policy for Secrets Manager to manage RDS credentials"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:AddSourceIdentifierToSubscription",
          "rds:CreateDBInstanceReadConnection",
          "rds:CreateDBProxy",
          "rds:CreateDBProxyEndpoint",
          "rds:DescribeDBInstances",
          "rds:DescribeDBProxies",
          "rds:DescribeDBProxyEndpoints",
          "rds:DescribeDBSubnetGroups",
          "rds:DescribeSourceIdentifiers",
          "rds:ListTagsForResource",
          "rds:RemoveSourceIdentifierFromSubscription"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "secrets_manager_attachment" {
  role       = aws_iam_role.secrets_manager_role.name
  policy_arn = aws_iam_policy.secrets_manager_policy.arn
}

# Database Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "aurora-mysql-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id
  tags = {
    Name = "Aurora-MySQL-Subnet-Group"
  }
}

# Aurora MySQL Cluster
resource "aws_db_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = "admin"
  master_password         = var.db_password # Use a secure method to provide this
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  storage_encrypted       = true
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.db_subnet_group.name
  enable_http_endpoint    = true
  enable_https_endpoint    = true
  tags = {
    Name = "Aurora-MySQL-Cluster"
  }
}

# Aurora MySQL Instance
resource "aws_db_instance" "aurora_mysql_instance" {
  identifier             = "aurora-mysql-instance"
  engine                 = aws_db_cluster.aurora_mysql.engine
  engine_version         = aws_db_cluster.aurora_mysql.engine_version
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_cluster_identifier  = aws_db_cluster.aurora_mysql.id
  storage_type           = "gp2"
  allocated_storage      = 200
  max_allocated_storage  = 1000
  storage_encrypted      = true
  copy_tags_to_snapshot  = true
  skip_final_snapshot    = true
  tags = {
    Name = "Aurora-MySQL-Instance"
  }
}

# RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name        = "aurora-mysql-proxy"
  engine      = aws_db_cluster.aurora_mysql.engine
  role_arn    = aws_iam_role.secrets_manager_role.arn
  secrets_arn = aws_secretsmanager_secret.db_secret.arn

  vpc_subnet_ids = aws_subnet.private_subnets[*].id
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  require_tls = true

  proxy_target_groups {
    db_cluster_identifier = aws_db_cluster.aurora_mysql.id
  }

  tags = {
    Name = "Aurora-MySQL-Proxy"
  }
}

# Secrets Manager for Database Credentials
resource "aws_secretsmanager_secret" "db_secret" {
  name        = "aurora-mysql-secret"
  description = "Database credentials for Aurora MySQL"
  force_overwrite_replica_secret = true
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = aws_db_cluster.aurora_mysql.master_username
    password = var.db_password # Use a secure method to provide this
  })
}

# IAM Policy for RDS Proxy
resource "aws_iam_policy" "rds_proxy_policy" {
  name        = "rds-proxy-policy"
  description = "Policy for RDS Proxy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "secretsmanager:GetSecretValue"
        ],
        Resource = aws_secretsmanager_secret.db_secret.arn
      },
      {
        Effect = "Allow",
        Action = [
          "rds-db:connect"
        ],
        Resource = "*"
      }
    ]
  })
}

# Attach IAM Policy to RDS Proxy Role
resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.secrets_manager_role.name
  policy_arn = aws_iam_policy.rds_proxy_policy.arn
}

# Outputs
output "rds_proxy_endpoint" {
  value = aws_db_proxy.rds_proxy.endpoint
}

output "db_cluster_endpoint" {
  value = aws_db_cluster.aurora_mysql.endpoint
}

# Variables
variable "db_password" {
  description = "Master password for the Aurora MySQL cluster"
  type        = string
  sensitive   = true
}

# Data Source for Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}
