  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

resource "aws_security_group" "proxy_sg" {
  name        = "aurora-proxy-sg"
  description = "Allow traffic to RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private_subnet[*].id
  tags = {
    Name = "aurora-subnet-group"
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "aurora-rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSProxyDefaultRole"
}

# Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "aurora-mysql-credentials"
  description = "Credentials for Aurora MySQL"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = "your_secure_password_here" # Change this to a secure password
  })
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "mydatabase"
  master_username         = "admin"
  master_password         = "your_secure_password_here" # Should match the secret
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  storage_encrypted       = true
  enable_http_endpoint    = false
  enable_global_write_forwarding = false
  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Aurora MySQL Instance
resource "aws_rds_cluster_instance" "aurora_mysql_instance" {
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class      = "db.r5.large"
  engine              = aws_rds_cluster.aurora_mysql.engine
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
}

# RDS Proxy
resource "aws_rds_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  require_tls            = true
  idle_client_timeout    = 1800
  debug_logging          = false
  role_arn               = aws_iam_role.rds_proxy_role.arn
  secrets_arn            = aws_secretsmanager_secret.db_credentials.arn
  vpc_subnet_ids         = aws_subnet.private_subnet[*].id
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]
  endpoint_acceptance_token {
    acceptance_token = "accept"
  }
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

# Outputs
output "rds_cluster_endpoint" {
  value = aws_rds_cluster.aurora_mysql.endpoint
}

output "rds_proxy_endpoint" {
  value = aws_rds_proxy.aurora_proxy.endpoint
}

output "secrets_manager_arn" {
  value = aws_secretsmanager_secret.db_credentials.arn
}

data "aws_availability_zones" "available" {}
