}

# Create a Lightsail instance
resource "aws_lightsail_instance" "web_server" {
  name              = "my-web-server"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  bundle_id         = "nano_2_0"      # Nano instance (2GB RAM, 2 vCPUs)

  key_pair_name = "my-key-pair" # Replace with your existing key pair name or create one

  # Optional: Configure the instance
  user_data = <<-EOF
              #!/bin/bash
              sudo apt update -y
              sudo apt install -y nginx
              sudo systemctl start nginx
              EOF

  # Optional: Attach a static IP
  static_ip_name = "my-static-ip"

  # Optional: Configure the instance to be publicly accessible
