  key_pair_name     = aws_lightsail_key_pair.lightsail_key_pair.name

  # Optional: Configure instance settings
  instance_type {
    name = "nano_2_0"
  }

  # Optional: Attach a volume if needed
  volume {
    size_in_gb = 8
    is_boot     = true
  }
}

