terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lightsail_instance" "mysql_server" {
  name              = "mysql-lightsail-instance"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  bundle_id         = "large_2_0"     # 2 vCPUs, 2GB RAM
  key_pair_name     = "your-key-pair" # Replace with your SSH key pair name

  # Optional: Configure instance settings
  platform          = "linux"
  region           = "us-east-1"

  # Optional: Enable monitoring
  monitoring_status = "monitored"

  # Optional: Configure network settings
  subnet_id = aws_lightsail_static_ip.mysql_static_ip.id # Optional: If using static IP

  # Optional: Attach a static IP (uncomment and configure if needed)
  # static_ip = aws_lightsail_static_ip.mysql_static_ip.id
}

resource "aws_lightsail_static_ip" "mysql_static_ip" {
  name        = "mysql-static-ip"
  region      = "us-east-1"
  allocation_id = aws_lightsail_instance.mysql_server.static_ip_allocation_id
}

# Optional: Configure security group to allow MySQL traffic (port 3306)
resource "aws_lightsail_security_group" "mysql_sg" {
  name        = "mysql-security-group"
  instance_ids = [aws_lightsail_instance.mysql_server.id]
  region      = "us-east-1"

  # Allow SSH (port 22) from anywhere (restrict in production!)
  ingress {
    protocol    = "tcp"
    port_range  = "22"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow MySQL (port 3306) from anywhere (restrict in production!)
  ingress {
    protocol    = "tcp"
    port_range  = "3306"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    protocol  = "-1"
    from_port = 0
    to_port   = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Optional: User data script to install and configure MySQL
resource "aws_lightsail_instance_user_data" "mysql_setup" {
  instance_id = aws_lightsail_instance.mysql_server.id
  user_data   = <<-EOF
              #!/bin/bash
              sudo apt-get update -y
              sudo apt-get install -y mysql-server
              sudo mysql_secure_installation <<EOF
              n
              y
              y
              y
              y
              EOF
              sudo systemctl enable mysql
              sudo systemctl start mysql
              sudo mysql -e "CREATE DATABASE testdb;"
              sudo mysql -e "CREATE USER 'admin'@'%' IDENTIFIED BY 'your_secure_password';"
              sudo mysql -e "GRANT ALL PRIVILEGES ON testdb.* TO 'admin'@'%';"
              sudo mysql -e "FLUSH PRIVILEGES;"
              EOF
}

# Optional: Output the instance's public IP
output "mysql_instance_public_ip" {
  value = aws_lightsail_instance.mysql_server.public_ip_address
}

