  tags = {
    Name = "Example-Lightsail-Storage"
  }
}

# Create a Lightsail disk attachment to connect storage to the instance
resource "aws_lightsail_disk_attachment" "example" {
  instance_name = aws_lightsail_instance.example.name
  disk_name     = aws_lightsail_storage.example.name
  mount_path    = "/mnt/storage" # Adjust mount path as needed
  is_read_only  = false
}

# Output the instance's public IP and storage details
output "instance_public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

output "storage_name" {
  value = aws_lightsail_storage.example.name
}

output "storage_size" {
  value = aws_lightsail_storage.example.size
}
