  region = "us-east-1" # Change to your preferred region
}

# Create an IAM policy allowing Lightsail instance to access S3 bucket
resource "aws_iam_policy" "lightsail_s3_access" {
  name        = "LightsailS3AccessPolicy"
  description = "Policy to allow Lightsail instance to access S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::your-bucket-name", # Replace with your S3 bucket name
          "arn:aws:s3:::your-bucket-name/*"
        ]
      }
    ]
  })
}

# Create an IAM role for Lightsail instance
resource "aws_iam_role" "lightsail_role" {
  name = "LightsailS3AccessRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lightsail.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "lightsail_s3_access_attach" {
  role       = aws_iam_role.lightsail_role.name
  policy_arn = aws_iam_policy.lightsail_s3_access.arn
}

# Create a Lightsail instance profile
resource "aws_iam_instance_profile" "lightsail_profile" {
  name = "LightsailS3AccessProfile"
  role = aws_iam_role.lightsail_role.name
}

# Create a Lightsail instance (Ubuntu 22.04 LTS example)
resource "aws_lightsail_instance" "s3_access_instance" {
  name              = "s3-access-instance"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  bundle_id         = "nano_2_0"      # Nano instance
  key_pair_name     = "your-key-pair" # Replace with your key pair name

  # Attach the IAM instance profile
  iam_instance_profile_arn = aws_iam_instance_profile.lightsail_profile.arn
}

# Output the Lightsail instance public IP
output "lightsail_instance_public_ip" {
  value = aws_lightsail_instance.s3_access_instance.public_ip_address
}

