terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create an S3 bucket for the origin
resource "aws_s3_bucket" "distribution_origin" {
  bucket = "my-lightsail-distribution-origin-${random_id.bucket_suffix.hex}" # Unique bucket name
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Configure bucket policy to allow Lightsail distribution to access the bucket
resource "aws_s3_bucket_policy" "allow_lightsail_access" {
  bucket = aws_s3_bucket.distribution_origin.id
  policy = data.aws_iam_policy_document.lightsail_s3_policy.json
}

data "aws_iam_policy_document" "lightsail_s3_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.distribution_origin.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["lightsail.amazonaws.com"]
    }
  }
}

# Create a CloudFront distribution with S3 bucket as origin
resource "aws_cloudfront_distribution" "lightsail_distribution" {
  origin {
    domain_name = aws_s3_bucket.distribution_origin.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.distribution_origin.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.distribution_origin.id}"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Create CloudFront Origin Access Identity (OAI)
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for S3 bucket access"
}

# Update S3 bucket policy to allow CloudFront OAI access
resource "aws_s3_bucket_policy" "cloudfront_oai_policy" {
  bucket = aws_s3_bucket.distribution_origin.id
  policy = data.aws_iam_policy_document.cloudfront_oai_policy.json
}

data "aws_iam_policy_document" "cloudfront_oai_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.distribution_origin.arn}/*"]

    principals {
      type        = "AWS"
      identifiers = [aws_cloudfront_origin_access_identity.oai.iam_arn]
    }
  }
}

# AWS Lightsail Distribution (CDN) - Note: Lightsail does not natively support CloudFront distributions.
# Instead, you can use AWS CloudFront as a CDN and configure Lightsail to point to CloudFront's domain.
# Below is a placeholder for Lightsail instance configuration (if needed for other purposes)
# Note: Lightsail does not have a direct CDN service; this is a conceptual example.
# For a true Lightsail CDN, you would need to use a third-party solution or CloudFront.

# Output the CloudFront domain name for use with Lightsail
output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.lightsail_distribution.domain_name
}

