terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a Lightsail instance for the origin
resource "aws_lightsail_instance" "origin_instance" {
  name              = "origin-server"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  bundle_id         = "nano_2_0"      # Nano instance (adjust based on your needs)

  key_pair_name = "your-key-pair" # Replace with your SSH key pair name

  # Configure the instance to allow HTTP/HTTPS traffic
  user_data = <<-EOF
              #!/bin/bash
              sudo apt-get update
              sudo apt-get install -y nginx
              sudo systemctl start nginx
              sudo systemctl enable nginx
              EOF

  # Attach a static IP to the instance
  attach_data = {
    source = aws_lightsail_static_ip.origin_static_ip.id
  }
}

# Create a static IP for the Lightsail instance
resource "aws_lightsail_static_ip" "origin_static_ip" {
  name = "origin-static-ip"
}

# Create a Lightsail distribution for CloudFront-like distribution
resource "aws_lightsail_distribution" "cdn_distribution" {
  name = "origin-distribution"

  origin {
    origin_id   = "origin-server"
    domain_name = aws_lightsail_instance.origin_instance.public_ip_address
    origin_type = "instance"
  }

  origin_groups {
    name = "origin-group"

    origins {
      origin_id = "origin-server"
    }
  }

  # Configure the distribution to listen on HTTP and HTTPS
  listeners {
    protocol = "http"
    port     = 80
    origin_groups {
      name = aws_lightsail_distribution.cdn_distribution.origin_groups[0].name
    }
  }

  listeners {
    protocol = "https"
    port     = 443
