terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# S3 Bucket for Long-Term Data Retention
resource "aws_s3_bucket" "long_term_retention" {
  bucket = "long-term-retention-bucket-${random_id.bucket_suffix.hex}" # Unique bucket name
  tags = {
    Name        = "Long-Term-Retention-Bucket"
    Environment = "Production"
    Purpose     = "Long-Term Data Storage"
  }
}

# Enable versioning for backup recovery
resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.long_term_retention.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable server-side encryption with SSE-S3
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.long_term_retention.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Configure lifecycle rules for long-term retention
resource "aws_s3_bucket_lifecycle_configuration" "lifecycle" {
  bucket = aws_s3_bucket.long_term_retention.id

  rule {
    id     = "archive-to-glacier-after-90-days"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 365
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 3650 # 10 years (adjust as needed)
    }
  }
}

# Enable bucket logging for audit purposes
resource "aws_s3_bucket_logging" "logging" {
  bucket        = aws_s3_bucket.long_term_retention.id
  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "logs/"
}

# Separate bucket for logging
resource "aws_s3_bucket" "log_bucket" {
  bucket = "long-term-retention-logs-bucket-${random_id.bucket_suffix.hex}"
  tags = {
    Name        = "Long-Term-Retention-Logs-Bucket"
    Environment = "Production"
  }
}

# Block public access to the bucket
resource "aws_s3_bucket_public_access_block" "public_access_block" {
  bucket = aws_s3_bucket.long_term_retention.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Generate random suffix for bucket names
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# IAM Policy for Backup Access
resource "aws_iam_policy" "backup_policy" {
  name        = "LongTermBackupPolicy"
  description = "Policy for long-term backup access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:DeleteObject"
        ]
        Resource = [
          aws_s3_bucket.long_term_retention.arn,
          "${aws_s3_bucket.long_term_retention.arn}/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetBucketLocation"
        ]
        Resource = aws_s3_bucket.long_term_retention.arn
      }
    ]
  })
}

# Output the bucket name for reference
output "bucket_name" {
  value = aws_s3_bucket.long_term_retention.bucket
}

output "bucket_arn" {
  value = aws_s3_bucket.long_term_retention.arn
}

