# Create an S3 Glacier Vault
resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault-${random_id.bucket_suffix.hex}" # Unique bucket name
  force_destroy = true
}

resource "aws_s3_bucket_versioning" "glacier_vault_versioning" {
  bucket = aws_s3_bucket.glacier_vault.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "glacier_transition" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 3650 # 10 years (optional: adjust as needed)
    }
  }
}

# Create a Data Lifecycle Manager policy for the Glacier Vault
resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description = "Lifecycle policy for S3 Glacier Vault"

  policy_type = "S3_GLACIER"

  policy_details {
    schedule {
      name = "daily-glacier-transition"
      copy_tags = true
      rule {
        name          = "transition-to-glacier"
        status        = "ENABLED"
        transition {
          days = 30
          storage_class = "GLACIER"
        }
      }
    }
  }

  retention_period_days = 90 # Adjust as needed
}

resource "aws_dlm_lifecycle_policy" "deep_archive_policy" {
  description = "Lifecycle policy for S3 Deep Archive"

  policy_type = "S3_DEEP_ARCHIVE"

  policy_details {
    schedule {
      name = "daily-deep-archive-transition"
      copy_tags = true
      rule {
        name          = "transition-to-deep-archive"
        status        = "ENABLED"
        transition {
          days = 90
          storage_class = "DEEP_ARCHIVE"
        }
      }
    }
  }

  retention_period_days = 3650 # Adjust as needed
}

# Associate the DLM policy with the S3 bucket
resource "aws_dlm_lifecycle_association" "glacier_association" {
  lifecycle_policy_arn = aws_dlm_lifecycle_policy.glacier_policy.arn
  resource_arn         = aws_s3_bucket.glacier_vault.arn
}

resource "aws_dlm_lifecycle_association" "deep_archive_association" {
  lifecycle_policy_arn = aws_dlm_lifecycle_policy.deep_archive_policy.arn
  resource_arn         = aws_s3_bucket.glacier_vault.arn
}

