  policy_details {
    resource_types = ["VOLUME"]
    target_tags = {
      "archive" = "true"
    }
    schedule {
      name = "2 weeks of daily snapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
