}

resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault-${random_id.bucket_suffix.hex}" # Unique bucket name
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_versioning" "glacier_vault_versioning" {
  bucket = aws_s3_bucket.glacier_vault.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "glacier_vault_encryption" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "glacier_vault_public_access" {
  bucket = aws_s3_bucket.glacier_vault.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_policy" "glacier_vault_policy" {
  bucket = aws_s3_bucket.glacier_vault.id
  policy = data.aws_iam_policy_document.glacier_vault_policy.json
}

data "aws_iam_policy_document" "glacier_vault_policy" {
  statement {
    actions   = ["s3:*"]
    resources = [aws_s3_bucket.glacier_vault.arn]

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "glacier_vault_lifecycle" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    id     = "glacier_transition_rule"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 3650 # 10 years
    }
  }
}

resource "aws_s3_bucket_notification" "glacier_vault_notification" {
  bucket = aws_s3_bucket.glacier_vault.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.glacier_notification.arn
    events              = ["s3:ObjectRestore:Complete"]
    filter_suffix       = ".glacier" # Optional: Filter for specific suffixes
  }

  depends_on = [aws_lambda_permission.allow_bucket]
}

resource "aws_cloudwatch_event_rule" "glacier_retrieval_complete" {
  name        = "glacier-retrieval-complete"
  description = "Trigger for Glacier retrieval completion notification"
}

resource "aws_cloudwatch_event_target" "glacier_notification_target" {
  rule      = aws_cloudwatch_event_rule.glacier_retrieval_complete.name
  target_id = "SendGlacierNotification"
  arn       = aws_lambda_function.glacier_notification.arn
}

resource "aws_lambda_function" "glacier_notification" {
  filename      = "lambda_function.zip" # Replace with your Lambda deployment package
  function_name = "glacier-retrieval-notification"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x" # Adjust runtime as needed
  timeout       = 30

  environment {
    variables = {
      SNS_TOPIC_ARN = aws_sns_topic.glacier_notification.arn
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "glacier_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "lambda_s3_access_policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.glacier_vault.arn,
          "${aws_s3_bucket.glacier_vault.arn}/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect   = "Allow"
        Action   = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.glacier_notification.arn
      }
    ]
  })
}

resource "aws_lambda_permission" "allow_bucket" {
  statement_id  = "AllowExecutionFromS3Bucket"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.glacier_notification.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.glacier_vault.arn
}

resource "aws_sns_topic" "glacier_notification" {
  name = "glacier-retrieval-notification-topic"
}

