    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_vpc" "alb_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "ALB-VPC"
  }
}

resource "aws_subnet" "alb_subnet_1" {
  vpc_id     = aws_vpc.alb_vpc.id
  cidr_block = "10.0.1.0/24"

  availability_zone = "us-east-1a"
  tags = {
    Name = "ALB-Subnet-1"
  }
}

resource "aws_subnet" "alb_subnet_2" {
  vpc_id     = aws_vpc.alb_vpc.id
  cidr_block = "10.0.2.0/24"

  availability_zone = "us-east-1b"
  tags = {
    Name = "ALB-Subnet-2"
  }
}

resource "aws_internet_gateway" "alb_igw" {
  vpc_id = aws_vpc.alb_vpc.id

  tags = {
    Name = "ALB-IGW"
  }
}

resource "aws_route_table" "alb_route_table" {
  vpc_id = aws_vpc.alb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.alb_igw.id
  }

  tags = {
    Name = "ALB-Route-Table"
  }
}

resource "aws_route_table_association" "alb_route_association_1" {
  subnet_id      = aws_subnet.alb_subnet_1.id
  route_table_id = aws_route_table.alb_route_table.id
}

resource "aws_route_table_association" "alb_route_association_2" {
  subnet_id      = aws_subnet.alb_subnet_2.id
  route_table_id = aws_route_table.alb_route_table.id
}

resource "aws_security_group" "alb_sg" {
  name        = "ALB-Security-Group"
  description = "Allow HTTP and HTTPS traffic"
  vpc_id      = aws_vpc.alb_vpc.id

  ingress {
    description = "HTTP from Internet"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS from Internet"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ALB-Security-Group"
  }
}

resource "aws_lb" "alb" {
  name               = "app-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.alb_subnet_1.id, aws_subnet.alb_subnet_2.id]

  enable_deletion_protection = false

  tags = {
    Name = "App-ALB"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "fixed-response"

    fixed_response {
      content_type = "text/plain"
      message_body = "Redirect to HTTPS"
      status_code  = "200"
    }
  }
}

resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.alb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your ACM certificate ARN

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_target_group.arn
  }
}

resource "aws_lb_target_group" "alb_target_group" {
  name     = "alb-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.alb_vpc.id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200-399"
  }

  tags = {
    Name = "ALB-Target-Group"
  }
}

