# main.tf - AWS ALB with Elastic IP (EIP) configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC (if not already existing)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "alb-vpc"
  }
}

# Create a public subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "alb-public-subnet"
  }
}

# Create an Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "alb-igw"
  }
}

# Create a route table for public subnet
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "alb-public-rt"
  }
}

# Associate route table with public subnet
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Create an Elastic IP (EIP) for the Load Balancer
resource "aws_eip" "alb" {
  domain   = "vpc"
  tags = {
    Name = "alb-eip"
  }
}

# Create an Application Load Balancer
resource "aws_lb" "main" {
  name               = "alb-example"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = [aws_subnet.public.id]
  enable_deletion_protection = false

  # Attach the Elastic IP to the Load Balancer
  access_logs {
    bucket  = aws_s3_bucket.alb_logs.id
    enabled = true
  }

  tags = {
    Name = "alb-with-eip"
  }
}

# Create a security group for the ALB
resource "aws_security_group" "alb" {
  name        = "alb-sg"
  description = "Allow HTTP/HTTPS traffic to ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# Create an S3 bucket for ALB logs
resource "aws_s3_bucket" "alb_logs" {
  bucket = "alb-access-logs-${random_id.bucket_suffix.hex}"
  tags = {
    Name = "alb-access-logs"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Associate the Elastic IP with the ALB (using AWS Network Load Balancer workaround)
# Note: ALB does not directly support Elastic IPs, so we use a workaround with NLB
# For true ALB with EIP, consider using a NAT Gateway or other workaround

# Alternative: Use Network Load Balancer with Elastic IP
resource "aws_lb" "nlb_with_eip" {
  name               = "nlb-with-eip"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public.id]
  enable_deletion_protection = false

  access_logs {
    bucket  = aws_s3_bucket.alb_logs.id
    enabled = true
  }

  tags = {
    Name = "nlb-with-eip"
  }
}

# Attach Elastic IP to Network Load Balancer
resource "aws_lb_listener" "nlb_eip" {
  load_balancer_arn = aws_lb.nlb_with_eip.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# Create a target group for the NLB
resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
}

# Associate the Elastic IP with the NLB (using an ENI)
resource "aws_network_interface" "nlb_eni" {
  subnet_id       = aws_subnet.public.id
  private_ips     = ["10.0.1.100"] # Replace with your desired private IP
  security_groups = [aws_security_group.nlb.id]

  tags = {
    Name = "nlb-eni"
  }
}

resource "aws_eip_association" "nlb_eip_assoc" {
  network_interface_id = aws_network_interface.nlb_eni.id
  allocation_id        = aws_eip.alb.id
}

# Security group for NLB
resource "aws_security_group" "nlb" {
  name        = "nlb-sg"
  description = "Allow traffic to NLB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "nlb-sg"
  }
}
```

