  load_balancer_arn = aws_lb.authenticated_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.example.arn
      user_pool_client_id = aws_cognito_user_pool_client.example.client_id
      user_pool_domain    = aws_cognito_user_pool.example.domain
      authentication_request_extra_params = {
        redirect_uri = "https://${aws_lb.authenticated_lb.dns_name}/"
      }
    }
  }
}

resource "aws_cognito_user_pool" "example" {
  name = "authenticated-alb-pool"
  auto_verified_attributes = ["email"]
}

resource "aws_cognito_user_pool_client" "example" {
  name         = "authenticated-alb-client"
  user_pool_id = aws_cognito_user_pool.example.id
  generate_secret = false
  explicit_auth_flows = [
    "ALLOW_USER_PASSWORD_AUTH",
    "ALLOW_REFRESH_TOKEN_AUTH"
  ]
}

resource "aws_cognito_user_pool_domain" "example" {
  domain       = "authenticated-alb-domain"
  user_pool_id = aws_cognito_user_pool.example.id
}

