provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_lb" "main" {
  name               = "oidc-auth-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id] # Replace with your subnet IDs

  enable_deletion_protection = false
}

resource "aws_security_group" "lb_sg" {
  name        = "oidc-auth-lb-sg"
  description = "Security group for OIDC Auth Load Balancer"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "public-subnet-2"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your ACM certificate ARN

  default_action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      authorization_endpoint = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/auth"
      client_id             = "your-client-id" # Replace with your OIDC client ID
      client_secret         = "your-client-secret" # Replace with your OIDC client secret
      token_endpoint        = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/token"
      user_info_endpoint    = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/userinfo"
      issuer               = "https://your-identity-provider.com/auth/realms/your-realm"
      on_unauthenticated_request = "authenticate"
      scope                 = "openid email profile"
    }
  }
}

