  availability_zone = "us-east-1a"
  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "public-subnet-2"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your ACM certificate ARN

  default_action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      authorization_endpoint = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/auth"
      client_id             = "your-client-id" # Replace with your OIDC client ID
      client_secret         = "your-client-secret" # Replace with your OIDC client secret
      token_endpoint        = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/token"
      user_info_endpoint    = "https://your-identity-provider.com/auth/realms/your-realm/protocol/openid-connect/userinfo"
      issuer               = "https://your-identity-provider.com/auth/realms/your-realm"
      on_unauthenticated_request = "authenticate"
      scope                 = "openid email profile"
    }
  }
}
