  identifier             = "simple-sql-db"
  engine                 = "mysql" # Change to "postgres" for PostgreSQL or "oracle-se2" for Oracle
  engine_version         = "8.0"   # Adjust version as needed
  instance_class         = "db.t3.micro" # Free tier eligible instance class
  allocated_storage      = 20      # Minimum 20GB for MySQL
  storage_type           = "gp2"   # General Purpose SSD
  username               = "admin" # Change to a secure username
  password               = "your_secure_password_here" # Change to a secure password or use aws_ssm_parameter
  db_name                = "mydatabase"
  skip_final_snapshot    = true    # Disable for production to create a final snapshot
  publicly_accessible    = false  # Set to true only if necessary (not recommended for security)
  multi_az               = false  # Enable for production for high availability
  backup_retention_period = 7      # Days to retain automated backups
  tags = {
    Name = "SimpleSQLDB"
  }
}

# Optional: Create a security group for the DB (if not using default VPC)
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow inbound traffic to DB from VPC only"
  vpc_id      = aws_vpc.default.id # Requires aws_vpc.default resource or adjust accordingly

  ingress {
    from_port   = 3306 # MySQL default port (adjust for other engines)
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["${aws_vpc.default.cidr_block}"] # Allow only within VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Optional: Create a VPC (if not using default VPC)
resource "aws_vpc" "default" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "default-vpc"
  }
}

# Optional: Output the endpoint for connection
output "db_endpoint" {
  value = aws_db_instance.simple_db.endpoint
}

