  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = {
    Name = "PostgreSQL Minimal Memory VPC"
  }
}

# Subnet for PostgreSQL
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "PostgreSQL Minimal Memory Subnet"
  }
}

# PostgreSQL RDS Instance with minimal memory optimization
resource "aws_db_instance" "postgres" {
  allocated_storage      = 20 # Start with minimal storage
  storage_type           = "gp2"
  engine                 = "postgres"
  engine_version         = "15.3" # Latest stable version
  instance_class         = "db.t3.micro" # Low-cost instance with minimal memory
  db_name                = "postgres"
  username               = var.db_username
  password               = var.db_password
  parameter_group_name   = aws_db_parameter_group.postgres_minimal.name
  skip_final_snapshot    = true # Disable for production
  publicly_accessible    = false
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.postgres.name
  multi_az               = false # Disable for cost savings (enable in production)
  storage_encrypted      = false # Enable in production
  backup_retention_period = 0 # Disable for minimal memory usage (enable in production)

  # Performance optimization for minimal memory
  max_allocated_storage = 20
  performance_insights_enabled = false # Disable for minimal memory usage
  copy_tags_to_snapshot = false # Disable for minimal memory usage

  tags = {
    Name = "PostgreSQL Minimal Memory Instance"
  }
}

# PostgreSQL DB Subnet Group
resource "aws_db_subnet_group" "postgres" {
  name       = "postgres-minimal-memory-subnet-group"
  subnet_ids = [aws_subnet.private.id]
  tags = {
    Name = "PostgreSQL Minimal Memory Subnet Group"
  }
}

# PostgreSQL Parameter Group for minimal memory optimization
resource "aws_db_parameter_group" "postgres_minimal" {
  name        = "postgres-minimal-memory-param-group"
  family      = "postgres15"
  description = "Parameter group optimized for minimal memory usage"

  parameter {
    name  = "shared_buffers"
    value = "16MB" # Reduced from default 128MB
  }

  parameter {
    name  = "effective_cache_size"
    value = "64MB" # Reduced from default 4GB
  }

  parameter {
    name  = "work_mem"
    value = "1MB" # Reduced from default 4MB
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "16MB" # Reduced from default 64MB
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1" # Optimized for SSD storage
  }

  parameter {
    name  = "effective_io_concurrency"
    value = "200" # Optimized for SSD storage
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.9" # Optimized for SSD storage
  }

  parameter {
    name  = "wal_buffers"
    value = "16MB" # Reduced from default 16MB (but kept minimal)
  }

  parameter {
    name  = "min_wal_size"
    value = "16MB" # Reduced from default 8MB
  }

  parameter {
    name  = "max_wal_size"
    value = "128MB" # Reduced from default 1GB
  }

  parameter {
    name  = "max_connections"
    value = "20" # Reduced from default 100
  }

  parameter {
    name  = "max_prepared_transactions"
    value = "0" # Disable prepared transactions
  }

  parameter {
    name  = "shared_preload_libraries"
    value = "" # Disable unnecessary extensions
  }
}

# Outputs
output "postgres_endpoint" {
  description = "PostgreSQL endpoint"
  value       = aws_db_instance.postgres.endpoint
}

output "postgres_port" {
  description = "PostgreSQL port"
  value       = var.postgres_port
}

variable "postgres_port" {
  description = "PostgreSQL port"
  type        = number
  default     = 5432
}

