terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC for the RDS instance
resource "aws_vpc" "rds_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "rds-vpc"
  }
}

# Create a subnet for the RDS instance
resource "aws_subnet" "rds_subnet" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "rds-subnet"
  }
}

# Create a security group for the RDS instance
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.rds_vpc.id

  ingress {
    from_port   = 5432 # PostgreSQL default port; change if using MySQL (3306) or other
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# Create a DB subnet group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.rds_subnet.id]

  tags = {
    Name = "rds-subnet-group"
  }
}

# Create the primary RDS instance (PostgreSQL example)
resource "aws_db_instance" "primary_rds" {
  allocated_storage      = 20
  engine                 = "postgres" # Change to "mysql" for MySQL
  engine_version         = "15.4"     # Adjust version as needed
  instance_class         = "db.t3.micro"
  db_name                = "primarydb"
  username               = "admin"
  password               = "your_secure_password_here" # Use AWS Secrets Manager in production
  parameter_group_name   = "default.postgres15" # Adjust for MySQL
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  publicly_accessible    = false # Set to true if needed for testing
  storage_encrypted      = true
  backup_retention_period = 7
  multi_az               = true # Enable for high availability
  tags = {
    Name = "primary-rds-instance"
  }
}

# Create a read replica of the primary RDS instance
resource "aws_db_instance" "replica_rds" {
  allocated_storage      = 20
  engine                 = aws_db_instance.primary_rds.engine
  engine_version         = aws_db_instance.primary_rds.engine_version
  instance_class         = "db.t3.micro"
  db_name                = "replicadb"
  username               = aws_db_instance.primary_rds.username
  password               = aws_db_instance.primary_rds.password
  parameter_group_name   = aws_db_instance.primary_rds.parameter_group_name
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  publicly_accessible    = false
  storage_encrypted      = true
  backup_retention_period = 7
  replica_of             = aws_db_instance.primary_rds.arn # Specify the primary instance ARN
  tags = {
    Name = "replica-rds-instance"
