  depends_on              = [aws_iam_role_policy.rds_s3_read_policy]
}

# Generate a random suffix for the snapshot identifier
resource "random_id" "snapshot_suffix" {
  byte_length = 4
}

# Create a DB instance from the restored snapshot
resource "aws_db_instance" "restored_db" {
  identifier             = "restored-db-instance" # Replace with your desired DB instance identifier
  allocated_storage      = 20 # Adjust storage as needed
  engine                 = "postgres" # Change to your preferred DB engine (e.g., "mysql", "oracle-ee")
  engine_version         = "15.3" # Adjust version as needed
  instance_class         = "db.t3.micro" # Adjust instance class as needed
  db_name                = "restored_database" # Replace with your desired DB name
  username               = "admin" # Replace with your desired DB username
  password               = "your-secure-password" # Replace with a secure password
  skip_final_snapshot    = true # Set to false if you want final snapshots
  snapshot_identifier    = aws_db_snapshot.restored_snapshot.db_snapshot_identifier
  db_subnet_group_name   = aws_db_subnet_group.default.name # Optional: Create subnet group if needed
  vpc_security_group_ids = [aws_security_group.rds_sg.id] # Optional: Create security group if needed
  publicly_accessible    = false # Set to true if needed
  storage_encrypted       = true # Set to false if encryption is not required
  backup_retention_period = 7 # Set to 0 to disable automated backups
  multi_az               = false # Set to true for multi-AZ deployment
}

# Optional: Create a DB subnet group
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id] # Replace with your subnet IDs
}

# Optional: Create security group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.main.id # Replace with your VPC ID

  ingress {
    from_port   = 5432 # PostgreSQL default port; adjust for your DB engine
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust CIDR block as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Optional: Create VPC and subnets (if not already existing)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}
