resource "aws_db_instance" "scalable_database" {
  identifier             = "scalable-db-instance"
  engine                 = "aurora-postgresql" # Aurora PostgreSQL (change to 'mysql' for MySQL)
  engine_version         = "15.4" # Adjust version as needed
  instance_class         = "db.serverless" # Serverless v1 (or use 'db.r6g.large' for provisioned)
  storage_encrypted      = true
  skip_final_snapshot    = true # Set to false if you want final snapshots

  # Enable auto-scaling for storage
  storage_type           = "aurora" # Aurora-specific storage type
  allocated_storage      = 20 # Initial storage in GB (minimum for Aurora Serverless v1)
  max_allocated_storage  = 128 # Maximum storage in GB (adjust as needed)

  # Serverless v1 specific configurations
  scaling_configuration {
    auto_pause               = true
    min_capacity            = 0.5 # ACU (Aurora Capacity Unit)
    max_capacity            = 8   # ACU (Aurora Capacity Unit)
    seconds_until_auto_pause = 300 # 5 minutes
    timeout_action          = "ForceApplyCapacityChange" # or "RollbackApplyCapacityChange"
  }

  # Optional: Enable performance insights for monitoring
  performance_insights_enabled = true
  performance_insights_retention_period = 7

