terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a KMS key for Secrets Manager
resource "aws_kms_key" "db_secret_key" {
  description             = "KMS key for encrypting RDS database secrets"
  deletion_window_in_days = 30
  enable_key_rotation     = true
  policy                  = data.aws_iam_policy_document.kms_key_policy.json
}

data "aws_iam_policy_document" "kms_key_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }

  statement {
    sid    = "Allow Secrets Manager to use the key"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["secretsmanager.amazonaws.com"]
    }
    actions = [
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKey*",
      "kms:DescribeKey"
    ]
    resources = ["*"]
  }
}

# Create a Secrets Manager secret for the database master credentials
resource "aws_secretsmanager_secret" "db_master_secret" {
  name        = "rds/master-credentials"
  description = "Master credentials for the RDS database"
  kms_key_id  = aws_kms_key.db_secret_key.arn
}

resource "aws_secretsmanager_secret_version" "db_master_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_master_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
