  username               = jsondecode(aws_secretsmanager_secret_version.db_master_secret_version.secret_string)["username"]
  password               = jsondecode(aws_secretsmanager_secret_version.db_master_secret_version.secret_string)["password"]
  parameter_group_name   = "default.postgres15"
  skip_final_snapshot    = true
  kms_key_id             = aws_kms_key.db_secret_key.arn
  db_subnet_group_name   = aws_db_subnet_group.example.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
}

# Create a DB subnet group
