provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_efs_file_system" "example" {
  creation_token = "my-efs-filesystem"
  encrypted      = true
  tags = {
    Name = "MyEFSFilesystem"
  }
}

resource "aws_efs_mount_target" "example" {
  count          = 2 # Adjust count based on the number of subnets you want to attach to
  file_system_id = aws_efs_file_system.example.id
  subnet_id      = "subnet-1234567890abcdef0" # Replace with your subnet IDs
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_security_group" "efs_sg" {
  name        = "efs-security-group"
  description = "Allow NFS traffic to EFS"
  vpc_id      = "vpc-1234567890abcdef0" # Replace with your VPC ID

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to specific IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "EFS-Security-Group"
  }
}

resource "aws_iam_policy" "efs_policy" {
  name        = "EFS-Resource-Policy"
  description = "Policy to allow access to the EFS file system"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::123456789012:root" # Replace with the AWS account ID that needs access
        },
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ],
        Resource = aws_efs_file_system.example.arn
      }
    ]
  })
}

resource "aws_iam_resource_policy" "efs_resource_policy" {
  name      = "EFS-Resource-Policy"
  policy    = data.aws_iam_policy_document.efs_policy_document.json
  resource  = aws_efs_file_system.example.arn
}

data "aws_iam_policy_document" "efs_policy_document" {
  statement {
    effect    = "Allow"
    actions   = ["elasticfilesystem:ClientMount", "elasticfilesystem:ClientWrite"]
    resources = [aws_efs_file_system.example.arn]

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }
}

