resource "aws_vpc" "main" {
  # Ensure this VPC exists or replace with your existing VPC ID
  id = "vpc-xxxxxxxx" # Replace with your VPC ID or omit if using existing VPC
}

resource "aws_egress_only_internet_gateway" "pike" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "pike"
    permissions = "egress-only"
  }
}

resource "aws_route_table" "ipv6_egress" {
  vpc_id = aws_vpc.main.id

  route {
    destination_cidr_block   = "::/0"
    egress_only_gateway_id   = aws_egress_only_internet_gateway.pike.id
  }

  tags = {
    Name = "ipv6-egress-route"
  }
}

resource "aws_main_route_table_association" "main" {
  vpc_id         = aws_vpc.main.id
  route_table_id = aws_route_table.ipv6_egress.id
}

# Optional: If you want to restrict inbound internet access via security groups
resource "aws_security_group" "ipv6_egress_sg" {
  name        = "ipv6-egress-sg"
  description = "Security group for IPv6 egress only"
  vpc_id      = aws_vpc.main.id

  # Allow outbound IPv6 traffic (default is already allowed in VPC)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["::/0"]
    ipv6_cidr_blocks = ["::/0"]
  }

  # Block inbound internet access (default is already blocked in VPC)
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    ipv6_cidr_blocks = ["::/0"]
    self        = true # Allow internal traffic
  }

  tags = {
    Name = "ipv6-egress-sg"
    permissions = "egress-only"
  }
}

