provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create a VPC (using a default CIDR block for example, adjust as needed)
resource "aws_vpc" "pike_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "pike-vpc"
  }
}

# Create a DHCP options set with Google's DNS
resource "aws_vpc_dhcp_options" "pike_dhcp_options" {
  domain_name          = "example.com" # Replace with your domain or leave empty
  domain_name_servers  = ["8.8.8.8", "8.8.4.4"]
  ntp_servers          = ["169.254.169.123"] # AWS default NTP server
  netbios_name_servers = ["10.0.0.1"] # Optional, adjust as needed
  netbios_node_type    = 2
  tags = {
    Name = "pike-dhcp-options"
    permissions = "dns-configuration"
  }
}

# Associate the DHCP options set with the VPC
resource "aws_vpc_dhcp_options_association" "pike_dhcp_association" {
  vpc_id          = aws_vpc.pike_vpc.id
  dhcp_options_id = aws_vpc_dhcp_options.pike_dhcp_options.id
  tags = {
    permissions = "dns-association"
  }
}

