provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_eip" "nat_gateway_eip" {
  # Use the provided allocation ID (replace with actual value)
  allocation_id = "eipalloc-xxxxxxxxxxxxxxxxx" # Replace with your EIP allocation ID
  domain       = "vpc"
}

resource "aws_nat_gateway" "public_nat_gateway" {
  allocation_id = aws_eip.nat_gateway_eip.id
  subnet_id     = "subnet-xxxxxxxxxxxxxxxxx" # Replace with your designated subnet ID

  tags = {
    Name = "Public-NAT-Gateway"
  }

  depends_on = [aws_eip.nat_gateway_eip]
}

resource "aws_route" "nat_route" {
  route_table_id            = "rtb-xxxxxxxxxxxxxxxxx" # Replace with your route table ID
  destination_cidr_block    = "0.0.0.0/0"
  nat_gateway_id            = aws_nat_gateway.public_nat_gateway.id
  depends_on                = [aws_nat_gateway.public_nat_gateway]
}

# Optional: Security group allowing outbound traffic (adjust as needed)
resource "aws_security_group" "nat_sg" {
  name        = "nat-gateway-sg"
  description = "Allow outbound traffic from NAT Gateway"
  vpc_id      = "vpc-xxxxxxxxxxxxxxxxx" # Replace with your VPC ID

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "NAT-Gateway-SG"
  }
}

# Optional: Associate security group with NAT Gateway (if required)
resource "aws_nat_gateway_association" "nat_sg_association" {
  nat_gateway_id = aws_nat_gateway.public_nat_gateway.id
  security_groups = [aws_security_group.nat_sg.id]
  depends_on      = [aws_nat_gateway.public_nat_gateway]
}

