provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# VPC for "peer" with CIDR 10.0.0.0/24
resource "aws_vpc" "peer_vpc" {
  cidr_block           = "10.0.0.0/24"
  instance_tenancy     = "default"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "peer"
  }
}

# VPC for "base" with CIDR 10.1.0.0/24
resource "aws_vpc" "base_vpc" {
  cidr_block           = "10.1.0.0/24"
  instance_tenancy     = "default"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "base"
  }
}

# VPC Peering Connection named "pike"
resource "aws_vpc_peering_connection" "pike" {
  vpc_id      = aws_vpc.peer_vpc.id
  peer_vpc_id = aws_vpc.base_vpc.id
  auto_accept = true

  tags = {
    Name = "pike"
    pike = "permissions"
  }
}

# Route table for "peer" VPC to route traffic to "base" VPC
resource "aws_route" "peer_to_base" {
  route_table_id            = aws_vpc.peer_vpc.main_route_table_id
  destination_cidr_block    = "10.1.0.0/24"
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  depends_on                = [aws_vpc_peering_connection.pike]
}

# Route table for "base" VPC to route traffic to "peer" VPC
resource "aws_route" "base_to_peer" {
  route_table_id            = aws_vpc.base_vpc.main_route_table_id
  destination_cidr_block    = "10.0.0.0/24"
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id
  depends_on                = [aws_vpc_peering_connection.pike]
}

