  vpc_id            = aws_vpc.peer.id
  cidr_block        = "10.0.0.0/25"
  availability_zone = "us-east-1a" # Change to your preferred AZ
  tags = {
    Name = "peer-subnet"
  }
}

# Route table for "base" VPC to allow traffic to "peer" VPC
resource "aws_route_table" "base_route_table" {
  vpc_id = aws_vpc.base.id
  tags = {
    Name = "base-route-table"
  }
}

# Route table for "peer" VPC to allow traffic to "base" VPC
