  route_table_id = aws_route_table.base_route_table.id
}

# Associate route tables with subnets for "peer" VPC
resource "aws_route_table_association" "peer_association" {
  subnet_id      = aws_subnet.peer_subnet.id
  route_table_id = aws_route_table.peer_route_table.id
}

