extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Create Network ACL
resource "aws_network_acl" "main" {
  vpc_id = aws_vpc.main.id
  subnet_ids = [] # Will be populated after subnet creation (optional)

  # Inbound rules
  dynamic "entry" {
    for_each = [
      { rule_number = 100, protocol = "6", from_port = 22, to_port = 22, cidr_block = "0.0.0.0/0", rule_action = "allow" },
      { rule_number = 110, protocol = "6", from_port = 80, to_port = 80, cidr_block = "0.0.0.0/0", rule_action = "allow" },
      { rule_number = 120, protocol = "6", from_port = 443, to_port = 443, cidr_block = "0.0.0.0/0", rule_action = "allow" },
      { rule_number = 130, protocol = "6", from_port = 3389, to_port = 3389, cidr_block = "0.0.0.0/0", rule_action = "allow" }
    ]

    content {
      rule_number = entry.value.rule_number
      protocol    = entry.value.protocol
      from_port   = entry.value.from_port
      to_port     = entry.value.to_port
      cidr_block  = entry.value.cidr_block
      action      = entry.value.rule_action
    }
  }

  # Outbound rules
  dynamic "entry" {
    for_each = [
      { rule_number = 100, protocol = "-1", from_port = 0, to_port = 0, cidr_block = "0.0.0.0/0", rule_action = "allow" }
    ]

    content {
      rule_number = entry.value.rule_number
      protocol    = entry.value.protocol
      from_port   = entry.value.from_port
      to_port     = entry.value.to_port
      cidr_block  = entry.value.cidr_block
      action      = entry.value.rule_action
    }
  }

  tags = {
    Name = "main-nacl"
  }
}

# Associate Network ACL with VPC
resource "aws_vpc_nacl_association" "main" {
  network_acl_id = aws_network_acl.main.id
  subnet_id      = aws_vpc.main.id # This will need to be updated with actual subnet ID(s)
}

